(window.courseContentFiles = window.courseContentFiles || {})["archived-000002/0006"] = "<!DOCTYPE html>\r\n<html lang=\"bg\">\r\n<head>\r\n  <meta charset=\"UTF-8\">\r\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\r\n  <title>d</title>\r\n  <link rel=\"stylesheet\" href=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/katex.min.css\">\r\n  <style>\r\n    body { \r\n      font-family: \"Open Sans\", Arial, sans-serif; \r\n      max-width: 1550px; \r\n      margin: 0.5rem auto; \r\n      padding: 0 1rem; \r\n      line-height: 1.8; \r\n      color: #1f2937; \r\n    }\r\n    h1, h2, h3, h4 { \r\n      font-weight: 600; \r\n      margin-top: 0.8em;\r\n      margin-bottom: 0.3em;\r\n      color: #3a5a40;\r\n    }\r\n    h1 { font-size: 1.5em; }\r\n    h2 { font-size: 1.3em; }\r\n    h3 { font-size: 1.1em; }\r\n    h4 { font-size: 1.05em; }\r\n    h3 + h4 { margin-top: 0.3em; }\r\n    p { \r\n      margin: 0.7em 0; \r\n      white-space: pre-wrap;\r\n    }\r\n    p + ul, p + ol { margin-top: -0.5em; }\r\n    h1 + p, h2 + p, h3 + p, h4 + p,\r\n    h1 + ul, h2 + ul, h3 + ul, h4 + ul,\r\n    h1 + ol, h2 + ol, h3 + ol, h4 + ol { \r\n      margin-top: 0.1em; \r\n    }\r\n    ul, ol { \r\n      margin: 0.3em 0; \r\n      padding-left: 1.5em; \r\n    }\r\n    li { margin: 0.15em 0; }\r\n    ul ul { list-style-type: circle; }\r\n    ul ul ul { list-style-type: square; }\r\n    strong { font-weight: 600; }\r\n    em { font-style: italic; }\r\n    code { \r\n      background: rgba(218, 215, 205, 0.3); \r\n      padding: 2px 6px; \r\n      border-radius: 3px; \r\n      font-family: \"Courier New\", monospace; \r\n      font-size: 0.9em; \r\n    }\r\n    pre {\r\n      background: rgba(255, 255, 255, 0.5);\r\n      padding: 12px;\r\n      border-radius: 4px;\r\n      overflow-x: auto;\r\n      margin: 0.5em 0;\r\n      font-family: \"Courier New\", monospace;\r\n    }\r\n    pre code {\r\n      background: none;\r\n      padding: 0;\r\n    }\r\n    blockquote {\r\n      border-left: 3px solid #a3b18a;\r\n      padding-left: 1em;\r\n      margin: 0.5em 0;\r\n      font-style: italic;\r\n      color: #3a5a40;\r\n    }\r\n    table { \r\n      border-collapse: collapse; \r\n      margin: 0.75em 0; \r\n      width: 100%; \r\n      table-layout: auto;\r\n    }\r\n    th, td { \r\n      border: 1px solid rgba(146, 64, 14, 0.35); \r\n      padding: 6px 10px; \r\n      text-align: left; \r\n      vertical-align: top;\r\n      height: 24px;\r\n      line-height: 1.2;\r\n    }\r\n    thead th { \r\n      background: rgba(196, 127, 9, 0.08); \r\n      font-weight: 600; \r\n    }\r\n    tbody tr:nth-child(odd) { \r\n      background: rgba(146, 64, 14, 0.03); \r\n    }\r\n    img { \r\n      max-width: 100%; \r\n      height: auto; \r\n    }\r\n    a { \r\n      color: #a3b18a; \r\n      text-decoration: underline; \r\n    }\r\n    a:hover {\r\n      color: #d97706;\r\n    }\r\n    /* Keep <p> tags inside list items on same line (as they appear in editor) */\r\n    li p {\r\n      margin: 0 !important;\r\n      padding: 0 !important;\r\n      display: inline !important;\r\n      line-height: 1 !important;\r\n    }\r\n    /* Prevent nested list paragraph issues */\r\n    li > ul,\r\n    li > ol {\r\n      margin: 0.3em 0 0 0;\r\n      padding-left: 1.5em;\r\n    }\r\n    /* Ensure list structure is clean */\r\n    ul ul, ul ol,\r\n    ol ul, ol ol {\r\n      margin-top: 0.2em;\r\n      padding-left: 1.5em;\r\n    }\r\n    @media (max-width: 768px) {\r\n      body {\r\n        max-width: 100%;\r\n        margin: 0.5rem 0;\r\n        padding: 0 0.5rem;\r\n        font-size: 16px;\r\n      }\r\n      h1 { font-size: 1.3em; }\r\n      h2 { font-size: 1.1em; }\r\n      h3 { font-size: 1em; }\r\n      p { margin: 0.5em 0; }\r\n      ul, ol { padding-left: 1.2em; }\r\n      li { margin: 0.1em 0; }\r\n      table { font-size: 0.9em; }\r\n      th, td { padding: 4px 6px; }\r\n    }\r\n  </style>\r\n</head>\r\n<body>\r\n<h1>БАКТЕРИЦИДНИ АНТИМИКРОБНИ ЛЕКАРСТВА</h1><h2>Доц. д-р Силвия Ганчева, д.м.</h2><hr><h2>Бактерии</h2><ul><li><b>Антибактериални лекарства </b>- вещества с природен (антибиотици) или синтетичен произход, които са предназначени да бъдат токсични за патогените, но не и за човека.</li><ul><li><b><font color=\"#3b82f6\">Бактерицидните</font></b> убиват бактериалните клетки.&nbsp;</li><li><b><font color=\"#3b82f6\">Бактериостатичните </font></b>потискат бактериалния растеж.</li></ul><li><b>Бактерии </b>- прокариотни клетки с характерно устройство:</li><ul><li><font color=\"#3b82f6\">Клетъчна стена</font>, съдържаща <font color=\"#3b82f6\">пептидогликан&nbsp;</font><font color=\"#000000\"><p style=\"\">да </p><p style=\"\">поддържа целостта на клетката (вътрешното </p><p style=\"\">осмотично налягане е високо)</p></font></li><li><font color=\"#3b82f6\">Клетъчна мембрана&nbsp;</font><p style=\"\"><font color=\"#000000\">подобна на тази в еукариотните</font></p><p style=\"\"><font color=\"#000000\">клетки (но не съдържа стероли)</font><font color=\"#3b82f6\">\r\n</font></p></li><li><font color=\"#3b82f6\">Липса на клетъчно ядро&nbsp;</font><font color=\"#000000\"><p style=\"\">– генетичната информация се</p><p style=\"\">съдържа в една хромозома, която няма обвивка</p></font></li><li><font color=\"#3b82f6\">Плазмиди&nbsp;</font><font color=\"#000000\"><p style=\"\">– мобилни елементи, носещи</p><p style=\"\">екстрахромозомна генетична информация</p></font></li><li><font color=\"#3b82f6\">Рибозомни субединици</font>&nbsp;- <p>са по-малки от тези на</p><p>еукариотите (30S и 50S срещу 40S и 60S)</p></li></ul></ul><hr><h2>Резистентност към антибактериалните лекарства</h2><ul><li>Естествен процес, превърнал се в сериозен глобален проблем.</li><li>Резистентните щамове се селектират (естествен подбор) при наличие на антибактериални лекарства в средата.</li><li><b>Видове резистентност:</b></li><ul><li><strong>Вродена</strong> - напр. микоплазмите нямат клетъчна стена =&gt; те са резистентни на всички лекарства, повлияващи синтеза на бактериална клетъчна стена.</li><li><strong>Придобита</strong></li></ul><li>Основен механизъм за разпространение на придобитата резистентност е прехвърляне на резистентни гени между бактериите.</li><li><b>Механизми на придобита резистентност</b>:</li><ul><li><b style=\"color: rgb(59, 130, 246);\">Производство на ензими, които инактивират лекарството</b><font color=\"#000000\">&nbsp;<p style=\"\">(напр. беталактамази, разграждащи бета-лактамния пръстен на пеницилините)</p></font></li><li><b style=\"color: rgb(59, 130, 246);\">Промяна на таргета на антибактериалното лекарство&nbsp;</b><font color=\"#000000\"><p style=\"\">(напр. рибозомна </p><p style=\"\">протекция от протеин, който пречи на свързването на макролидите </p></font><p style=\"\"><font color=\"#000000\">към бактериалната рибозомна субединица)</font><b style=\"color: rgb(59, 130, 246);\">\r\n</b></p></li><li><b style=\"color: rgb(59, 130, 246);\">Намалено натрупване на лекарството в бактериалната клетка</b><p style=\"\"><b style=\"color: rgb(59, 130, 246);\"> </b><font color=\"#000000\">(напр. </font></p><font color=\"#000000\"><p style=\"\">чрез експресия на активен транспортер, който изпомпва </p><p style=\"\">тетрациклините =&gt; те не могат да се натрупат и да свържат таргета</p></font><p style=\"\"><font color=\"#000000\">си)</font><b style=\"color: rgb(59, 130, 246);\">\r\n</b></p></li><li><b style=\"color: rgb(59, 130, 246);\">Намалена чувствителност на таргетния ензим</b><font color=\"#000000\">&nbsp;<p style=\"\">(напр. резистентност </p><p style=\"\">към сулфонамиди чрез производство на таргетен ензим, който има </p><p style=\"\">нисък афинитет за свързване с лекарството</p></font></li></ul></ul><hr><h2>Класификация на антибактериалните лекарства</h2><p><b><font color=\"#3b82f6\">Бактерицидни</font></b></p><p><b>I. Бета-лактамни антибиотици</b></p><ol><li>Пеницилини</li><li>Цефалоспорини</li><li>Монобактами</li><li>Карбапенеми</li></ol><p><b>II. Гликопептидни антибиотици</b></p><p><b>III. Аминогликозидни антибиотици</b></p><p><b>IV. Други антибиотици</b></p><ol><li>Fosfomycin</li><li>Fidaxomicin</li></ol><p><b>V. Флуорирани хинолони</b></p><p><b>VI. Нитроимидазоли</b></p><p><b>\r\n<font color=\"#3b82f6\">Бактериостатични</font></b></p><p>I. Тетрациклини</p><p>II. Chloramphenicol</p><p>III. Макролиди</p><p>IV. Линкозамиди</p><p>V. Сулфонамиди</p><p>VI. Оксазолидинони</p><hr><h2>Бета-лактамни антибиотици</h2><h3>Механизъм на действие</h3><ul><li><font color=\"#3b82f6\">Бета-лактамите нарушават синтезата на <strong>пептидогликан.</strong></font></li><li><font color=\"#3b82f6\"><strong><p>Пептидогликанът е полимер, съдържащ полизахариди и пептиди.</p></strong></font></li><ul><li><p style=\"\"><font color=\"#000000\">Полизахаридната верига се състои от редуващи се аминозахарни </font></p><p style=\"\"><font color=\"#000000\">остатъци и пептидни вериги, които са свързани към тях</font></p></li><li><p><font color=\"#000000\">Тези пептидни вериги се свързват напречно от ензими – транспептидази</font></p></li><li><p style=\"\"><font color=\"#000000\">Напречните връзки са необходими, за да бъде клетъчната стена </font></p><p style=\"\"><font color=\"#000000\">устойчива.</font></p></li></ul><li><font color=\"#000000\"><p style=\"\">Структурата на бета-лактамния пръстен наподобява краищата на</p><p style=\"\">пептидните вериги:</p></font></li><ul><li><p style=\"\"><font color=\"#000000\">Антибиотикът се свързва с активния център на</font><font color=\"#3b82f6\"> транспептидазата и я </font></p><p style=\"\"><font color=\"#3b82f6\">блокира</font><font color=\"#000000\">; транспептидаза = пеницилин-свързващ протеин (penicillinbinding protein (PBP))</font></p></li><li><font color=\"#000000\"><p>Така бета-лактамите блокират образуването на напречните връзки в </p><p>молекулата на пептидогликана и правят клетъчната стена неустойчива</p></font></li></ul><li><font color=\"#3b82f6\">Бета-лактамите <b>инактивират инхибитор на автолитичните ензими</b> в бактериалната клетка</font>.</li><li><b>Краен ефект</b>: клетката се лизира (<strong><font color=\"#3b82f6\">бактерицидно действие</font></strong>).</li><li>Бета-лактамите са <strong>бактерицидни само за активно делящи се клетки</strong>, защото само те синтезират клетъчни стени.</li></ul><h3><span style=\"font-size: 1.3em;\">Пеницилини</span></h3><h4>Класификация</h4><strong>I. Тясно-спектърни пеницилини</strong><br><ul><ol><li><strong>Природни, бета-лактамаза чувствителни</strong></li><ul><li><i><font color=\"#7e22ce\">Benzylpenicillin (Penicillin G)</font></i></li><li><i><font color=\"#7e22ce\">Benzathinbenzylpenicillin</font></i></li><li><i><font color=\"#7e22ce\">Phenoxymethylpenicillin (Penicillin V)</font></i></li></ul><li><strong>Полусинтетични, бета-лактамаза резистентни (антистафилококови)</strong></li><ul><li><i><font color=\"#7e22ce\">Meticillin</font></i></li><li><i><font color=\"#7e22ce\">Oxacillin</font></i></li></ul></ol></ul><strong>ІІ. Широко-спектърни пеницилини</strong><br><ul><ol><li><strong>Аминопеницилини</strong></li><ul><li><font color=\"#6b84ae\" style=\"\"><b style=\"\">Бета-лактамаза чувствителни</b></font></li><ul><li><i><font color=\"#7e22ce\">Amoxicillin</font></i></li><li><i><font color=\"#7e22ce\">Ampicillin</font></i></li></ul><li><font color=\"#6b84ae\" style=\"\"><b>Бета-лактамаза резистентни (комбинации с инхибитор на бета-лактамазата)</b></font></li><ul><li><i><font color=\"#7e22ce\">Amoxicillin + Clavulanic acid =&nbsp;<p>Co-amoxiclav</p></font></i></li><li><i><font color=\"#7e22ce\">Ampicillin + Sulbactam =&nbsp;<p>Sultamicillin</p></font></i></li></ul></ul><li><strong>Карбоксипеницилини, бета-лактамаза чувствителни (антипсевдомонасни)</strong></li><ul><li><i><font color=\"#7e22ce\">Carbenicillin</font></i></li></ul><li><strong>Уреидопеницилини (антипсевдомонасни)</strong></li><ul><li><font color=\"#6b84ae\" style=\"\"><b style=\"\">Бета-лактамаза чувствителни</b></font></li><ul><li><i><font color=\"#7e22ce\">Piperacillin</font></i></li></ul><li><font color=\"#6b84ae\" style=\"\"><b style=\"\">Бета-лактамаза резистентни (комбинации с инхибитор на бета-лактамазата)</b></font></li><ul><li><i><font color=\"#7e22ce\">Piperacillin + tazobactam =&nbsp;<p>Tazocin</p></font></i></li></ul></ul></ol></ul><h3>Антибактерилен спектър</h3><blockquote><span style=\"color: rgb(31, 41, 55); font-size: 16px;\">(наизуст - тясно спектърни природни и след това всяка група увеличава спектъра)</span></blockquote><ul><li><strong><font color=\"#3a5a40\">Тясно-спектърните природни пеницилини</font></strong> са активни основно срещу G(+) бактерии и са <font color=\"#dd0a0a\">неустойчви на бета-лактамази</font></li><ul><li><font color=\"#3b82f6\">G(+) коки</font>: стрептококи, вкл. пневмококи, стафилококи (<font color=\"#dd0a0a\">с изключение на S. aureus</font>, защото произвежда бета-лактамаза). <font color=\"#dd0a0a\">Нямат </font>активност срещу <font color=\"#dd0a0a\">ентерококи </font>(вродена резистентност).</li><li><font color=\"#3b82f6\">G(-) коки</font>: <em>Neisseria meningitidis</em>.</li><li><font color=\"#3b82f6\">G(+) пръчици, вкл. някои анаероби</font>: <em>Corynebacterium diphteriae, Bacillus anthracis, Clostridium spp.</em> (<font color=\"#dd0a0a\">без <em>Cl. difficile</em></font>), <em>Bacteroides spp.</em> (<font color=\"#dd0a0a\">без <em>B. fragilis</em></font>), <em>Listeria monocytogenes</em>, актиномицети.</li><li><font color=\"#3b82f6\">Спирохети</font>: <em>Treponema pallidum, Borrelia burgdorferi</em>.</li></ul><li><strong>Т<font color=\"#3a5a40\">ясно-спектърните полусинтетични пеницилини</font></strong> са <font color=\"#65a30d\">устойчиви на бета-лактамази</font> </li><ul><li>Aктивност срещу <font color=\"#3b82f6\">бета-лактамаза продуциращи щамове <em>Staphylococcus aureus</em></font>.</li><li>Тези стафилококи се наричат <strong><font color=\"#3b82f6\">метицилин-чувствителни S.aureus (MSSA)</font></strong>.</li></ul><li><strong><font color=\"#3a5a40\">Аминопеницилините</font></strong> са <font color=\"#dd0a0a\">неустойчиви на бета-лактамази</font></li><ul><li><font color=\"#3b82f6\">Някои G(-) пръчици</font>, като <em><font color=\"#3b82f6\">H. influenzae</font></em><font color=\"#3b82f6\"> </font></li><li>Някои представители на семейство <em>Enterobacteriaceae</em> (<em><font color=\"#3b82f6\">E. coli, Salmonella spp., Shigella spp.</font></em>), както и <font color=\"#3b82f6\">ентерококи</font>.</li><li><strong></strong><p><strong>Комбинацията с инхибитор на бета-лактамазата</strong> е активна и спрямо бактерии, продуциращи бета-лактамаза</p>.</li></ul><li><font color=\"#3a5a40\" style=\"font-weight: bold;\">Карбокси и уреидопеницилините </font><font color=\"#000000\" style=\"\">са</font><font color=\"#dd0a0a\" style=\"\">&nbsp;<p style=\"\">неустойчви на бета-лактамази</p></font></li><ul><li>По-активни от аминопеницилините спрямо <font color=\"#3b82f6\">G(-) пръчици</font> </li><li>Покриват още <font color=\"#3b82f6\"><em>Proteus spp., Klebsiella pneumonia, <u>Pseudomonas aeruginosa</u></em> </font>(<strong>антипсевдомонасни пеницилини</strong>).</li><li><strong>Комбинацията с инхибитор на бета-лактамазата</strong> е активна и спрямо бактерии, продуциращи бета-лактамаза.</li></ul></ul><h3>Резистентност</h3><ul><li><strong>Инактивиране на бета-лактамния пръстен от бета-лактамази</strong>.</li><ul><li>Бета-лактамазите се произвеждат от много микроорганизми: <em><font color=\"#dd0a0a\">S. aureus, H. influenzae, E.coli</font></em> и много други.</li><li>Някои пеницилини (напр. <i><font color=\"#7e22ce\">оxacillin</font></i>) притежават странична верига, която предпазва бета-лактамния пръстен и предотвратява свързването му от ензима =&gt; тези пеницилини са резистентни на бета-лактамазите.</li><li>Инхибиторите на бета-лактамазата (<strong>clavulanic acid, tazobactam, sulbactam</strong>) нямат антибактериална активност. Те свързват бета-лактамния пръстен и предотвратяват разграждането не лекарството =&gt; комбинациите са устойчиви на бета-лактамазите.</li></ul></ul><ul><li><strong>Мутация на пеницили-свързващите протеини</strong>.</li><ul><li><p>Променените транспептидази (пеницилин-свързващи протеини) са с никък афинитет за свързване с </p><p>пеницилините =&gt; пеницилините не могат да реализират своя механизъм на действие</p></li><li>Типична резистентност за <strong>стрептококи (<font color=\"#dd0a0a\">penicillin resistant streptococci, PRSP</font>)</strong> и <strong>S. aureus (метицилин-резистенти стафилококи (<font color=\"#dd0a0a\">methicillin-resistant staphylococci, MRSA)</font>)</strong>.</li></ul></ul><h3>Фармакокинетика</h3><ul><li><strong><font color=\"#3a5a40\">Път на приложение</font></strong> зависи от <font color=\"#3a5a40\">устойчивостта </font>на лекарствата към действието на солната киселина.</li><ul><li><strong><font color=\"#3b82f6\">Киселинно-устойчивите пеницилини</font></strong> (!!<font color=\"#7e22ce\"><u style=\"font-style: italic;\">phenoxymethylpenicillin, ampicillin, amoxicillin</u>!</font>!) могат да се прилагат <font color=\"#3b82f6\">перорално</font>.</li><ul><li>Резорбцията им при перорално приложение <font color=\"#3b82f6\">се намалява при наличие на храна </font>(с изключение на <em><font color=\"#7e22ce\">amoxicillin</font></em>) =&gt; лекарствата трябва да се приемат поне <font color=\"#3b82f6\">1-2 часа преди хранене</font>.</li></ul><li><strong><font color=\"#dd0a0a\">Киселинно-неустойчивите пеницилини</font></strong> се прилагат <font color=\"#3b82f6\">парентерално </font>(интравенозно или мускулно).</li><li><i style=\"\"><font color=\"#7e22ce\">Benzathinbenzylpenicillin </font></i>е предназначен за <font color=\"#3b82f6\">мускулно приложение</font>. Абсорбира се бавно от мястото на инжектиране =&gt; <font color=\"#3b82f6\">по-продължително действие</font>.</li></ul><li><strong><font color=\"#3a5a40\">Разпределение</font></strong></li><ul><li><font color=\"#3b82f6\">Водно-разтворими вещества</font> =&gt; разпределение в екстрацелуларната течност.</li><li><font color=\"#3b82f6\">Високи концентрации</font> се достигат в <font color=\"#3b82f6\">повечето тъкани и телесни течности</font><font color=\"#000000\"><p style=\"\">, вкл. синовиална течност, бронхиален</p><p style=\"\">секрет, слюнка, кърма.</p></font></li><li><strong>Преминаване през бариерни системи</strong></li><ul><li>Пеницилините <font color=\"#3b82f6\">преминават през плацентата</font>.</li><li>При нормални условия те не преминват през ХЕБ, хемато-окуларната и простатната бариера.</li><li><font color=\"#3b82f6\">При менингит</font> пермеабилитетът на ХЕБ се повишава =&gt; <font color=\"#3b82f6\">пеницилините я преминават</font> и достигат терапевтични концентрации в церебро-спиналната течност (<font color=\"#3b82f6\">необходими са високи дози, приложени интравенозно</font>).</li></ul></ul><li><strong><font color=\"#3a5a40\">Елиминация</font></strong></li><ul><li><font color=\"#000000\">Основно бъбречна екскреция&nbsp;<p>– 90% тубулна секреция, 10% гломерулна филтрация</p></font></li><li>Някои лекарства се екскретират частично с жлъчката в непроменен вид (<em><font color=\"#7e22ce\">oxacillin</font>, <font color=\"#7e22ce\">ampicillin</font></em>).</li></ul><li><strong><font color=\"#3a5a40\">Плазмен полуживот и дозови интервали</font></strong></li><ul><li>Повечето пеницилини <font color=\"#3b82f6\">имат кратък плазмен полуживот&nbsp;</font>=&gt; прилагат се на всеки 4 или 6 часа.</li><li><font color=\"#7e22ce\"><em style=\"\">Amoxicillin</em> </font>има по-дълго действие =&gt; прилага се на всеки <font color=\"#3b82f6\">8 или 12 часа</font>.</li></ul></ul><h3>Клинично приложение</h3><ul><li>Лекарства на <strong><font color=\"#3b82f6\">първи избор</font></strong> при бактериални инфекции при <strong><font color=\"#3b82f6\">деца и бременни жени</font></strong>.</li><li><font color=\"#3b82f6\">Орално </font>се прилагат за лечение на <font color=\"#3b82f6\">леки до умерено тежки бактериални инфекции</font>.</li><li><font color=\"#3b82f6\">Тежките системни инфекции</font> изискват <font color=\"#3b82f6\">парентерално </font>лечение.</li><li><font color=\"#7e22ce\"><strong style=\"\"><em style=\"\">Benzylpenicillin</em></strong> </font>се използва при <b><font color=\"#3b82f6\">тежки инфекции</font></b>, предизвикани от чувствителни патогени, напр. <b>менингококов менингит</b>, <b>стрептококова пневмония</b>, <b>ендокардит</b>, <b>анаеробни инфекции</b>, <b>сепсис </b>(комбинирани с други бактерицидни лекарства).</li><li><strong><em><font color=\"#7e22ce\">Benzathinbenzylpenicillin</font></em></strong>, приложен интрамускулно, достига <b>ниски</b>, но стабилни серумни концентрации за <b>дълъг период от време </b>=&gt; използва се за <b><font color=\"#3b82f6\">профилактика </font></b>на <b><font color=\"#3b82f6\">ревматизъм </font></b>и ревматични сърдечни пороци след инфекция с <b>бета-хемолитични стрептококи</b> и за лечение на <b><font color=\"#3b82f6\">сифилис</font></b>.</li><li><font color=\"#7e22ce\"><strong style=\"\"><em style=\"\">Phenoxymethylpenicillin</em></strong> </font>се използва при<font color=\"#3b82f6\"> </font><b><font color=\"#3b82f6\">леки стрептококови инфекции</font> </b>– отит, фарингит, тонзилит, синузит, профилактика на скарлатина.</li><li><i><font color=\"#7e22ce\"><strong>Полусинтетичните тясно-спектърни пеницилини</strong> </font></i>се използват за лечение на стафилококови инфекции (причинени от <b><font color=\"#3b82f6\">MSSA</font></b>) – <b>инфекции на кожа и меки тъкани, костно-ставни инфекции</b>.</li><li><strong style=\"\"><i style=\"\"><font color=\"#7e22ce\">Аминопеницилините&nbsp;</font></i></strong>са подходящи за <b><font color=\"#3b82f6\">емпирична терапия</font> </b>на <b>дихателни инфекции</b>, <b>уроинфекции</b>, <b>гастроинтестинални инфекции</b>, <b>менингит</b>, <b>отит</b>, <b>синузит</b>, <b>оро-дентални инфекции</b>, <b>профилактика на бактериален ендокардит </b>и др.</li><ul><li><p>Комбинациите с <b>инхибитори на бета-лактамазата</b> често са предпочитани поради високата </p><p>честота на <b>E.coli</b> и <b>H.influenzae</b></p></li></ul><li><strong><i style=\"\"><font color=\"#7e22ce\">Карбокси </font></i><i style=\"\"><font color=\"#7e22ce\">и уреидопеницилините</font></i><font color=\"#3b82f6\">&nbsp;</font></strong>се използват при <b>тежки инфекции </b>предизвикани от <font color=\"#3b82f6\"><b style=\"\">Pseudomonas</b>&nbsp;</font>– най-често уроинфекции, вкл. уросепсис, дихателни инфекции при пациенти с муковисцидоза, вътреболнични инфекции.</li></ul><h3>Нежелани лекарствени реакции</h3><ul><li>Почти пълна <font color=\"#3b82f6\">липса </font>на директна <font color=\"#3b82f6\">органна токсичност</font>.</li><li><u style=\"font-weight: bold;\"><font color=\"#dd0a0a\">Чести алергични реакции</font></u><span style=\"font-weight: bold; color: rgb(166, 78, 48);\">&nbsp;</span><font color=\"#000000\" style=\"\"><p style=\"\">- (при около 5% от популацията) – кожен тест за </p><p style=\"\">свръхчувствителност е препоръчителен преди интравенозно приложение</p></font></li><ul><li><font color=\"#6d7b5b\">Разнообразни кожни обриви</font>.</li><li><font color=\"#6d7b5b\">Симптоми на серумна болест (уртикария, температура, ставни болки и пр.)</font>.</li><li><font color=\"#6d7b5b\">Анафилактичен шок</font> (рядко).</li></ul><li><strong><font color=\"#dd0a0a\">Локален дразнещ ефект върху тъканите</font></strong>.</li><ul><li>При орално приложение – <font color=\"#dd0a0a\">гастроинтестинални нарушения</font>.</li><li>При интрамускулно приложение – <font color=\"#dd0a0a\">болка на мястото на инжектиране</font>.</li><li>При интравенозно приложение – <font color=\"#dd0a0a\">флебит</font>.</li></ul><li>При приложение на високи дози и <font color=\"#a64e30\">интратекално въвеждане </font>могат да се провокират <strong><font color=\"#dd0a0a\">гърчове</font></strong>.</li><li><strong><font color=\"#dd0a0a\">Дисбактериоза и суперинфекции</font></strong> – възможни при <font color=\"#a64e30\">широкоспектърните пеницилини</font>.</li><ul><li><font color=\"#6d7b5b\">При орално приложение</font> (особено при <em><font color=\"#7e22ce\">ampicillin</font></em>) <font color=\"#6d7b5b\">се уврежда нормалната чревна флора </font>(дисбактериоза), което може да доведе до развитие на суперинфекции, предизвикани от пеницилин-резистентни патогени (напр. <strong><font color=\"#dd0a0a\">псевдомембранозен колит</font>, предизвикан от Cl. difficile</strong>).</li><li><font color=\"#dd0a0a\">Орална и вагинална кандидоза</font>.</li></ul><li>При приложение на <font color=\"#a64e30\">аминопеницилини </font>на пациенти с <font color=\"#a64e30\">инфекциозна мононуклеоза</font> (Epstein-Barr вирусна инфекция) се развива <strong><font color=\"#dd0a0a\">характерен кожен обрив</font></strong>.</li></ul><hr><h2>Цефалоспорини (Класификация)</h2><ul><li><strong>I. Първо поколение</strong></li><ul><li><i><font color=\"#7e22ce\">Cefalexin</font></i></li><li><i><font color=\"#7e22ce\">Cefadroxil</font></i></li><li><i><font color=\"#7e22ce\">Cefazolin</font></i></li></ul><li><strong>II. Второ поколение</strong></li><ul><li><i><font color=\"#7e22ce\">Cefuroxime</font></i></li><li><i><font color=\"#7e22ce\">Cefamandole</font></i></li><li><i><font color=\"#7e22ce\">Cefaclor</font></i></li></ul><li><strong>III. Трето поколение</strong></li><ul><li><i><font color=\"#7e22ce\">Ceftriaxone</font></i></li><li><i><font color=\"#7e22ce\">Cefoperazone</font></i></li><li><p><i><font color=\"#7e22ce\">Cefoperazone + Sulbactam = Sulperazone</font></i></p></li><li><i><font color=\"#7e22ce\">Cefotaxime</font></i></li><li><font color=\"#7e22ce\"><i>Ceftazidime</i></font></li><li><font color=\"#7e22ce\"><i>Ceftibuten</i></font></li><li><i><font color=\"#7e22ce\">Cefixime</font></i></li><li><i><font color=\"#7e22ce\">Cefpodoxime</font></i></li></ul><li><strong>IV. Четвърто поколение</strong></li><ul><li><i><font color=\"#7e22ce\">Cefepime</font></i></li></ul><li><strong>V. Пето поколение</strong></li><ul><li><i><font color=\"#7e22ce\">Ceftaroline</font></i></li></ul></ul><h3>Антибактериален спектър</h3><ul><li><u>Всички цефалоспорини са <strong>широкоспектърни</strong></u>.</li><li><strong>Първо поколение</strong> имат:</li><ul><li>Висока активност спрямо <font color=\"#3b82f6\">G(+) патогени</font>, като <font color=\"#3b82f6\">стрептококи </font>и <font color=\"#3b82f6\">стафилококи </font>(без <font color=\"#dd0a0a\">MRSA</font>).</li><li>Активност спрямо <font color=\"#3b82f6\">някои G(-) патогени</font>, като <em><font color=\"#3b82f6\">E.coli</font>, <font color=\"#3b82f6\">P.mirabilis</font></em>.</li><li><font color=\"#dd0a0a\">Нямат активност</font> срещу <font color=\"#dd0a0a\">ентерококи</font>, <em><font color=\"#dd0a0a\">P.aeruginosa</font>, <font color=\"#dd0a0a\">Enterobacter spp</font>.</em> и други причинители на вътреболнични инфекции.</li></ul><li><strong>Второ поколение</strong> са:</li><ul><li><font color=\"#3b82f6\">По-слабо активни </font>срещу <font color=\"#3b82f6\">G(+) патогени</font>.</li><li><font color=\"#3b82f6\">По-активни</font> срещу <font color=\"#3b82f6\">G(-) патогени,</font> като <em><font color=\"#3b82f6\">H.influenzae</font></em> и други причинители на <font color=\"#3b82f6\">дихателни инфекции</font>.</li><li><font color=\"#dd0a0a\">Нямат активност</font> срещу <font color=\"#dd0a0a\">ентерококи</font>,<font color=\"#dd0a0a\"> <em>P.aeruginosa</em></font>.</li></ul><li><strong>Трето поколение</strong> са:</li><ul><li><font color=\"#3b82f6\">Още по-активни </font>срещу <font color=\"#3b82f6\">G(-) патогени</font> от второ поколение.</li><li>Активни срещу <font color=\"#3b82f6\">бета-лактамаза</font> продуциращи щамове<font color=\"#3b82f6\"> <em>H.influenzae</em></font> и <em><font color=\"#3b82f6\">N.meningitides</font></em>.</li><li><font color=\"#3b82f6\"><em>Ceftazidim</em> </font>и <em><font color=\"#3b82f6\">Cefoperazone </font>(<font color=\"#3b82f6\">+sulbactam</font>)</em> са активни срещу <em><font color=\"#3b82f6\">P.aeruginosa</font></em>.</li></ul><li><strong>Четвърто поколение</strong>:</li><ul><li>Активност срещу <font color=\"#3b82f6\">G(+)</font> и <font color=\"#3b82f6\">G(-) бактерии</font>, вкл. <em><font color=\"#3b82f6\">P.aeruginosa</font></em>, <em><font color=\"#3b82f6\">Enterobacter spp</font>., <font color=\"#3b82f6\">H. influenzae</font>, <font color=\"#3b82f6\">N. meningitidis</font></em></li><li><span style=\"white-space-collapse: preserve;\">Активност срещу <font color=\"#3b82f6\">анаероби</font></span></li><li><p><font color=\"#3b82f6\">Устойчивост срещу бета-лактамази </font></p></li><li><font color=\"#dd0a0a\">Нямат активност</font> срещу<font color=\"#dd0a0a\"> MRSA</font>.</li></ul><li><strong>Пето поколение</strong>:</li><ul><li><p>Активност спрямо <font color=\"#3b82f6\">MRSA</font> </p><p>и <font color=\"#3b82f6\">PRSP </font></p><p>(бактериите с променени пеницилин</p><p>-свързващи протеини</p><p>)</p></li><li><p>Активност срещу <font color=\"#3b82f6\">G(</font></p><p><font color=\"#3b82f6\">-) бактерии</font></p><p style=\"\"><font color=\"#000000\">, подобна на тази на препаратите от трето поколение</font><font color=\"#3b82f6\">\r\n</font></p></li></ul></ul><h3>Фармакокинетика</h3><ul><li><font color=\"#a23510\"><strong style=\"\">Път на приложение</strong> </font>– зависи от <font color=\"#a23510\">киселинната устойчивост</font> на лекарствата.</li><ul><li><strong><font color=\"#3b82f6\">Киселинно-устойчивите цефалоспорини</font></strong> (напр. <font color=\"#7e22ce\"><em>cefalexin</em> </font>(I), <font color=\"#7e22ce\"><em>cefuroxime</em> </font>(II), <font color=\"#7e22ce\"><em>ceftibuten</em> </font>(III)) могат да се прилагат <font color=\"#3b82f6\">орално</font>.</li><li><strong><font color=\"#dd0a0a\">Киселинно-неустойчивите цефалоспорини</font></strong> се прилагат парентерално (<font color=\"#3b82f6\">интравенозно или мускулно</font>).</li></ul><li><strong><font color=\"#a23510\">Разпределение</font></strong></li><ul><li><font color=\"#000000\">Водо-разтворими лекарства</font> =&gt; разпределение в екстрацелуларната течност.</li><li><strong><font color=\"#000000\">Бариерни системи</font></strong></li><ul><li><font color=\"#000000\"><strong>Хемато-енцефална бариера (ХЕБ)</strong> </font>– с увеличаване на номера на поколението, се повишава способността на лекарствата да преминават:</li><ul><li><font color=\"#953718\"><b>Първо поколение</b> </font><font color=\"#dd0a0a\">не минават</font>.</li><li><font color=\"#953718\"><b>Второ поколение</b> </font><font color=\"#dd0a0a\">не минават</font>, с изключение на <i style=\"\"><font color=\"#7e22ce\">cefuroxime</font></i>.</li><li><b><font color=\"#953718\">Трето поколение</font></b> <font color=\"#3b82f6\">преминават по-добре</font>, особено <em><font color=\"#7e22ce\">ceftriaxone</font>, <font color=\"#7e22ce\">cefotaxime</font>, <font color=\"#7e22ce\">ceftazidime</font></em>.</li><li><b><font color=\"#953718\">Четвърто поколение</font></b> <font color=\"#3b82f6\">минава</font>.</li></ul><li><font color=\"#000000\"><strong>Плацента</strong> </font>– цефалоспорините <font color=\"#000000\">преминават </font>през плацентата.</li></ul></ul><li><strong><font color=\"#a23510\">Елиминация</font></strong></li><ul><li><font color=\"#000000\">Бъбречна екскреция в неп</font>роменен вид (повечето лекарства).</li><li>Някои лекарства се екскретират <u><font color=\"#3b82f6\">частично с жлъчката</font> – <font color=\"#7e22ce\"><em style=\"\">cefoperazone</em> </font>(III), <font color=\"#7e22ce\"><em style=\"\">ceftriaxone</em> </font>(III), <font color=\"#7e22ce\"><em style=\"\">cefamandole</em> </font>(II), <font color=\"#7e22ce\"><em style=\"\">cefazolin</em> </font>(I).</u></li><li><p style=\"\"><i><font color=\"#7e22ce\">Cefotaxim </font></i>се метаболизира частично до активен метаболит</p></li></ul><li><strong><font color=\"#a23510\">Дозов режим</font></strong></li><ul><li>Повечето цефалоспорини имат<font color=\"#000000\"> кратък плазмен полуживот</font> =&gt; приложение на всеки<font color=\"#000000\"> 6 или 8 часа.</font></li><li><font color=\"#7e22ce\"><em style=\"\">Ceftriaxone</em> </font>се прилага на <font color=\"#3b82f6\">24 часа</font>.</li><li><font color=\"#7e22ce\"><em style=\"\">Cefepime</em> </font>и <font color=\"#7e22ce\"><em style=\"\">ceftaroline</em> </font>се прилагат на <font color=\"#3b82f6\">12 часа</font>.</li></ul></ul><h3>Клинично приложение</h3><ul><li><font color=\"#000000\">Подходящи за <strong>деца и бременни жени</strong>.</font></li><li><font color=\"#000000\">Пероралното приложение&nbsp;- при леки до умерени; i.v - тежки системни инфекции.</font></li><li><font color=\"#000000\">Всички цефалоспорини са <b>широкоспектърни</b></font><b> </b>=&gt; подходящи са за <strong style=\"\"><font color=\"#3b82f6\">емпирично лечение</font></strong> на:</li><ul><li><font color=\"#3b82f6\">Дихателни инфекции</font><font color=\"#000000\">.</font></li><li><font color=\"#3b82f6\">Отит</font><font color=\"#000000\">, </font><font color=\"#3b82f6\">синузит </font><font color=\"#000000\">(I и II поколение).</font></li><li><font color=\"#3b82f6\">Уроинфекции </font><font color=\"#000000\">(II и III поколение).</font></li><li><font color=\"#3b82f6\">Инфекции на кости</font><font color=\"#000000\">, </font><font color=\"#3b82f6\">стави </font><font color=\"#000000\">и </font><font color=\"#3b82f6\">меки тъкани </font><font color=\"#000000\">(II и III поколение).</font></li><li><font color=\"#3b82f6\">Инфекции на жлъчните пътища</font><font color=\"#000000\"> (лекарствата с жлъчна екскреция).</font></li><li><font color=\"#3b82f6\">Менингит</font><font color=\"#000000\">, причинен от G(-) пръчици (III и IV поколение).</font></li><li><font color=\"#3b82f6\">Сепсис </font><font color=\"#000000\">(III и IV поколение).</font></li></ul><li><strong style=\"color: rgb(0, 0, 0);\">Първо поколение</strong><font color=\"#000000\"> се използват интравенозно за </font><strong style=\"\"><font color=\"#3b82f6\">хирургична профилактика</font></strong><font color=\"#000000\">.</font></li><li><font color=\"#7e22ce\"><strong style=\"\"><em style=\"\">Ceftriaxone</em></strong> </font>е лечение на първи избор при <strong style=\"\"><font color=\"#3b82f6\">гонорея</font><font color=\"#787e49\">.</font></strong></li><li><font color=\"#7e22ce\"><strong style=\"\"><em style=\"\">Ceftaroline</em></strong> </font>се използва при инфекции от <strong><font color=\"#3b82f6\">MRSA </font>и <font color=\"#3b82f6\">PRSP</font></strong>.</li></ul><h3>Нежелани лекарствени реакции</h3><ul><li><font color=\"#000000\">Ниска органна токсичност.</font></li><li><strong><font color=\"#dd0a0a\">Алергични реакции</font></strong> – възможна е<font color=\"#dd0a0a\"> <strong>кръстосана свръхчувствителност с пеницилини.</strong></font></li><li><strong><font color=\"#dd0a0a\">Локален дразнещ ефект върху тъканите</font></strong>:</li><ul><li><font color=\"#000000\">При орално приложение – </font><font color=\"#dd0a0a\">гастроинтестинални нарушения</font><font color=\"#000000\">.</font></li><li><font color=\"#000000\">При интрамускулно приложение –</font><font color=\"#dd0a0a\"> болка на мястото на инжектиране</font><font color=\"#000000\">.</font></li><li><font color=\"#000000\">При интравенозно приложение – </font><font color=\"#dd0a0a\">флебит</font><font color=\"#000000\">.</font></li></ul><li><strong style=\"\"><font color=\"#7e22ce\"><em style=\"\">Cefoperazone</em> </font><font color=\"#000000\">и</font><font color=\"#9c3c1c\"> </font><em style=\"\"><font color=\"#7e22ce\">cefamadole</font></em></strong><font color=\"#7e22ce\"> </font>съдържат странична верига, която:</li><ul><li><font color=\"#dd0a0a\">Потиска синтезата на витамин К-зависимите фактори на кръвосъсирването</font><font color=\"#000000\"> =&gt; риск от </font><strong style=\"\"><font color=\"#dd0a0a\">хипопротромбинемия </font><font color=\"#000000\">и </font><font color=\"#dd0a0a\">кървене</font></strong><font color=\"#000000\">.</font></li><li><strong style=\"\"><u style=\"\"><font color=\"#dd0a0a\">Дисулфирам-подобна реакция</font></u></strong><font color=\"#000000\"> при прием с алкохол (симптоми, наподобяващи махмурлук).</font></li></ul><li><font color=\"#dd0a0a\">Гастроинтестинална дисбактериоза и суперинфекции</font><font color=\"#000000\">, причинени от резистентни патогени (вкл. </font><strong><font color=\"#dd0a0a\">псевдомембранозен колит</font></strong><font color=\"#000000\">).</font></li><li><font color=\"#dd0a0a\">Орална и вагинална кандидоза</font><font color=\"#000000\">.</font></li></ul><hr><h2>Карбапенеми</h2><h3>Антибактериален спектър</h3><ul><li><font color=\"#000000\"><strong>Широкоспектърни</strong>.</font></li><li>Активност срещу <font color=\"#3b82f6\">G(+)</font> и <font color=\"#3b82f6\">G(-) бактерии</font>, вкл. <font color=\"#3b82f6\"><em>P.aeruginosa</em>.</font></li><li>Активност срещу <font color=\"#3b82f6\">анаероби</font>.</li><li><font color=\"#3b82f6\">Устойчивост </font>спрямо повечето <font color=\"#3b82f6\">бета-лактамази</font>.</li><li><font color=\"#dd0a0a\">Липса на активност</font> срещу <font color=\"#dd0a0a\">MRSA</font>, <em><font color=\"#dd0a0a\">Cl. Difficile</font></em>.</li></ul><h3>Фармакокинетика</h3><ul><li><strong><font color=\"#3a5a40\">Път на приложение</font>:</strong></li><ul><li><font color=\"#dd0a0a\">Киселинно-неустойчиви</font> – <font color=\"#000000\">парентерално </font>приложение.</li></ul><li><font color=\"#3a5a40\"><strong>Разпределение:</strong></font></li><ul><li><font color=\"#000000\">Екстрацелуларно разпределение.&nbsp;</font></li><li><font color=\"#000000\">Високи концентрации в повечето тъкани и телесни течности.</font></li><li><font color=\"#000000\">Добро преминаване през ХЕБ.</font></li></ul><li><strong><font color=\"#3a5a40\">Елиминация</font></strong></li><ul><li><font color=\"#7e22ce\"><em style=\"\">Meropenem</em> </font>се екскретира непроменен с урината.</li><li><font color=\"#7e22ce\"><em style=\"\">Imipenem</em> </font>се инактивира от дехидропептидази в бъбречните тубули, което води до ниска концентрация в урината и продукция на нефротоксични метаболити =&gt; <b style=\"\"><font color=\"#000000\">винаги се комбинира с инхибитор на дехидропептидазата</font></b> (<i><font color=\"#7e22ce\">cilastatin</font></i>) =&gt; <font color=\"#7e22ce\"><em>imipenem</em> </font>се екскретира непроменен.</li></ul><li><font color=\"#3a5a40\"><strong>Приложение</strong> </font>на всеки<font color=\"#000000\"> 6-8 часа.</font></li></ul><h3>Клинично приложение</h3><ul><li><font color=\"#000000\">Антибактериални лекарства на <strong style=\"\">втори избор</strong>.</font></li><li><font color=\"#3b82f6\">Тежки инфекции</font><font color=\"#000000\">,</font><font color=\"#3b82f6\"> предизвикани от патогени резистентни на други антибактериални средства </font><font color=\"#000000\">(напр. </font><em style=\"\"><b style=\"\"><font color=\"#3b82f6\">P.aeruginosa</font></b></em><font color=\"#000000\">).</font></li><li><font color=\"#3b82f6\">Смесени аеробни и анаеробни инфекции</font><font color=\"#000000\">.</font></li><li><font color=\"#3b82f6\">Имунокомпрометирани пациенти с фебрилна неутропения</font><font color=\"#000000\">.</font></li></ul><h3>Нежелани лекарствени реакции</h3><ul><li><font color=\"#dd0a0a\">Алергични реакции</font><font color=\"#000000\">.</font></li><li><font color=\"#dd0a0a\">Локален дразнещ ефект върху тъканитe</font><font color=\"#000000\">&nbsp;<p>– болка, флебит</p></font></li><li><font color=\"#dd0a0a\">Гастроинтестинални нарушения</font><font color=\"#000000\">.</font></li><li>Във високи дози <font color=\"#7e22ce\"><em style=\"\">imipenem</em> </font>е невротоксичен =&gt; <strong style=\"\"><font color=\"#dd0a0a\">гърчове</font></strong><font color=\"#000000\">.</font></li><li><font color=\"#dd0a0a\">Дисбактериоза и суперинфекции</font><font color=\"#000000\">.</font></li></ul><hr><h2>Гликопептидни антибиотици</h2><h3>Механизъм на действие:</h3><ul><li><font color=\"#000000\"><p>Гликопептидите се свързват с пептидната странична верига на строителните блокчета на пептидогликана, като така </p><p>предотвратяват удължаването на веригата</p></font></li><li><font color=\"#000000\">Бактериалната клетка става податлива на лизиране.</font></li><li><font color=\"#000000\">Гликопептидите действат <strong>бактерицидно само при активно делящи се бактерии&nbsp;</strong><p>=&gt; не е удачно да се комбинират с</p><p>бактериостатични лекарства</p></font></li></ul><h3>Антибактериален спектър</h3><ul><li><font color=\"#000000\"><strong>Тясноспектърни антибиотици</strong>.</font></li><li>Не могат да навлязат в G(-) бактерии.</li><li><font color=\"#3b82f6\">Активни спрямо G(+) бактерии</font>:</li><ul><li><font color=\"#3b82f6\">G(+) коки</font>, вкл. <strong><font color=\"#3b82f6\">MRSA </font>и <font color=\"#3b82f6\">PRSP</font></strong>.</li><li><font color=\"#3b82f6\">G(+) анаероби</font> като <em><font color=\"#3b82f6\">Clostridium difficile</font></em>.</li></ul></ul><h3>Резистентност</h3><ul><li><font color=\"#000000\">Модификация на свързващото място върху пептидогликановите строителни блокчета.</font></li><li><font color=\"#000000\"><em>Vancomycin</em>-резистентни ентерококи, <em>vancomycin</em>-резистентни <em>S.aureus</em>.</font></li></ul><h3>Фармакокинетика</h3><ul><li><strong><font color=\"#963717\">Резорбция и пътища на приложение</font></strong> – не се резорбират в ГИТ.</li><ul><li><font color=\"#000000\">Интравенозно приложение.</font></li><li><font color=\"#000000\">Орално приложение при псевдомемранозен колит.</font></li></ul><li><font color=\"#963717\"><strong>Разпределение</strong> </font>– екстрацелуларно.</li><li><font color=\"#963717\"><strong>Елиминация</strong> </font>– бъбречна екскреция главно чрез гломерулна филтрация.</li><li><strong><font color=\"#963717\">Приложение</font></strong></li><ul><li><font color=\"#7e22ce\"><em style=\"\">Vancomycin</em> </font>се прилага на <font color=\"#000000\">8-12 часа.</font></li><li><font color=\"#7e22ce\"><em style=\"\">Teicoplanin</em> </font>има по-дълъг плазмен полуживот – <font color=\"#000000\">еднократно дневно приложение.</font></li></ul></ul><h3>Клинично приложение</h3><ul><li><font color=\"#000000\">Лекарства на <strong style=\"\">втора линия</strong> за лечение на</font><font color=\"#3b82f6\"> тежки инфекции</font><font color=\"#000000\">, като </font><font color=\"#3b82f6\">сепсис</font><font color=\"#000000\">, </font><font color=\"#3b82f6\">ендокардит</font>, <font color=\"#3b82f6\">остеомиелит</font>, <font color=\"#3b82f6\">предизвикани </font>от <font color=\"#3b82f6\"><b>MRSA </b></font>и <font color=\"#3b82f6\"><b>PRSP</b></font>.</li><li>При <font color=\"#3b82f6\">ентерококови инфекции </font>(напр. ендокардит) – комбинация с аминогликозиди.</li><li><font color=\"#3b82f6\"><b style=\"\">Псевдомембранозен колит</b> </font>(орално приложение).</li></ul><h3>Нежелани лекарствени реакции</h3><ul><li>Доза-зависима<strong style=\"\"> <u style=\"\"><font color=\"#dd0a0a\">ото- и нефрототоксичност</font></u></strong><font color=\"#000000\"> (повишен риск при комбиниране с аминогликозиди).</font></li><li><strong style=\"\"><u style=\"\"><font color=\"#dd0a0a\">Синдром на “червения човек”</font></u></strong><font color=\"#000000\">.</font></li><li><font color=\"#dd0a0a\">Флебит</font><font color=\"#000000\"> </font>при интравенозно приложение.</li></ul><hr><h2>Аминогликозидни антибиотици</h2><h3>Класификация</h3><ul><li><strong>Природни</strong></li><ul><li><i><font color=\"#7e22ce\">Gentamicin</font></i></li><li><i><font color=\"#7e22ce\">Tobramycin</font></i></li><li><i><font color=\"#7e22ce\">Streptomycin</font></i></li><li><i><font color=\"#7e22ce\">Neomycin</font></i></li></ul><li><strong>Полусинтетични</strong></li><ul><li><i><font color=\"#7e22ce\">Amikacin</font></i></li></ul></ul><h3>Механизъм на действие</h3><ul><li>Аминогликозидите навлизат в бактериалните клетки чрез <font color=\"#000000\"><strong>активен транспорт, </strong>който е зависим от налич</font>ието на<strong> <font color=\"#000000\">кислород</font></strong><font color=\"#000000\"> </font>=&gt; <strong><font color=\"#dd0a0a\">анаеробите са резистентни</font></strong>.</li><li>Аминогликозидите се свързват с<font color=\"#000000\"> <strong style=\"\">30S субединицата</strong> на бактериалните рибозоми.</font></li><li><font color=\"#000000\">Инхибират протеиновия синтез и водят до грешки в разчитането на иРНК, при което се синтезират нефункционални протеини.</font></li><li><font color=\"#000000\"><strong>Синергично действие</strong> с лекарства, инхибиращи синтеза на клетъчна стена (бета лактами и гликопептиди).</font></li></ul><h3>Антибактериален спектър – широкоспектърни</h3><ul><li>Висока активност спрямо <strong><font color=\"#3b82f6\"><u>G(-) бактерии</u></font></strong>, вкл. <em>P.aeruginosa, K.pneumoniae</em> и представителите на сем. <em>Enterobacteriaceae</em>.</li><li>Активност спрямо някои <font color=\"#3b82f6\">G(+) бактерии</font>, вкл. ентерококи.</li><li>Активност спрямо <font color=\"#3b82f6\"><strong style=\"text-decoration-line: underline;\">микобактерии</strong> </font>(напр. <em>Mycobacterium tuberculosis</em>).</li><li><strong><font color=\"#dd0a0a\">Липса на активност спрямо анаероби</font></strong>.</li></ul><h3>Резистентност</h3><ul><li><font color=\"#000000\">Инактивиране от ензими&nbsp;</font><p style=\"\"><font color=\"#000000\">– </font><i style=\"\"><font color=\"#7e22ce\">amikacin </font></i><font color=\"#000000\">е по-устойчив на ензимно разграждане от </font></p><p style=\"color: rgb(0, 0, 0);\">природните аминогликозиди</p></li><li><font color=\"#000000\">Нарушаване на на влизането им в клетката.</font></li><li><font color=\"#000000\">Мутация на свързващото място върху 3</font>0S субединицата.</li></ul><h3>Фармакокинетика</h3><ul><li><font color=\"#000000\">Големи водоразтворими молекули =&gt; не преми</font>нават през клетъчните мембрани на човешките клетки.</li><li><strong><font color=\"#993d1e\">Резорбция и пътища на приложение</font></strong>:</li><ul><li><font color=\"#000000\">Не се резорбират в ГИТ.</font></li><li><font color=\"#000000\">Парентерално системно приложение – мускулно или интравенозно.</font></li><li><font color=\"#000000\">Локално приложение&nbsp;<p>върху кожата и лигавиците под формата на </p><p>спрейове, кремове, унгвенти, колири и др.</p></font></li><li><font color=\"#7e22ce\"><em style=\"\">Tobramycin</em> </font>се прилага и под формата на <font color=\"#3b82f6\">разтвор за инхалиране </font>с цел локално действие в белите дробове.</li></ul><li><font color=\"#993d1e\"><strong>Разпределение</strong> </font>– <font color=\"#000000\">екстрацелуларно</font>.</li><ul><li><font color=\"#000000\">Не преминават през ХЕБ, хемато-окуларната и простатната бариера.</font></li><li><font color=\"#000000\">Преминават през плацентата.</font></li></ul><li><strong><font color=\"#993d1e\">Елиминация</font></strong>:</li><ul><li><font color=\"#000000\">Бъбречна екскреция основно чрез гломерулна филтрация.</font></li><li><font color=\"#000000\">Акумулират при бъб</font>речна недостатъчност.</li></ul><li><strong><font color=\"#993d1e\">Плазмен полуживот и дозов режим</font></strong>:</li><ul><li><font color=\"#000000\">Кратък плазмен полуживот.</font></li><li><font color=\"#000000\"><strong>Еднократно дневно приложение</strong>: имат концентрация-зависимо действие и значителен постантибиотичен ефект&nbsp;<p>=&gt; терапевтичният </p><p>ефект е по-добър, ако цялата дневна доза се приложи еднократно </p><p>вместо да се разделя на 2 или 3 приема </p></font></li></ul></ul><h3>Клинично приложение</h3><ul><li>Тежки <font color=\"#3b82f6\">уроинфекции </font>и <font color=\"#3b82f6\">уросепсис</font>&nbsp;<p>– парентерално системно приложение</p></li><li><font color=\"#3b82f6\">Дихателни инфекции</font>, причинени от <em><font color=\"#3b82f6\">K. pneumonia</font></em> или <font color=\"#3b82f6\"><em>P. aeruginosa</em> </font>(напр. белодробни усложнения при пациенти с муковисцидоза) – парентерално системно приложение или инхалиране на <font color=\"#7e22ce\"><i>tobramycin </i></font>(минимална абсорбция в системното кръвообращение).</li><li><font color=\"#3b82f6\">Гастроинтестинални инфекции</font> – парентерално системно или орално приложение (локално действие в ГИТ).</li><li><font color=\"#3b82f6\">Тазови </font>и <font color=\"#3b82f6\">интраабдоминални инфекции</font>.</li><li><font color=\"#3b82f6\">Ендокардит&nbsp;</font><p>– комбиниране с гликопептиди при ентерококови инфекции\r\n</p></li><li><font color=\"#3b82f6\">Сепсис </font>и <font color=\"#3b82f6\">смесени инфекции</font><font color=\"#7e22ce\">&nbsp;</font><font color=\"#000000\"><p style=\"\">– комбиниране с бета-лактами и</p><p style=\"\">антианаеробни лекарства</p></font></li><li><font color=\"#3b82f6\">Микобактериални инфекции</font> (напр. туберкулоза)&nbsp;<p> – комбиниране с други</p><p>антимикобактериални средства\r\n</p></li><li><font color=\"#3b82f6\">Чума</font>, <font color=\"#3b82f6\">туларемия</font>, <font color=\"#3b82f6\">бруцелоза</font>.&nbsp;<p>– комбиниране с тетрациклини</p></li><li><font color=\"#3b82f6\">Локално приложение при очни инфекции и инфектирани кожни рани и изгаряния</font>.</li></ul><h3>Нежелани лекарствени реакции</h3><ul><li><u style=\"\"><b style=\"\"><font color=\"#dd0a0a\">Ототоксичност&nbsp;и нефротоксичност</font></b></u><font color=\"#000000\">.</font></li><li><font color=\"#dd0a0a\">Кураре-подобен ефект</font><font color=\"#000000\"> –</font><p style=\"color: rgb(0, 0, 0);\"> потискат освобождаването на ацетилхолин от </p><p style=\"\"><font color=\"#000000\">двигателните нерви в моторната плочка, водещо до </font><b style=\"\"><font color=\"#dd0a0a\">нервно-мускулен блок</font></b><font color=\"#000000\"> =&gt; </font></p><p style=\"\"><u style=\"\"><font color=\"#000000\">риск от </font><font color=\"#dd0a0a\">дихателна парализа</font><font color=\"#000000\"> при комбиниране с периферни миорелаксанти</font></u><font color=\"#000000\">.</font></p></li><li><font color=\"#dd0a0a\">Дисбактериоза и суперинфекции</font><font color=\"#000000\">.</font></li><li><font color=\"#dd0a0a\">Тератогенни ефекти</font><font color=\"#000000\">&nbsp;<p>– неподходящи по време на бременност.</p></font></li></ul><h3>Лекарствени взаимодействия</h3><ul><li>По-добър <font color=\"#65a30d\">терапевтичен ефект </font>с <font color=\"#65a30d\">бета-лактами </font>и <font color=\"#65a30d\">гликопептиди</font>.</li><li>Повишен риск от <font color=\"#dd0a0a\">ототоксичност </font>с <font color=\"#dd0a0a\">гликопептиди </font>и <font color=\"#dd0a0a\">бримкови диуретици</font>.</li><li>Повишен риск от <font color=\"#dd0a0a\">нефротоксичност </font>с <font color=\"#dd0a0a\">гликопептиди </font>и <font color=\"#dd0a0a\">други нефротоксични лекарства </font>(напр. <em>amphotericin B</em>).</li><li>Повишен риск от <u><font color=\"#dd0a0a\">дихателна парализа </font>с <font color=\"#dd0a0a\">миорелаксанти</font></u>.</li></ul><hr><h2>Други бактерицидни антибиотици - <i><font color=\"#7e22ce\">Fosfomycin</font></i></h2><ul><li><strong><font color=\"#3a5a40\">Механизъм на действие</font></strong>: блокиране на началните фази на си<font color=\"#000000\">нтезата на пептидогликан.</font></li><li><strong><font color=\"#3a5a40\">Антибактериален спектър</font></strong>:<font color=\"#3b82f6\"> <em>in vitro</em></font> активност спрямо много <font color=\"#3b82f6\">G(+) </font>и <font color=\"#3b82f6\">G(-) бактерии</font>.</li><li><strong><font color=\"#3a5a40\">Резистентност</font></strong>: нарушено навлизане на лекарството в клетката.</li><li><strong><font color=\"#3a5a40\">Фармакокинетика</font></strong>:</li><ul><li><font color=\"#000000\">Орално приложение.</font></li><li><font color=\"#000000\">Бъбречна екскреция.</font></li><li><font color=\"#000000\">Еднократно приложение </font>(многократното приложение води до резистентност).</li></ul><li><strong><font color=\"#3a5a40\">Клинично приложение</font></strong>:</li><ul><li><font color=\"#3b82f6\">Неусложнен цистит</font> – висока еднократна доза вечер преди лягане.</li><li><font color=\"#000000\">Безопасен за употреба по време на бременност.</font></li></ul></ul><hr><h2>Други бактерицидни антибиотици - <i><font color=\"#7e22ce\">Fidaxomicin</font></i></h2><ul><li><strong><font color=\"#3a5a40\">Механизъм на дейсвие</font></strong>: инхибиране <font color=\"#000000\">на транскрипцията чрез блокиране на РНК полимеразата.</font></li><li><strong><font color=\"#3a5a40\">Тесен антибактериален спектър</font></strong>: <font color=\"#3b82f6\">G(+) анаероби</font>, вкл. <em><font color=\"#3b82f6\">Clostridium difficile</font></em>.</li><li><strong><font color=\"#3a5a40\">Фармакокинетика</font></strong>:</li><ul><li><font color=\"#000000\">Слаба резорбция в ГИТ.</font></li><li><font color=\"#000000\"><u>Орално приложение с цел локално действие в ГИТ</u>.</font></li><li><font color=\"#000000\">Екскреция с фецеса.</font></li></ul><li><strong><font color=\"#3a5a40\">Клинично приложение</font></strong>:</li><ul><li><font color=\"#3b82f6\">Псевдомембранозен колит</font>.</li></ul><li><strong><font color=\"#3a5a40\">Нежелани лекарствени реакции</font></strong>:</li><ul><li><font color=\"#dd0a0a\">Гастроинтестинални смущения</font>.</li></ul></ul><hr><h2><p>СИНТЕТИЧНИ БАКТЕРИЦИДНИ ЛЕКАРСТВА. ФЛУОРИРАНИ ХИНОЛОНИ</p></h2><h3>Класификация</h3><ul><li><strong>Първо поколение</strong></li><ul><li><i><font color=\"#7e22ce\">Ciprofloxacin</font></i></li><li><i><font color=\"#7e22ce\">Norfloxacin</font></i></li><li><i><font color=\"#7e22ce\">Ofloxacin</font></i></li></ul><li><strong>Второ поколение</strong></li><ul><li><i><font color=\"#7e22ce\">Levofloxacin</font></i></li><li><i><font color=\"#7e22ce\">Moxifloxacin</font></i></li></ul></ul><h3>Механизъм на действие</h3><ul><li><font color=\"#3b82f6\">Инхибиране </font>на <font color=\"#3b82f6\" style=\"\">топоизомераза II<b style=\"\"> </b><b style=\"text-decoration-line: underline;\">(ДНК гираза</b><b>)</b></font> в<font color=\"#3b82f6\"> G(-) бактерии</font> и <font color=\"#3b82f6\" style=\"\">топоизомераза IV</font> в <font color=\"#3b82f6\">G(+) бактерии.</font></li><ul><li><font color=\"#000000\"><p style=\"\">Инхибирането на ДНК гиразата предотвратява релаксацията на суперспирализираната </p><p style=\"\">молекула на ДНК, което е необходимо за репликацията и транскрипцията</p></font></li><li><font color=\"#000000\"><p style=\"\">Инхибирането на топоизомераза IV предотвратява разделянето на новосинтезираната </p><p style=\"\">хромозомна ДНК</p></font></li></ul><li><span style=\"white-space-collapse: preserve; color: rgb(0, 0, 0);\">Блокирането на бактериалните топоизомерази възпрепятства синтезата на ДНК</span></li></ul><h3>Антибактерилен спектър – широкоспектърни</h3><ul><li><strong><font color=\"#3b82f6\">Първо поколение</font></strong> проявяват висока активност спрямо <strong><font color=\"#3b82f6\">G(-) патогени</font></strong>, вкл. <em><font color=\"#3b82f6\">Enterobacter spp</font>., <font color=\"#3b82f6\">P. aeruginosa,</font> <font color=\"#3b82f6\">N.meningitidis</font>, <font color=\"#3b82f6\">Haemophilus spp</font>.</em> и <em><font color=\"#3b82f6\">Campylobacter jejuni</font></em>.</li><ul><li><font color=\"#7e22ce\"><i>Ciprofloxacin </i></font>и <font color=\"#7e22ce\"><em style=\"\">ofloxacin</em> </font>са активни и срещу <font color=\"#3b82f6\">MSSA</font>, но <font color=\"#dd0a0a\">не </font>срещу <font color=\"#dd0a0a\">стрептококи</font>, <font color=\"#dd0a0a\">ентерококи </font>и <font color=\"#dd0a0a\">MRSA</font>.</li></ul><li><strong><font color=\"#3b82f6\">Второ поколение</font></strong><font color=\"#3b82f6\"> </font>са с по-висока активност спрямо <strong><font color=\"#3b82f6\">G(+) бактерии</font></strong>, но <font color=\"#dd0a0a\">с по-ниска</font> спрямо <font color=\"#dd0a0a\">G(-) бактерии</font>.</li><ul><li><font color=\"#7e22ce\"><em style=\"\">Moxifloxacin</em> </font>е активен спрямо <strong>анаероби</strong>.</li></ul><li>Активни спрямо <strong><font color=\"#3b82f6\">вътреклетъчни патогени</font></strong> – <font color=\"#3b82f6\">микоплазми, хламидии, <em>Legionella</em></font>.</li><li>Активни спрямо <strong><font color=\"#3b82f6\">микобактерии</font></strong>.</li></ul><h3>Резистентност</h3><ul><li><font color=\"#000000\">Мутации на свързващите места на таргетните ензими.</font></li><li><font color=\"#000000\">Нарушено навлизане в бактериалните клетки.</font></li><li><font color=\"#000000\">Активен ефлукс чрез транспортер.</font></li></ul><h3>Фармакокинетика</h3><ul><li><font color=\"#000000\"><strong>Липоразтворими лекарства</strong>.</font></li><li><strong><font color=\"#993d1e\">Резорбция и пътища на приложение</font></strong>:</li><ul><li><font color=\"#000000\">Добра резорбция при перорално приложение<p>, която не зависи от приема на храна, но се намалява при</p><p>наличие на би- и тривалентни катиони.</p></font></li><li><font color=\"#000000\">Парентерално приложение при тежки инфе</font>кции.</li></ul><li><strong><font color=\"#993d1e\">Разпределение</font></strong>:</li><ul><li><font color=\"#000000\">Извън- и вътреклетъчно разпределение – високи концентрации се достигат в повечето тъкани (особено бъбреци, простата, бели дробове) и телесни течности.</font></li><li><strong><font color=\"#993d1e\">Бариерни системи</font></strong>:</li><ul><li><font color=\"#000000\">Преминават добре през хемато-простатната и хемато-окуларната барие</font>ра.</li><li><font color=\"#7e22ce\"><em style=\"\">Ofloxacin</em> </font>преминава <font color=\"#000000\">ХЕБ.</font></li><li><font color=\"#000000\">Всички минават през плацентата.</font></li></ul><li>Високи концентрации в <font color=\"#3b82f6\">костите и хрущялите</font>.</li></ul><li><strong><font color=\"#993d1e\">Елиминация</font></strong>:</li><ul><li>Основно<font color=\"#000000\"> бъбречна елиминация.</font></li><li><font color=\"#7e22ce\"><em style=\"\">Moxifloxacin</em> </font>и <font color=\"#7e22ce\"><em style=\"\">norfloxacin</em> </font>се <font color=\"#000000\">метаболизират </font>частично в черния дроб.</li></ul><li><strong><font color=\"#993d1e\">Приложение</font></strong>:</li><ul><li><font color=\"#000000\">Първо поколение се прилагат на 12 часа.</font></li><li><font color=\"#000000\">Второ поколение се прилагат на 24 часа</font>.</li></ul></ul><h3>Клинично приложение</h3><ul><li><strong>Първо поколение</strong>:</li><ul><li><font color=\"#3b82f6\">Уроинфекции&nbsp;</font><p>– пиелонефрит, уросепсис (<font color=\"#dd0a0a\">не </font>при цистит)\r\n</p></li><li><font color=\"#3b82f6\">Простатит</font>.</li><li><font color=\"#3b82f6\">Гастроинтестинални инфекции</font>.</li><li><font color=\"#3b82f6\">Дихателни инфекции</font>, предизвикани от <font color=\"#3b82f6\">G(-) бактерии</font>, <p>напр. белодробни усложнеия от<font color=\"#3b82f6\"> P.aeruginosa</font> </p><p>при пациенти с муковисцидоза\r\n</p></li><li>Локални приложение при <font color=\"#3b82f6\">очни инфекции</font>.</li></ul><li><strong>Второ поколение</strong>:</li><ul><li><font color=\"#3b82f6\">Инфекции на дихателните пътища</font>, <u>вкл. атипична пневмония</u> (лекарства на втори избор).</li><li><font color=\"#3b82f6\">Инфекции на кости и стави</font>.</li><li><font color=\"#3b82f6\">Инфекции на меки тъкани</font>.</li><li>Гонококов и негонококов <font color=\"#3b82f6\">уретрит </font>(лекарства на втори избор).</li><li><font color=\"#3b82f6\">Туберкулоза </font>- <i><font color=\"#7e22ce\">ciprofloxacin</font></i>, <i><font color=\"#7e22ce\">levofloxacin </font></i>и <i><font color=\"#7e22ce\">miofloxacin </font></i>(лекарства на втори избор).</li><li>Профилактика и лечение на <font color=\"#3b82f6\">anthrax </font>- <i><font color=\"#7e22ce\">ciprofloxacin </font></i>и <i><font color=\"#7e22ce\">levofloxacin</font></i></li><li><font color=\"#3b82f6\">Анаеробни инфекции</font> - <i><font color=\"#7e22ce\">moxifloxacin</font></i></li></ul></ul><h3>Нежелани лекарствени реакции</h3><ul><li><font color=\"#dd0a0a\">Гастроинтестинални нарушения</font><font color=\"#3b82f6\">.</font></li><li><p style=\"\"><font color=\"#dd0a0a\">Централно-нервни нежелани ефекти </font><font color=\"#000000\">– замаяност, главоболие, безсъние, намалено внимание и концентрация, </font></p><p style=\"\"><font color=\"#000000\">тревожност, депресия, паметови смущения, повишен риск от гърчове</font></p></li><li><p style=\"\"><font color=\"#dd0a0a\">Периферна невропатия</font><b style=\"color: rgb(59, 130, 246);\">\r\n</b></p></li><li><font color=\"#dd0a0a\">Алергични реакции&nbsp;</font><p style=\"color: rgb(0, 0, 0);\">– кожни обриви, фоточувствителност</p></li><li><strong><font color=\"#dd0a0a\">Удължаване на QT интервала</font></strong> – <font color=\"#7e22ce\"><em>levofloxacin</em> </font>и <em><font color=\"#7e22ce\">moxifloxacin</font></em>.</li><li><strong><font color=\"#dd0a0a\">Увреждания на опорно-двигателната система</font></strong>:</li><ul><li>Увреждане на ставния хрущял и <font color=\"#dd0a0a\">артропатия </font>(при деца).</li><li><strong><font color=\"#dd0a0a\">Тендинити, риск от руптура на сухожилия</font><font color=\"#3b82f6\">&nbsp;</font></strong><p>(повишен риск при пациенти в напреднала възраст и тежко</p><p>общо състояние)</p></li></ul><li><font color=\"#dd0a0a\">Чернодробна увреда</font>.</li><li><font color=\"#dd0a0a\">Промени в кръвно-захарните нива</font>.</li><li><font color=\"#dd0a0a\">Дисбактериоза и суперинфекции </font>(вкл. псевдомембранозен колит).</li><li><strong><font color=\"#dd0a0a\">Не са подходящи за деца, бременни и кърмачки</font></strong>.</li><li><font color=\"#dd0a0a\">По препоръка на EMA (European Medicine Agency) употребата на флуорирани хинолони трябва да бъде ограничена поради персистиращи потенциално инвалидизиращи странични ефекти</font>.</li></ul><h3>Лекарствени взаимодействия</h3><ul><li><font color=\"#7e22ce\"><em style=\"\">Ciprofloxacin</em> </font>и <font color=\"#7e22ce\"><em style=\"\">norfloxacin</em> </font><font color=\"#dd0a0a\">инхибират CYP1A2</font><p style=\"\"><font color=\"#000000\">, при което повишават плазмените нива и токсичност на други</font></p><p style=\"\"><font color=\"#000000\">лекарства, напр. <i>theophylline</i></font><font color=\"#dd0a0a\">\r\n</font></p></li><li><p><font color=\"#dd0a0a\">Оралната резорбция</font> се намалява при прием на <font color=\"#dd0a0a\">лекарства</font>,<font color=\"#dd0a0a\"> съдържащи дву- и тривалентни катиони </font>като </p><p>антиацидни и антианемични железни препарати</p></li><li><p><font color=\"#7e22ce\"><i>Moxifloxacin </i></font>и <font color=\"#7e22ce\"><i>levofloxacin </i></font>повишават риска от <font color=\"#dd0a0a\">аритмии </font></p><p>повишават риска от аритмии при едновременно приложение на антиаритмици от</p><p>клас Ia и III, някои антипсихотици и антидепресанти и др. (поради <font color=\"#dd0a0a\">удължаване на QT интервала</font>)\r\n</p><font color=\"#dd0a0a\"></font></li><li><p>При комбиниране с <font color=\"#dd0a0a\">НСПВЛ </font>се повишава рискът от <font color=\"#dd0a0a\">гърчове</font></p></li></ul><br><br>\r\n<p><span style=\"color: rgb(124, 45, 18); font-size: 1.5em; font-weight: 600;\">Бактериостатични антимикробни лекарства. Антианаеробни лекарства</span></p><p><span style=\"color: rgb(124, 45, 18); font-size: 1.5em; font-weight: 600;\">Доц. д-р Антоанета Георгиева, д.м.</span></p><hr><h2>Бактериостатични антимикробни лекарства</h2><h3>Антибиотици (Природни и Полусинтетични)</h3><ul><li><strong>Тетрациклини</strong></li><ul><li>Природни: <i><font color=\"#7e22ce\">Tetracycline</font></i></li><li>Полусинтетични: <i><font color=\"#7e22ce\">Doxycycline</font></i></li></ul><li><strong>Макролиди</strong></li><ul><li>І поколение:&nbsp;</li><ul><li><i><font color=\"#7e22ce\">Erythromycin</font></i></li><li><p><i><font color=\"#7e22ce\">Spiramycin </font></i>+ <i><font color=\"#7e22ce\">Metronidazole</font></i></p></li></ul><li>ІІ поколение:&nbsp;</li><ul><li><i><font color=\"#7e22ce\">Clarithromycin</font></i></li><li><i><font color=\"#7e22ce\">Azithromycin</font></i></li><li><p><i><font color=\"#7e22ce\">Midecamycin</font></i></p></li><li><p><i><font color=\"#7e22ce\">Roxithromycin</font></i></p></li></ul></ul><li><strong>Линкозамиди</strong></li><ul><li><i><font color=\"#7e22ce\">Clindamycin</font></i></li><li><i><font color=\"#7e22ce\">Lincomycin</font></i></li></ul><li><strong>Амфениколи</strong></li><ul><li><i><font color=\"#7e22ce\">Chloramphenicol</font></i></li></ul></ul><h3>Синтетични Лекарства</h3><ul><li><strong>Сулфонамиди</strong></li><ul><li>Със системно действие: <i><font color=\"#7e22ce\">Sulfamethoxazole + Trimethoprim = <strong>Co-trimoxazole</strong></font></i></li><li>С локално действие в <p>храносмилателния тракт</p>: <i><font color=\"#7e22ce\">Sulfasalazine</font></i></li><li>С локално действие върху кожата: <i><font color=\"#7e22ce\">Sulfathiazole</font></i></li></ul><li><strong>Оксазолидинони</strong></li><ul><li><i><font color=\"#7e22ce\">Linezolid</font></i></li></ul></ul><hr><h2>Тетрациклини</h2><h3>Спектър на действие - <u>широк</u>:</h3><ul><li><font color=\"#3b82f6\">G+ и G-</font>, вкл. <font color=\"#3b82f6\"><i>Enterobacteriaceae</i></font>, <font color=\"#3b82f6\"><i>H. influenzae</i></font>, <font color=\"#3b82f6\"><i>V. cholerae</i></font>, <font color=\"#3b82f6\"><i>Brucella</i></font>.</li><li><font color=\"#3b82f6\">Вътреклетъчни бактерии</font> - <font color=\"#3b82f6\"><i>Ricketsia</i></font>, <font color=\"#3b82f6\"><i>Chlamydia</i></font>.</li><li><font color=\"#3b82f6\">Бактерии без клетъчна стена </font>- <i><font color=\"#3b82f6\">Mycoplasma</font></i>, <font color=\"#3b82f6\"><i>Ureaplasma</i></font>.</li><li><font color=\"#3b82f6\">Спирохети </font>- <font color=\"#3b82f6\"><i>Т. pallidum</i></font>, <font color=\"#3b82f6\"><i>Borellia</i></font>.</li><li><font color=\"#3b82f6\">Първаци </font>- <font color=\"#3b82f6\"><i>Entamoeba</i></font>, <font color=\"#3b82f6\"><i>Plasmodium</i></font>.</li></ul><strong><h3><strong>Фармакодинамика:</strong></h3></strong><ul><li>Проникват в бактериалната клетка посредством пасивен и активен транспорт.</li><li>Концентрират се в бактериалната клетка.</li><li>Свързват се с <strong><font color=\"#3b82f6\">30S рибозомната единица</font></strong>.</li><li>Спират удължаването на полипептидната верига като блокират свързването на аминоацил-тРНК с мРНК-рибозомния комплекс.</li><li><font color=\"#3b82f6\">Потиска се синтезата на протеини в бактериалната клетка</font>.</li></ul><h3>Фармакокинетика</h3><ul><li><strong><font color=\"#7e22ce\">Tetracycline&nbsp;</font></strong></li><ul><li><b style=\"\"><font color=\"#973312\">Приложение</font></b><font color=\"#3b82f6\">: </font><font color=\"#000000\">Орално и локално <strong>.</strong></font></li><li><b><font color=\"#973312\">Резорбция</font></b>:&nbsp;</li><ul><li>Нару<font color=\"#000000\">шава се от храна (напр. млечни продукти) и лекарства, съдържащи дву- и тривалентни йони като Ca<sup>2+</sup>, M</font>g<sup>2+</sup>, Fe<sup>2+/3</sup>+ (напр. антиациди, лаксативи, антианемични) поради образуване на неразтворими комплекси.</li></ul><li><b><font color=\"#973312\">Разпределение</font></b>:&nbsp;</li><ul><li>Прони<font color=\"#000000\">ква вътреклетъчно, преминава бариери, висока концентрация, но не в ЦНС.&nbsp;</font></li><li><font color=\"#3b82f6\">Натрупва се в кости и зъби</font> поради висок афинитет към Са.</li></ul><li><b><font color=\"#973312\">Елиминация</font></b>:<font color=\"#000000\">&nbsp;Излъчва се непроменен през бъбреците.</font></li><li><b><font color=\"#973312\">Полуживот</font></b>:<font color=\"#000000\">&nbsp;Кратък.</font></li></ul><li><strong><font color=\"#7e22ce\">Doxycycline&nbsp;</font></strong></li><ul><li><b style=\"\"><font color=\"#973312\">Приложение</font></b><font color=\"#3b82f6\">:</font><font color=\"#000000\"> Орално<strong>.</strong></font></li><li><b><font color=\"#973312\">Резорбция</font></b>:&nbsp;</li><ul><li>Не се нарушава от храна и лекарства.</li></ul><li><b><font color=\"#973312\">Разпределение</font></b>:&nbsp;</li><ul><li><font color=\"#000000\">Прониква вътреклетъчно, преминава бариери, висока концентрация, но не в ЦНС</font>.&nbsp;</li><li><font color=\"#000000\">Свързва се с плазмените протеини.&nbsp;</font></li><li><font color=\"#3b82f6\">Натрупва се в кости и зъби</font> поради висок афинитет към Са.</li></ul><li><b><font color=\"#973312\">Елиминация</font></b>:<font color=\"#3b82f6\"> </font><font color=\"#000000\">Метаболизира се, излъчва се с жлъчката и претърпява ентерохепатален кръговрат.</font></li><li><b><font color=\"#973312\">Полуживот</font></b>: <font color=\"#000000\">Дълъг.</font></li></ul></ul><h3><p>Резистентност - висока:</p></h3><ul><li>Ограничено проникване в клетката или активен ефлукс.</li><li>Нарушено свързване с рибозомата.</li><li>Ензимно обезвреждане.</li></ul><h3>Показания:</h3><ul><li><font color=\"#3b82f6\">Епидемичен петнист тиф</font> (<i>R. provaceki</i>), <font color=\"#3b82f6\">възвратен тиф </font>(<i>B. recurrentis</i>)&nbsp;</li><li><font color=\"#3b82f6\">Респираторни инфекции</font> <p><i>(S. pneumoniae, Chlamydia, Mycoplasma</i>)</p></li><li>Полово-предавани инфекции<p> - <font color=\"#3b82f6\">негонококов уретрит</font>, <font color=\"#3b82f6\">простатит</font>, <font color=\"#3b82f6\">цервицит </font></p><p>(<i>C. trachomatis, Mycoplasma, Ureaplasma</i>)</p></li><li><font color=\"#3b82f6\">Лаймска болест</font><p><font color=\"#3b82f6\"> </font>(<i>B. burgdorferi</i>)</p></li><li><font color=\"#3b82f6\">Холера</font></li><li><font color=\"#3b82f6\">Чума, туларемия, бруцелоза</font></li><li><font color=\"#3b82f6\">Антракс</font></li><li>СЧТ - <font color=\"#3b82f6\">жлъчно-чернодробни инфекции</font> (<i><font color=\"#7e22ce\">Doxycycline</font></i>); <font color=\"#3b82f6\">язвена болест</font> (<i><font color=\"#7e22ce\">Tetracycline</font></i>).</li><li><font color=\"#3b82f6\">Акне </font>(<i><font color=\"#7e22ce\">Tetracycline </font></i>локално)</li><li><font color=\"#3b82f6\">Сифилис</font>, <font color=\"#3b82f6\">шигелоза</font>, <font color=\"#3b82f6\">лептоспироза</font>...</li></ul><h3>Нежелани реакции</h3><ul><li><font color=\"#3b82f6\">Стомашно</font>-<font color=\"#3b82f6\">чревни</font>, <font color=\"#3b82f6\">дисбактериоза </font>и <font color=\"#3b82f6\">суперинфекции</font>.</li><li>Натрупване в костите и зъбите - <b style=\"color: rgb(59, 130, 246);\">оцветяване на зъбите, кариес </b><font color=\"#000000\">по време на минерализация.</font></li><li><font color=\"#3b82f6\"><strong>Фоточувствителност</strong> </font>(<i><font color=\"#7e22ce\">Doxycycline</font></i>).</li><li><font color=\"#3b82f6\">Нефротоксичност </font><font color=\"#000000\"><p>след изтичане на срока на</p><p>годност</p></font></li><li><font color=\"#3b82f6\">Хепатотоксичност при бременни</font>.</li></ul><h3>Противопоказания</h3><ul><li><font color=\"#dd0a0a\">Бременност, кърмене, деца</font> - увреждане на костите и зъбите.</li><li><font color=\"#dd0a0a\">Новородени </font>- изместване на билирубин и <strong><font color=\"#dd0a0a\">керниктер</font></strong>.</li><li><font color=\"#dd0a0a\">Чернодробна недостатъчност</font> (<i><font color=\"#7e22ce\">Doxycycline</font></i>).</li><li><font color=\"#dd0a0a\">Бъбречна недостатъчност</font> (<i><font color=\"#7e22ce\">Tetracycline</font></i>).</li></ul><hr><h2><font color=\"#7e22ce\"><i>Chloramphenicol </i></font>(Амфениколи)</h2><h3>Спектър - <u>много широк</u>:</h3><ul><li><u><font color=\"#3b82f6\">Като на тетрациклини, плюс <strong>анаероби</strong></font></u>, вкл. <i><font color=\"#3b82f6\">Bacteroides fragilis</font></i>, БЕЗ C. difficile.</li><li><font color=\"#3b82f6\"><strong>Бактерициден</strong> </font>за <font color=\"#3b82f6\"><i>S. pneumoniae</i></font>, <font color=\"#3b82f6\"><i>N. meningitidis</i></font>, <font color=\"#3b82f6\"><i>H. influenzae</i></font>, <font color=\"#3b82f6\"><i>B. fragilis</i></font>.</li></ul><h3>Фармакокинетика<b>:</b></h3><ul><li><b style=\"\">Приложение</b><font color=\"#3b82f6\">: </font><font color=\"#000000\">Орално, венозно и локално.</font>&nbsp;</li><li><strong>Най-добра орална резорбция</strong> в света (100%).</li><li><b>Разпределение</b>: <font color=\"#000000\">Прониква вътреклетъчно, преодолява лесно бариери, вкл. <strong>кръвно-мозъчната</strong>.</font></li><li><b>Метаболизъм</b>:&nbsp;</li><ul><li><font color=\"#000000\">ІІ фаза, глюкурониране.</font></li><li><font color=\"#000000\">Бъбречна екскреция на неактивните метаболити.</font></li></ul></ul><h3>Фармакодинамика:</h3><ul><li>Свързва се с <strong><font color=\"#3b82f6\">50S рибозомната субединица</font></strong>.</li><li>Предотвратява удължаването на полипептидната верига (транспептидация).</li><li><font color=\"#3b82f6\">Потиска белтъчната синтеза</font>.</li></ul><h3>Показания:</h3><ul><li><font color=\"#3b82f6\"><strong>Никога не е първи избор</strong> </font>(поради опасни НЛР).</li><li>При тежък <font color=\"#3b82f6\">менингит</font>, <font color=\"#3b82f6\">мозъчен абсцес</font>, <font color=\"#3b82f6\">коремен тиф</font>, <font color=\"#3b82f6\"><u>анаеробни инфекции</u></font>, <font color=\"#3b82f6\"><u>рикетсиози</u></font>.</li><li><b>Локално приложение</b>:<font color=\"#000000\"> бактериален конюнктивит, трахома; кожни инфекции, изгаряния, измръзвания, пиодермия.</font></li></ul><b><h3>Нежелани реакции:</h3></b><ul><li><font color=\"#dd0a0a\">Дисбактериози и суперинфекции</font>.</li><li><font color=\"#dd0a0a\"><strong>Доза-зависимо потискане на костния мозък</strong> </font>(анемия, левкопения, тромбоцитопения).</li><ul><li>Риск от потенциално фатална тежка <strong><font color=\"#dd0a0a\">апластична анемия</font></strong>.</li></ul><li><strong><font color=\"#dd0a0a\"><u>Синдром на сивото бебе</u></font></strong> при новородени (поради дефицит на глюкуронил трансфераза).</li></ul><strong><h3>Взаимодействия:</h3></strong><ul><li><font color=\"#dd0a0a\"><strong>Дисулфирам реакция</strong> с алкохол</font>.</li><li><strong><font color=\"#dd0a0a\">Ензимен инхибитор</font></strong> (CYP2C19, 3A4).</li></ul><hr><h2>Макролиди</h2><strong><h3>Спектър - <u>много широк</u>:</h3></strong><ul><ul><li><b>I поколение</b>:&nbsp;</li><ul><li><font color=\"#3b82f6\">G+ коки и бактерии</font></li><li><i><font color=\"#3b82f6\">N. gonorrhoeae</font></i>, <i><font color=\"#3b82f6\">B. pertussis</font></i>, <i><font color=\"#3b82f6\">Legionell</font></i><font color=\"#3b82f6\"><i>a</i></font></li><li><font color=\"#3b82f6\"><i>Chlamydia</i></font>, <font color=\"#3b82f6\"><i>Mycoplasma</i></font></li></ul><li><b>II поколение</b>:&nbsp;</li><ul><li><font color=\"#3b82f6\">Като I поколение + <i>H. influenzae</i></font></li><li><i style=\"\"><font color=\"#7e22ce\">Clarithromycin </font></i>и <i style=\"\"><font color=\"#7e22ce\">Azithromycin </font></i>покриват <i><font color=\"#3b82f6\">Borrelia</font></i>, <i><font color=\"#3b82f6\">Mycobacterium </font></i>(MAC), <i><font color=\"#3b82f6\">Toxoplasma</font></i></li><li><i><font color=\"#7e22ce\">Clarithromycin </font></i>покрива <i><font color=\"#3b82f6\">H. pylori</font></i></li></ul></ul></ul><h3>Фармакодинамика:</h3><ul><li>Свързва се с <strong><font color=\"#3b82f6\">50S рибозомната субединица</font></strong>.</li><li>Предотвратява удължаването на полипептидната верига (транспептидация).</li><li><font color=\"#3b82f6\">Потиска белтъчната синтеза</font>.</li><li>Допълнително <font color=\"#000000\"><strong>противовъзпалително и имуномодулиращо</strong> действие.</font></li><li><font color=\"#000000\">Активиране на мотилинови рецептори и <strong>прокинетично действие</strong>.</font></li></ul><strong><h3>Резистентност:</h3></strong><ul><li>Активен ефлукс.</li><li>Модификация на свързващото място.</li><li>Производство на ензими, които ги разграждат.</li></ul><h3><span style=\"font-size: 1.1em;\">Фармакокинетика:</span></h3><ul><li><font color=\"#000000\">Орална резорбция – по-добра при </font>II поколение.</li><li><b>Разпределение:</b></li><ul><li><font color=\"#000000\"><b style=\"\">В</b><strong>ътреклетъчно</strong>, преминават бариери, но&nbsp; </font>ниска концентрация в ЦНС.&nbsp;</li><li><p>Някои достигат високи концентрации в специфични тъкани, напр. <font color=\"#3b82f6\">вътрешното ухо</font> </p><p>(<i style=\"\"><font color=\"#7e22ce\">Clarithromycin</font></i>), <font color=\"#3b82f6\">тонзили </font>(<i style=\"\"><font color=\"#7e22ce\">Roxithromycin</font></i>);</p></li><li><i><font color=\"#7e22ce\">Azithromycin </font></i>достига <font color=\"#3b82f6\">високи концентрации във всички тъкани</font>.</li></ul><li><font color=\"#000000\">Частичен метаболизъм,</font> <i style=\"\"><font color=\"#7e22ce\">Clarithromycin </font></i><font color=\"#3b82f6\">има активен метаболит</font>.</li><li><font color=\"#000000\">Жлъчна и бъбречна екскреция</font><p><font color=\"#000000\">, </font><i><font color=\"#7e22ce\">Spiramycin </font></i><font color=\"#3b82f6\">и значителна слюнчена екскреция</font></p></li><li><b>Плазмен полуживот</b> – <font color=\"#000000\">кратък за I поколение, дълъг за II,</font><font color=\"#3b82f6\"> </font><strong style=\"\"><font color=\"#3b82f6\">най-дълъг за </font><font color=\"#7e22ce\"><i>Azithromycin</i></font></strong>.</li></ul><h3>Показания:</h3><ul><li><font color=\"#3b82f6\">Респираторни инфекции&nbsp;<p> – дифтерия, коклюш, <u>атипична пневмония</u>, </p><p>легионелоза</p></font></li><li><font color=\"#3b82f6\">Полово-предавани</font> (<i style=\"\"><font color=\"#7e22ce\">Azithromycin</font></i>)</li><li><font color=\"#3b82f6\">Язвена болест </font><font color=\"#000000\">- H. Pylori</font> (<i style=\"\"><font color=\"#7e22ce\">Clarithromycin</font></i>).</li><li><font color=\"#3b82f6\"><i>Toxoplasma</i></font>,<font color=\"#3b82f6\"> <i>MAC </i>инфекции при имунокомпроментирани</font>.</li><li><font color=\"#3b82f6\">Оро-дентални инфекции</font> (<font color=\"#7e22ce\"><i>Spiramycin </i>+<i>Metronidazole</i></font>)</li><li><font color=\"#3b82f6\">Профилактика на ендокардит</font>, <p>при високорискови пациенти с клапни пороци </p><p>(<i><font color=\"#7e22ce\">Clarithromycin</font></i>, <i><font color=\"#7e22ce\">Azithromycin</font></i>)</p></li><li><font color=\"#3b82f6\">Акне </font>(<font color=\"#7e22ce\"><i>Erithromycin </i></font>локално)</li><li><span style=\"white-space-collapse: preserve;\">Алтернатива на бета-лактами при респираторни инфекции, отит, синузит</span></li></ul><h3>Нежелани реакции:</h3><ul><li><font color=\"#dd0a0a\">Стомашно-чревни - често</font>&nbsp;<font color=\"#dd0a0a\">диария </font>(поради стимулиране на мотилитета).</li><li><font color=\"#dd0a0a\">Увреждане на слуха</font>, <font color=\"#dd0a0a\">тинитус</font>.</li><li><strong><font color=\"#dd0a0a\">Удължаване на QT интервала</font></strong> с <font color=\"#dd0a0a\">камерна тахикардия&nbsp;</font><p>(<i>Erithromycin</i>, </p><p><font color=\"#7e22ce\"><i>Clarithromycin</i></font>, <font color=\"#7e22ce\"><i>Azithromycin</i></font>)</p></li><li>Холестатична жълтеница (<font color=\"#7e22ce\" style=\"\"><i>Erithromycin</i></font>).</li></ul><h3>Взаимодействия:</h3><ul><li><font color=\"#dd0a0a\"><strong><u>Инхибитори на CYP3A4, P-gp</u></strong> </font>(с изключение на <font color=\"#7e22ce\"><i>Azithromycin</i></font>, <font color=\"#7e22ce\"><i>Spiramycin</i></font>).</li></ul><hr><h2>Линкозамиди (<i><font color=\"#7e22ce\">Clindamycin</font></i>, <i><font color=\"#7e22ce\">Lincomycin</font></i>)</h2><strong><h3>Спектър - <u>тесен</u>:</h3></strong><ul><li><font color=\"#3b82f6\">G+ коки</font>, вкл. <font color=\"#3b82f6\"><i>S. aureus</i></font>.</li><li><strong><font color=\"#3b82f6\">Анаероби</font></strong>, вкл. <i><font color=\"#3b82f6\">B. fragilis</font></i>, <font color=\"#dd0a0a\">БЕЗ C. difficile</font>.</li><li><font color=\"#3b82f6\">Първаци </font>– <i><font color=\"#3b82f6\">P. jirovecii</font></i>, <font color=\"#3b82f6\"><i>Toxoplasma</i></font>.</li></ul><h3>Фармакокинетика:</h3><ul><li><font color=\"#000000\">Добра орална резорбция.</font></li><li><font color=\"#000000\">Широко разпределение – вътреклетъчно,</font> в <strong><font color=\"#3b82f6\">кости</font></strong>, но <font color=\"#000000\">не в ЦНС.</font></li><li><font color=\"#000000\">Частичен метаболизъм, </font><i style=\"\"><font color=\"#7e22ce\">Clindamycin </font></i><font color=\"#000000\">има активни метаболити.</font></li><li><font color=\"#000000\">Жлъчна и бъбречна екскреция.</font></li></ul><h3>Фармакодинамика:</h3><ul><li><span style=\"white-space-collapse: preserve;\">(като Chloramphenicol и макролиди)</span></li><li>Свързва се с <strong><font color=\"#3b82f6\">50S рибозомната субединица</font></strong>.</li><li>Предотвратява удължаването на полипептидната верига (транспептидация).</li><li><font color=\"#3b82f6\">Потиска белтъчната синтеза</font>.</li></ul><h3>Показания:</h3><ul><li><font color=\"#3b82f6\">Инфекции на кожа и меки тъкани</font>, <strong><font color=\"#3b82f6\">остеомиелит</font></strong>.</li><li><strong><font color=\"#3b82f6\">Анаеробни инфекции</font></strong> <p>– <font color=\"#3b82f6\">периодонтален </font>и <font color=\"#3b82f6\">белодробен абсцес</font>; <font color=\"#3b82f6\">проникващи</font></p><p><font color=\"#3b82f6\">коремни рани</font>; женска полова система (<font color=\"#3b82f6\">септичен аборт</font>, <font color=\"#3b82f6\">малкотазово</font></p><p><font color=\"#3b82f6\">възпаление</font>) </p></li><li>Инфекции с <i><font color=\"#3b82f6\">Toxoplasma</font></i>, <i><font color=\"#3b82f6\">P. jirovecii</font></i>&nbsp;<p>при имунокомпроментирани пациенти</p></li><li>Локално при акне, бактериален конюнктивит.</li></ul><h3>Нежелани реакции:</h3><ul><li><font color=\"#dd0a0a\">Стомашно-чревни – често диария</font>.</li><li><font color=\"#dd0a0a\">Дисбактериози </font>и <font color=\"#dd0a0a\">суперинфекции </font>(<strong><font color=\"#dd0a0a\">висока честота на псевдомембранозен колит</font></strong>).</li><li><font color=\"#dd0a0a\">Алергични</font><font color=\"#000000\">.</font></li><li><font color=\"#dd0a0a\">Езофагит</font>.</li><li>Редки: неутропения, тромбоцитопения, хепатотоксичност.</li></ul><hr><h2>Сулфонамиди</h2><h3>Спектър - <u>широк</u>:</h3><ul><li>Широк но <font color=\"#000000\">висока резистентност</font>.</li><li><font color=\"#3b82f6\">G+</font>, <font color=\"#3b82f6\">G-</font>, <font color=\"#3b82f6\"><i>Chlamydia</i></font>, <font color=\"#3b82f6\"><i>Nocardia</i></font>, <font color=\"#3b82f6\"><i>P. jirovecii</i></font>, първаци -&nbsp;<font color=\"#3b82f6\"><i>Entamoeba</i></font>, <font color=\"#3b82f6\"><i>Toxoplasma</i></font>.</li></ul><h3>Фармакокинетика:</h3><ul><li>Деривати на <p>пара-аминобензоена к-на (ПАБК)</p>. <font color=\"#000000\">Добра орална резорбция.</font></li><li><font color=\"#000000\"><strong>Масово свързване с плазмените протеини</strong> </font>(могат да изместват други л-ва и в-ва).</li><li><font color=\"#000000\">Широко разпределения, вкл. вътреклетъчно, преминават бариерите.</font></li><li><b>Метаболизъм</b><font color=\"#000000\">: фаза II глюкурониране и ацетилиране.&nbsp;</font></li><li><font color=\"#000000\">Бъбречна екскреция&nbsp;<p>посредством гломерулна филтрация.</p></font></li></ul><h3>Фармакодинамика:</h3><ul><li><p><i><font color=\"#7e22ce\">Sulfamethoxazole </font></i>и <i><font color=\"#7e22ce\">Trimethoprim </font></i><u>потискат различни стъпки </u></p><p><u>в синтезата на фолиева киселина в бактериите, необходима за синтезата </u></p><p><u>на ДНК</u>.</p></li><li><i><font color=\"#7e22ce\">Sulfamethoxazole </font></i>потиска <strong><font color=\"#000000\">дихидроптероат синтаза</font></strong><p><font color=\"#000000\">, у</font>частващ в </p><p>синтезата на дихидрофолиева к-на от </p><p>пара-аминобензоена к-на.</p></li><li><i><font color=\"#7e22ce\">Trimethoprim </font></i>потиска <strong><font color=\"#000000\">дихидрофолат редуктаза</font></strong><p><font color=\"#000000\">, уч</font>астващ в </p><p>синтеза на тетрахидрофолиева к-на от дихидрофолиева.</p></li><li>Поотделно са <strong><font color=\"#3b82f6\">бактериостатични</font></strong>. Комбинацията (<strong style=\"\"><i style=\"\"><font color=\"#7e22ce\">Co-trimoxazole</font></i></strong><font color=\"#3b82f6\">)</font> е <font color=\"#3b82f6\"><strong>бактерицидна</strong> </font><p>защото потиска две (последователни) </p><p>стъпки и напълно спира синтеза на жизненоважната за бактериите </p><p>фолиева к-на.</p></li></ul><strong><h3>Резистентност:</h3></strong><ul><li>Свръхпроизводство на <p>пара-аминобензоена к-на</p>.</li><li>Ензими с нисък афинитет.</li><li>Затруднено проникване.</li></ul><b><h3>Показания:</h3></b><ul><li><span style=\"white-space-collapse: preserve;\">Респираторни и уроинфекции, но висока резистентност</span></li><li><font color=\"#3b82f6\">Пневмония от <strong><i>P. jirovecii</i></strong></font> и нейната профилактика&nbsp;<p>при имунокомпроментирани болни</p></li><li><font color=\"#3b82f6\">Нокардиоза</font>, <font color=\"#3b82f6\">токсоплазмоза</font>, <font color=\"#3b82f6\">амебиаза</font>.</li><li><i><font color=\"#7e22ce\">Sulfasalazine </font></i>– <font color=\"#3b82f6\">възпалителни чревни заболявания</font>.</li><li><i><font color=\"#7e22ce\">Sulfathiazole </font></i>– <font color=\"#3b82f6\">бактериални кожни инфекции</font>, <font color=\"#3b82f6\">рани</font>, <font color=\"#3b82f6\">изгаряния</font>.</li></ul><h3>Нежелани реакции:</h3><ul><li><strong><font color=\"#dd0a0a\">Алергични реакции</font></strong>, вкл. <strong><font color=\"#dd0a0a\">кръстосана свръхчувствителност</font></strong> (с диуретици, сулфонилурейни).</li><li><b><font color=\"#dd0a0a\">Хематологични </font></b>–<font color=\"#000000\"> <p>мегалобластна анемия, левкопения, тромбоцитопения; хемолиза при </p><p>Г6ФДХ дефицит</p></font></li><li><font color=\"#dd0a0a\">Кристалурия</font>.</li></ul><strong><h3>Взаимодействия:</h3></strong><ul><li>При новородени <strong><font color=\"#dd0a0a\">изместват билирубин</font></strong> – <font color=\"#dd0a0a\">керниктер</font>.</li><li><span style=\"white-space-collapse: preserve;\">С антикоагуланти, сулфонилурейни антидиабетични – изместване от ПП и инхибиция на CYP2C9.</span></li></ul><hr><h2>Оксазолидинони (Linezolid)</h2><h3><p>Спектър - <u>тесен</u>:</p></h3><ul><li><strong><font color=\"#3b82f6\">G+ коки и бактерии</font></strong>, вкл. <font color=\"#3b82f6\"><strong>резистентни</strong> </font>като <strong><font color=\"#3b82f6\"><i><u>MRSA</u></i></font>, <font color=\"#3b82f6\"><i><u>PRSP</u></i></font>, <font color=\"#3b82f6\"><i><u>VRE</u></i></font></strong>.</li><li><font color=\"#3b82f6\">Анаероби</font>.</li><li><font color=\"#3b82f6\"><strong>Бактерициден</strong> </font>за <i><font color=\"#3b82f6\">Streptococci</font></i>.</li></ul><h3>Фармакокинетика:</h3><ul><li><font color=\"#000000\">Орално и венозно приложение.&nbsp;</font></li><li><font color=\"#000000\">Добра резорбция.</font></li><li><font color=\"#000000\">Широко разпределение, <strong>преминава бариери</strong>.</font></li><li><font color=\"#000000\">Метаболизъм чрез неензимно оксидиране.&nbsp;</font></li><li><font color=\"#000000\">Предимно бъбречна екскреция.</font></li></ul><h3>Фармакодинамика:</h3><ul><li>Свързва се с <strong><font color=\"#3b82f6\">50S рибозомната субединица</font></strong>.</li><li>Потиска <strong><font color=\"#3b82f6\">образуването на рибозомния комплекс</font></strong>, даващ началото на белтъчната синтеза.</li></ul><h3><span style=\"font-size: 1.1em;\">Показания:</span></h3><ul><li>Инфекции, причинени от <strong><font color=\"#3b82f6\">мултирезистентни причинители.</font></strong></li><li>Инфекции на <font color=\"#3b82f6\">кожата </font>и <font color=\"#3b82f6\">меките тъкани</font>, <font color=\"#3b82f6\">остеомиелит</font>.</li><li><font color=\"#3b82f6\">Пневмония</font>, <font color=\"#3b82f6\">туберкулоза</font>, <font color=\"#3b82f6\">нокардиоза</font>.</li></ul><h3>Нежелани реакции:</h3><ul><li><font color=\"#dd0a0a\"><strong>Хематологични</strong> </font>– <font color=\"#000000\">a<p>немия, левкопения, тромбоцитопения, </p><p>панцитопения</p></font></li><li><strong><font color=\"#dd0a0a\">Митохондриална токсичност</font></strong> (при продължително приложение) – <font color=\"#dd0a0a\">периферна </font>и <font color=\"#dd0a0a\">оптична невропатия</font>, <font color=\"#dd0a0a\">лактатна ацидоза</font>.</li></ul><h3>Взаимодействия:</h3><ul><li><strong><font color=\"#dd0a0a\">Инхибитор на МАО</font></strong> – риск от <strong><font color=\"#dd0a0a\">серотонинов синдром</font></strong><font color=\"#dd0a0a\"> </font><p>с други </p><p>серотонин-повишаващи л-ва като антидепресанти</p>.</li></ul><hr><h2>Антианаеробни лекарства</h2><h3><table><thead><tr><th>Морфология</th><th>Оцветяване по Gram</th><th>Род</th></tr></thead><tbody><tr><td rowspan=\"2\">Спорообразуващи пръчици</td><td>+</td><td><span style=\"font-weight: normal;\"><i>Clostridium</i></span></td></tr><tr><td>-</td><td><span style=\"font-weight: normal;\"><i>None</i></span></td></tr><tr><td rowspan=\"2\">Неспорообразуващи пръчици</td><td>+</td><td><span style=\"font-weight: normal;\"><i>Actinomyces,<br>Bifidobacterium,<br>Eubacterium,<br>Lactobacillus,<br>Propionibacterium</i></span></td></tr><tr><td>-</td><td><span style=\"font-weight: normal;\"><i>Bacteroides,<br>Fusobacterium</i></span></td></tr><tr><td rowspan=\"2\">Не-спорообразуващи коки</td><td>+</td><td><span style=\"font-weight: normal;\"><i>Peptococcus,<br>Peptosteptococcus,<br>Streptococcus</i></span></td></tr><tr><td>-</td><td><span style=\"font-weight: normal;\"><i>Veilonella</i></span></td></tr></tbody></table></h3><h3>Характеристика на анаеробните бактерии и инфекции</h3><ul><li>Много от анаеробите са п<font color=\"#3b82f6\">редставители на <strong>нормалната флора</strong></font> (с изкл. на живеещи в почвата <i><font color=\"#dd0a0a\">C. tetani</font></i> и <i><font color=\"#dd0a0a\">C. botulinum</font></i>).</li><li><p>Най-честата манифестация са <b><font color=\"#3b82f6\">абсцеси с разнообразна локализация:</font></b></p></li><ul><li><p><b style=\"\"><font color=\"#000000\">Мозък</font></b><font color=\"#dd0a0a\"> </font>- мозъчен абсцес,</p><p>субдурален емпием</p></li><li><p><b style=\"\"><font color=\"#000000\">Бели дробове</font></b> - аспирационна и некротизираща пневмония, белодробен</p><p>абсцес, плеврален емпием</p></li><li><p><b style=\"\"><font color=\"#000000\">Женска полова система</font></b><font color=\"#3b82f6\"> </font>- вулво-вагинален и тубо-овариален абсцес,</p><p>салпингит, ендометрит, септичен аборт</p></li><li><p><font color=\"#000000\"><b>Жлъчни пътища, </b><b style=\"\">коремна кухина</b></font><font color=\"#3b82f6\"> </font>- перитонит, </p><p>апендикуларен и чернодробен абсцес.</p></li><li><p><b style=\"\"><font color=\"#000000\">Инфекции на кожата и меките тъкани</font></b><font color=\"#3b82f6\"> </font>- декубитални</p><p>и варикозни язви, диабетно стъпало, ухапвания, раневи инфекции</p></li></ul><li><strong>Специфични заболявания</strong>: <font color=\"#3b82f6\">тетанус</font>, <font color=\"#3b82f6\">ботулизъм</font>, <strong><font color=\"#3b82f6\">псевдомембранозен колит</font> (<font color=\"#3b82f6\"><i>C. difficile</i></font>)</strong>.</li><li>Обикновено се откриват <font color=\"#000000\"><strong>няколко патогена</strong> </font><p><font color=\"#000000\"> </font>– комбинация от различни облигатни анаероби или </p><p>облигатни с факултативни анаероби.\r\n</p></li><li><strong>Симптоми</strong><p>, налагащи съмнение за анаеробна инфекция <font color=\"#000000\">– секрет с неприятна миризма, наличие на </font></p><p><font color=\"#000000\">газ в тъканите и некротични тъкани.</font></p></li><li><font color=\"#000000\"><p style=\"\">Инфекциите след белодробна аспирация, чревна хирургия, аборт, човешки или животински</p><p style=\"\">ухапвания и при болни от рак често са причинени от анаероби.</p></font></li></ul><h3>Класификация на Антианаеробните Антимикробни Лекарства</h3><ul><li><strong>Бактерицидни:</strong></li><ul><li><strong>Природни:</strong>&nbsp;</li><ul><li><b>Бета-лактами</b>:</li><ul><li><b>Пеницилини</b>:&nbsp;<p><i><font color=\"#7e22ce\">Benzylpenicillin</font>, </i></p><p><i><font color=\"#7e22ce\">Amoxicillin</font>, </i></p><p><i><font color=\"#7e22ce\">Co-Amoxiclav</font>, </i></p><p><i><font color=\"#7e22ce\">Piperacillin </font></i><font color=\"#7e22ce\">+ <i>Tazobactam</i></font></p></li><li><b>Карбапенеми</b>:&nbsp;<p><i><font color=\"#7e22ce\">Imipenem </font></i><font color=\"#7e22ce\">+ <i>Cilastatin</i></font>, </p><p><i><font color=\"#7e22ce\">Meropenem</font></i></p></li><li><b>Гликопептиди</b>:&nbsp;<p><i><font color=\"#7e22ce\">Vancomycin</font></i>, <i><font color=\"#7e22ce\">Teicoplanin</font></i>\r\n</p></li></ul></ul><li><strong>Синтетични:</strong>&nbsp;</li><ul><li><b>Флуорирани хинолони</b>: <i><font color=\"#7e22ce\">Moxifloxacin</font></i></li><li><b>Нитроимидазоли</b>: <i><font color=\"#7e22ce\">Metronidazole</font></i>, <i><font color=\"#7e22ce\">Tinidazole</font></i></li></ul></ul><li><strong>Бактериостатични:</strong></li><ul><li><strong>Природни:</strong>&nbsp;</li><ul><li><b>Амфениколи</b>: <i><font color=\"#7e22ce\">Chloramphenicol</font></i></li><li><b>Линкозамиди</b>: <i><font color=\"#7e22ce\">Clindamycin</font></i>, <i><font color=\"#7e22ce\">Lincomycin</font></i>.</li></ul><li><strong>Синтетични:</strong>&nbsp;</li><ul><li><b>Оксазолидинони:&nbsp;</b><i><font color=\"#7e22ce\">Linezolid</font></i>.</li></ul></ul></ul><hr><h2><font color=\"#7e22ce\"><i>Metronidazole </i></font>(Нитроимидазоли)</h2><strong><h3>Спектър:</h3></strong><ul><li><strong><font color=\"#3b82f6\">Облигатни анаероби</font></strong>, вкл. <strong><i><font color=\"#3b82f6\">B. fragilis</font></i> и <font color=\"#3b82f6\"><i>C. difficile</i></font></strong>.</li><li><font color=\"#3b82f6\">Микроаерофили</font> като <font color=\"#3b82f6\"><i><b>H. pylori</b></i></font> и <font color=\"#3b82f6\"><i>Gardnerella vaginalis</i></font>.</li><li>Първаци като <font color=\"#3b82f6\"><i>T. vaginalis</i></font>, <font color=\"#3b82f6\"><i>Entamoeba</i></font>, <font color=\"#3b82f6\"><i>Giardia lamblia</i></font>.</li><li>Няма активност против аероби.</li></ul><h3>Фармакокинетика:</h3><ul><li><font color=\"#000000\">Орално и венозно приложение.&nbsp;</font></li><li><font color=\"#000000\"><strong>Добра орална резорбция</strong>.</font></li><li><font color=\"#000000\">Широко разпределение, вкл. вътреклетъчно, <strong>висока ЦНС концентрация</strong>.</font></li><li><font color=\"#000000\">Частичен метаболизъм.&nbsp;</font></li><li><font color=\"#000000\">Бъбречна екскреция.&nbsp;</font></li><li><font color=\"#000000\">Полуживот около 8 ч.</font></li></ul><h3>Фармакодинамика:</h3><ul><li><strong>Активира се</strong> в бактериалната клетка посредством неензимна редукция.</li><li>Произвеждат се <strong><font color=\"#3b82f6\">метаболити</font>, <font color=\"#3b82f6\">токсични</font></strong><font color=\"#3b82f6\"> за бактериалната клетка</font>.</li><li>Метаболитите се вграждат в <strong><font color=\"#3b82f6\">бактериалната ДНК</font></strong> и я дестабилизират.</li><li><font color=\"#3b82f6\">Потиска се репликацията</font>.</li></ul><h3>Показания:</h3><ul><li><strong><font color=\"#3b82f6\">Анаеробни инфекции</font></strong> <p> – малкотазово възпаление, интра-абдоминални </p><p>инфекции, мозъчни абсцеси</p></li><li>Язвена болест.</li><li>Инфекции с <strong>едноклетъчни паразити</strong> <p>– трихомоназа, амебиаза, ламблиаза</p></li><li>Профилактика при коремна хирургия.</li><li><i><font color=\"#7e22ce\">Tinidazole </font></i>– <font color=\"#3b82f6\">трихомоназа</font>, <font color=\"#3b82f6\">ламблиаза</font>.</li></ul><strong><h3>Нежелани реакции:</h3></strong><ul><li><b>Стомашно-чревни</b> – <font color=\"#dd0a0a\">гадене</font>, <font color=\"#dd0a0a\">диария</font>, <font color=\"#dd0a0a\">стоматит</font>, <strong><font color=\"#dd0a0a\">метален вкус</font></strong>.</li><li><b>НС</b> – <strong><font color=\"#dd0a0a\">периферна невропатия,&nbsp;</font></strong><p>възможни <font color=\"#dd0a0a\">енцефалопатия</font>, <font color=\"#dd0a0a\">атаксия</font>, <font color=\"#dd0a0a\">гърчове</font></p></li></ul><h3>Взаимодействия:</h3><ul><li><p><font color=\"#dd0a0a\">Дисулфирам реакция с алкохол</font></p></li><li><p><b><font color=\"#dd0a0a\">Инхибитор на CYP2C9</font> </b>(антикоагуланти, сулфонилурейни антидиабетични)</p></li></ul><br><p><script></p><p>renderMathInElement(document.body, {</p><p>  delimiters: [</p><p>    {left: '$$', right: '$$', display: true},</p><p>    {left: '$', right: '$', display: false}</p><p>  ]</p><p>});</p><p></script></p><link rel=\"stylesheet\" href=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/katex.min.css\"><style></p><p>    body { </p><p>      font-family: \"Open Sans\", Arial, sans-serif; </p><p>      max-width: 1550px; </p><p>      margin: 0.5rem auto; </p><p>      padding: 0 1rem; </p><p>      line-height: 1.8; </p><p>      color: #1f2937; </p><p>    }</p><p>    h1, h2, h3, h4 { </p><p>      font-weight: 600; </p><p>      margin-top: 0.8em;</p><p>      margin-bottom: 0.3em;</p><p>      color: #3a5a40;</p><p>    }</p><p>    h1 { font-size: 1.5em; }</p><p>    h2 { font-size: 1.3em; }</p><p>    h3 { font-size: 1.1em; }</p><p>    h4 { font-size: 1.05em; }</p><p>    h3 + h4 { margin-top: 0.3em; }</p><p>    p { </p><p>      margin: 0.7em 0; </p><p>      white-space: pre-wrap;</p><p>    }</p><p>    p + ul, p + ol { margin-top: -0.5em; }</p><p>    h1 + p, h2 + p, h3 + p, h4 + p,</p><p>    h1 + ul, h2 + ul, h3 + ul, h4 + ul,</p><p>    h1 + ol, h2 + ol, h3 + ol, h4 + ol { </p><p>      margin-top: 0.1em; </p><p>    }</p><p>    ul, ol { </p><p>      margin: 0.3em 0; </p><p>      padding-left: 1.5em; </p><p>    }</p><p>    li { margin: 0.15em 0; }</p><p>    ul ul { list-style-type: circle; }</p><p>    ul ul ul { list-style-type: square; }</p><p>    strong { font-weight: 600; }</p><p>    em { font-style: italic; }</p><p>    code { </p><p>      background: rgba(218, 215, 205, 0.3); </p><p>      padding: 2px 6px; </p><p>      border-radius: 3px; </p><p>      font-family: \"Courier New\", monospace; </p><p>      font-size: 0.9em; </p><p>    }</p><p>    pre {</p><p>      background: rgba(255, 255, 255, 0.5);</p><p>      padding: 12px;</p><p>      border-radius: 4px;</p><p>      overflow-x: auto;</p><p>      margin: 0.5em 0;</p><p>      font-family: \"Courier New\", monospace;</p><p>    }</p><p>    pre code {</p><p>      background: none;</p><p>      padding: 0;</p><p>    }</p><p>    blockquote {</p><p>      border-left: 3px solid #a3b18a;</p><p>      padding-left: 1em;</p><p>      margin: 0.5em 0;</p><p>      font-style: italic;</p><p>      color: #3a5a40;</p><p>    }</p><p>    table { </p><p>      border-collapse: collapse; </p><p>      margin: 0.75em 0; </p><p>      width: 100%; </p><p>      table-layout: auto;</p><p>    }</p><p>    th, td { </p><p>      border: 1px solid rgba(146, 64, 14, 0.35); </p><p>      padding: 6px 10px; </p><p>      text-align: left; </p><p>      vertical-align: top;</p><p>      height: 24px;</p><p>      line-height: 1.2;</p><p>    }</p><p>    thead th { </p><p>      background: rgba(196, 127, 9, 0.08); </p><p>      font-weight: 600; </p><p>    }</p><p>    tbody tr:nth-child(odd) { </p><p>      background: rgba(146, 64, 14, 0.03); </p><p>    }</p><p>    img { </p><p>      max-width: 100%; </p><p>      height: auto; </p><p>    }</p><p>    a { </p><p>      color: #a3b18a; </p><p>      text-decoration: underline; </p><p>    }</p><p>    a:hover {</p><p>      color: #d97706;</p><p>    }</p><p>    /<em> Keep <p> tags inside list items on same line (as they appear in editor) </em>/</p><p>    li p {</p><p>      margin: 0 !important;</p><p>      padding: 0 !important;</p><p>      display: inline !important;</p><p>      line-height: 1 !important;</p><p>    }</p><p>    /<em> Prevent nested list paragraph issues </em>/</p><p>    li > ul,</p><p>    li > ol {</p><p>      margin: 0.3em 0 0 0;</p><p>      padding-left: 1.5em;</p><p>    }</p><p>    /<em> Ensure list structure is clean </em>/</p><p>    ul ul, ul ol,</p><p>    ol ul, ol ol {</p><p>      margin-top: 0.2em;</p><p>      padding-left: 1.5em;</p><p>    }</p><p>    @media (max-width: 768px) {</p><p>      body {</p><p>        max-width: 100%;</p><p>        margin: 0.5rem 0;</p><p>        padding: 0 0.5rem;</p><p>        font-size: 16px;</p><p>      }</p><p>      h1 { font-size: 1.3em; }</p><p>      h2 { font-size: 1.1em; }</p><p>      h3 { font-size: 1em; }</p><p>      p { margin: 0.5em 0; }</p><p>      ul, ol { padding-left: 1.2em; }</p><p>      li { margin: 0.1em 0; }</p><p>      table { font-size: 0.9em; }</p><p>      th, td { padding: 4px 6px; }</p><p>    }</p><p>  </style>\r\n<h1 style=\"font-size: 1.5em; color: rgb(124, 45, 18);\"><span style=\"color: rgb(124, 45, 18); font-size: inherit; font-weight: 600;\"></span></h1><h1 style=\"font-size: 1.5em; color: rgb(124, 45, 18);\">Противогъбичкови лекарства. Антитуберкулозни Лекарства. Противовирусни лекарства.</h1><h2 style=\"font-size: 1.3em; color: rgb(124, 45, 18);\">Противогъбичкови лекарства</h2><h3 style=\"font-size: 1.1em; color: rgb(124, 45, 18);\">Патогенни гъбички</h3><table><thead><tr><th style=\"font-size: 1em;\">Вид организъм</th><th style=\"font-size: 1em;\">Организъм</th><th style=\"font-size: 1em;\">Източник</th><th style=\"font-size: 1em;\">Спектър на заболявания</th></tr></thead><tbody><tr><td rowspan=\"2\" style=\"font-size: 1em;\"> <br> Дрожди</td><td style=\"font-size: 1em;\">Candida spp.</td><td style=\"font-size: 1em;\">Коменсал на кожата, ГИТ, вагината.</td><td style=\"font-size: 1em;\">Хематогенно дисеминирани инфекции<br>Мукокутанни инфекции:<br><ul><li style=\"font-size: 1em;\">Орофарингеална инфекция (млечница)</li><li style=\"font-size: 1em;\">Инфекции на кожата и ноктите</li><li style=\"font-size: 1em;\">Вагинит</li></ul></td></tr><tr><td style=\"font-size: 1em;\">Cryptococcus spp.</td><td style=\"font-size: 1em;\">Среща се в почва, замърсена с птичи или гъбълов тор, или върху дървета.<br>Заразяването става чрез вдишване на спори или прах.</td><td style=\"font-size: 1em;\">Пневмония<br>Менингит</td></tr><tr><td rowspan=\"2\" style=\"font-size: 1em;\"> <br> Атипична гъба?</td><td rowspan=\"2\" style=\"font-size: 1em;\">Pneumocystis spp.</td><td rowspan=\"2\" style=\"font-size: 1em;\">Строга хост-специфичност, без външен резервоар</td><td rowspan=\"2\" style=\"font-size: 1em;\">Пневмония</td></tr><tr></tr><tr><td rowspan=\"2\" style=\"font-size: 1em;\"> <br> Диморфни гъби</td><td style=\"font-size: 1em;\">Histoplasma capsulatum</td><td style=\"font-size: 1em;\">Среща се в почва, замърсена с птичи или прилепен гуано.<br>Заразяването става чрез вдишване на спори</td><td style=\"font-size: 1em;\">Самоограничаваш се грипоподобен синдром<br>Остра пневмония<br>Хронична белодробна инфекция<br>Дисемининирана форма</td></tr><tr><td style=\"font-size: 1em;\">Blastomyces dermatitidis</td><td style=\"font-size: 1em;\">Среща се в почва или разлагаща се дървесина.<br>Заразяване чрез вдишване на спори или чрез директно проникване през кожата.</td><td style=\"font-size: 1em;\">Остри/хронични белодробни инфекции<br>Кожни/подкожни лезии<br>Дисеминирана форма</td></tr><tr><td rowspan=\"2\" style=\"font-size: 1em;\"> <br> Плесени</td><td style=\"font-size: 1em;\">Aspergillus spp.</td><td style=\"font-size: 1em;\">Широко разпространена в почва, органични материали, плесенясала храна.</td><td style=\"font-size: 1em;\">Пневмония<br>Алергични реакции<br>Инвазивна аспергилоза при имунокомпрометирани</td></tr><tr><td style=\"font-size: 1em;\">Mucorales</td><td style=\"font-size: 1em;\">Почва, органични отпадъци, растителен материал.</td><td style=\"font-size: 1em;\">Синузит<br>Инвазивна мукормикоза при имунокомпрометирани</td></tr></tbody></table><br><hr><h3 style=\"font-size: 1.1em; color: rgb(124, 45, 18);\"><span style=\"font-size: inherit;\">I. Лекарства, използвани при системни микози</span></h3><p style=\"font-size: 1em;\">1. <b>Антибиотици:</b></p><ul><li style=\"font-size: 1em;\"><i><font color=\"#7e22ce\">Amphotericin B</font></i></li><li style=\"font-size: 1em;\"><i><font color=\"#7e22ce\">Caspofungin</font></i></li></ul>2. <b>Синтетични лекарства:</b><ul><li style=\"font-size: 1em;\"><b>Азоли</b>:</li><ul><li style=\"font-size: 1em;\"><i><font color=\"#7e22ce\"><b>Fluconazole</b></font></i></li><li style=\"font-size: 1em;\"><i><font color=\"#7e22ce\">Ketoconazole</font></i></li><li style=\"font-size: 1em;\"><i><font color=\"#7e22ce\">Itraconazole</font></i></li><li style=\"font-size: 1em;\"><i><font color=\"#7e22ce\">Voriconazole</font></i></li><li style=\"font-size: 1em;\"><i><font color=\"#7e22ce\">Posaconazole (няма в ръководство)</font></i></li></ul><li style=\"font-size: 1em;\"><b>Антиметаболити:</b></li><ul><li style=\"font-size: 1em;\"><i><font color=\"#7e22ce\">Flucytosine</font></i></li></ul></ul><h4 style=\"font-size: 1.05em; color: rgb(124, 45, 18);\"><hr></h4><p style=\"font-size: 1em;\"><b><font color=\"#000000\">Антибиотици - </font><font color=\"#7e22ce\"><i>Amphotericin B</i></font></b></p><ul><li style=\"font-size: 1em;\"><strong><font color=\"#bb431b\">Вид</font></strong>: Амфотерен полиенов антибиотик, системен антимикотик.</li><li style=\"font-size: 1em;\"><strong><font color=\"#bb431b\">Механизъм на действие</font></strong>:</li><ul><li style=\"font-size: 1em;\">Свързва се с <strong>ергостерола</strong> (основен компонент на клетъчната мембрана на гъбите).</li><li style=\"font-size: 1em;\">Образува пори в мембраната, през които изтичат йони и настъпва смърт на клетката.</li></ul><li style=\"font-size: 1em;\"><strong><font color=\"#bb431b\">Фармакокинетика</font></strong>:</li><ul><li style=\"font-size: 1em;\"><font color=\"#000000\"><strong>Абсорбция</strong>: Не се абсорбира перорално, прилага се само чрез <strong>i.v. инфузия</strong>.</font></li><li style=\"font-size: 1em;\"><font color=\"#000000\"><strong>Свързване</strong>: 90% свързан с плазмени и тъканни протеини.</font></li><li style=\"font-size: 1em;\"><font color=\"#000000\"><strong>Разпределение</strong>: Натрупва се в <strong>черен дроб, далак, бъбреци</strong>; слаба проникваемост през <strong>КМБ</strong>.</font></li><li style=\"font-size: 1em;\"><font color=\"#000000\"><strong>Полуживот</strong>: Дълъг (15 дни).</font></li></ul><li style=\"font-size: 1em;\"><strong><font color=\"#bb431b\">Противогъбичков спектър</font></strong>:</li><ul><li style=\"font-size: 1em;\"><strong><font color=\"#3b82f6\">Най-широкият</font></strong>.</li><li style=\"font-size: 1em;\"><strong><font color=\"#3b82f6\">Candida albicans</font></strong><font color=\"#3b82f6\"> </font>+ други <strong>дрожди</strong> (<strong><font color=\"#3b82f6\">Cryptococcus</font></strong>), <strong>плесени</strong> (<strong><font color=\"#3b82f6\">Aspergilus</font></strong>), <strong>ендемични микози</strong> (<strong><font color=\"#3b82f6\">Hystoplasma</font>, <font color=\"#3b82f6\">Blastomyces</font>, <font color=\"#3b82f6\">Coccidioides</font></strong>); <strong><font color=\"#3b82f6\">мукормикоза</font></strong>.</li></ul><li style=\"font-size: 1em;\"><strong><font color=\"#bb431b\">Клинична употреба</font></strong>:</li><ul><li style=\"font-size: 1em;\"><font color=\"#000000\"><b style=\"\">Начална </b>терапия на <strong style=\"\">живото-застрашаващи <u>системни микози</u></strong>.</font></li><li style=\"font-size: 1em;\"><font color=\"#000000\">Инфекции на ГИТ, причинени от Candida.</font></li><li style=\"font-size: 1em;\"><font color=\"#000000\">Орални кандидозни инфекции</font>.</li></ul><li style=\"font-size: 1em;\"><strong><font color=\"#bb431b\">Резистентност</font></strong>: Редуцирано свързване с <strong>ергостерола</strong>.</li><li style=\"font-size: 1em;\"><strong><font color=\"#bb431b\">Нежелани лекарствени реакции (НЛР)</font></strong>:</li><ol><li style=\"font-size: 1em;\"><strong><font color=\"#dd0a0a\">Инфузионна токсичност (незабавна)</font></strong>:&nbsp;</li><ul><li style=\"font-size: 1em;\">Треска, повръщане, главоболие, хипотония, мускулни болки</li><li style=\"font-size: 1em;\"><strong>Флебит</strong> на мястото на приложение.</li></ul><li style=\"font-size: 1em;\"><strong><font color=\"#dd0a0a\">Хронична токсичност (кумулативна)</font></strong>:</li><ul><li style=\"font-size: 1em;\"><font color=\"#dd0a0a\"><strong>Нефротоксичност</strong> (&gt; 80%)</font>.</li><ul><li style=\"font-size: 1em;\"><font color=\"#000000\"><strong style=\"\">Обратим компонент</strong>: намалена бъбречна перфузия.</font></li><li style=\"font-size: 1em;\"><font color=\"#000000\"><strong>Необратим компонент</strong>: ренална тубулна ацидоза.</font></li></ul><li style=\"font-size: 1em;\">Хипокалиемия, хипомагнезиемия.</li><li style=\"font-size: 1em;\">Анемия.</li><li style=\"font-size: 1em;\">Мускулна и миокардна токсичност.</li></ul></ol><ul><li style=\"font-size: 1em;\"><strong style=\"\"><font color=\"#000000\">Възможно решение</font></strong><font color=\"#65a30d\">:</font> <font color=\"#65a30d\"><strong>Липозомна форма</strong> на <strong>Ampho B</strong></font> (<i>значително намалява тези ефекти, но значително по-скъпа</i>).</li></ul></ul><hr><p style=\"font-size: 1em;\"><b><font color=\"#000000\">Антибиотици - </font><u style=\"color: rgb(126, 34, 206);\"><i>Ca</i></u><font color=\"#7e22ce\"><i>spofungin</i> (Ехинокандини)</font></b></p><ul><li style=\"font-size: 1em;\"><strong><font color=\"#3a5a40\">Механизъм на действие</font></strong>: <strong><font color=\"#000000\">Инхибиция на синтезата на бета-глюкан</font></strong> (компонент на клетъчна стена).</li><li style=\"font-size: 1em;\"><strong><font color=\"#3a5a40\">Фармакокинетика</font></strong>:&nbsp;</li><ul><li style=\"font-size: 1em;\"><strong><font color=\"#000000\">i.v. инфузия</font></strong></li><li style=\"font-size: 1em;\"><font color=\"#000000\">Висок % свързване с протеините</font></li><li style=\"font-size: 1em;\"><b>Полуживот</b>:<font color=\"#000000\"> 9-11 часа.</font></li></ul><li style=\"font-size: 1em;\"><strong><font color=\"#3a5a40\">Спектър на действие</font></strong>: C<font color=\"#000000\">-</font><strong><i><font color=\"#3b82f6\">Candida spp</font></i><font color=\"#000000\">.</font></strong><font color=\"#000000\">, A-</font><strong><i><font color=\"#3b82f6\">Aspergillus spp</font></i>. </strong>(<i>първите 2 букви от името</i>)</li></ul><blockquote style=\"font-size: 1em;\"></blockquote><ul><li style=\"font-size: 1em;\"><strong><font color=\"#3a5a40\">Клинична употреба</font></strong>:</li><ul><li style=\"font-size: 1em;\">Усложнени и муко-кутанни кандидозни инфекции (вкл. <strong>Candida auris</strong> инфекция).</li><li style=\"font-size: 1em;\">Емпирична противогъбичкова терапия при фебрилна неутропения.</li><li style=\"font-size: 1em;\">Инвазивна аспергилоза при пациенти неповлияващи се от <i><font color=\"#7e22ce\">Ampho B</font></i>.</li></ul><li style=\"font-size: 1em;\"><strong><font color=\"#3a5a40\">НЛР</font></strong>: Добре поносим, флъш, ГИТ, повишени чернодробни ензими.</li></ul><h4 style=\"font-size: 1.05em; color: rgb(124, 45, 18);\"><font color=\"#000000\"><hr></font></h4><h4 style=\"font-size: 1.05em; color: rgb(124, 45, 18);\"><font color=\"#000000\">Синтетични лекарства - </font><font color=\"#7e22ce\">Системни&nbsp;Азоли</font></h4><ul><li style=\"font-size: 1em;\"><strong><font color=\"#af3a12\">Представители</font></strong>:</li><ul><li style=\"font-size: 1em;\"><strong>Триазоли</strong>: <i style=\"\"><font color=\"#7e22ce\" style=\"\">Fluconazole</font></i>, <i style=\"\"><font color=\"#7e22ce\">Itraconazole</font></i>, <i style=\"\"><font color=\"#7e22ce\">Voriconazole</font></i>.</li><li style=\"font-size: 1em;\"><strong>Имидазоли</strong>: <i style=\"\"><font color=\"#7e22ce\" style=\"\">Ketoconazole</font></i>.</li></ul><li style=\"font-size: 1em;\"><strong><font color=\"#af3a12\">Фармакодинамика</font></strong>:</li><ul><li style=\"font-size: 1em;\">Инхибират ензима <strong>ланостерол 14α-деметилаза</strong>, който участва в синтезата на <strong>ергостерол</strong>.</li><li style=\"font-size: 1em;\"><strong>Триазолите</strong> са по-селективни към гъбичния ензим.</li></ul><li style=\"font-size: 1em;\"><strong><font color=\"#af3a12\">Фармакокинетика</font></strong>:</li><ul><li style=\"font-size: 1em;\"><strong>Орална резорбция</strong> (<strong><font color=\"#7e22ce\"><i>K, I&nbsp;</i></font></strong>- в кисело рН).</li><li style=\"font-size: 1em;\"><strong>Разпределение</strong>:&nbsp;</li><ul><li style=\"font-size: 1em;\">Вагинална течност - <i><font color=\"#7e22ce\">Fluconazole</font></i></li><li style=\"font-size: 1em;\"><i><b>Кожа</b>, <b>нокти </b>- <font color=\"#7e22ce\">Itraconazole</font></i></li><li style=\"font-size: 1em;\">ЦНС&nbsp;- <i><font color=\"#7e22ce\">Fluconazole,&nbsp; Voriconazole</font></i></li></ul><li style=\"font-size: 1em;\"><strong>Метаболизъм</strong>: <strong>Чернодробен</strong> (<strong><font color=\"#3b82f6\">NB! CYP инхибитори</font></strong>).</li><li style=\"font-size: 1em;\"><b>Бъбречна екскреция</b> - <i><font color=\"#7e22ce\">Fluconazole</font></i> (непроменен)</li><li style=\"font-size: 1em;\"><strong>Полуживот</strong>:&nbsp;</li><ul><li style=\"font-size: 1em;\"><i style=\"\"><font color=\"#7e22ce\">K, V</font></i><b> </b>- 6-8 ч.</li><li style=\"font-size: 1em;\"><i><font color=\"#7e22ce\">F, I</font></i><b>&nbsp;</b>- 25-40 ч.</li></ul></ul><li style=\"font-size: 1em;\"><strong><font color=\"#af3a12\">Противогъбичков спектър - широк</font></strong>:</li><ul><li style=\"font-size: 1em;\"><strong><font color=\"#7e22ce\"><i>Fluconazole</i></font></strong>: Candida spp., Cryptococcus neoformans.</li><li style=\"font-size: 1em;\"><p><i><b style=\"\"><font color=\"#7e22ce\">Ketonozole</font></b></i>: Candida spp, Dermatophytes</p></li><li style=\"font-size: 1em;\"><strong><font color=\"#7e22ce\"><i>Itraconazole</i></font></strong>: Диморфни гъби (Histoplasma, Coccidioides, Blastomyces).</li><li style=\"font-size: 1em;\"><strong><font color=\"#7e22ce\"><i>Voriconazole</i></font></strong>: Aspergillus, гъбичков менингит.</li></ul><li style=\"font-size: 1em;\"><strong><font color=\"#af3a12\">Клинична употреба</font></strong>:</li><ul><li style=\"font-size: 1em;\"><strong>Системни микози</strong>:&nbsp;</li><ul><li style=\"font-size: 1em;\"><font color=\"#7e22ce\"><i>F, V</i></font><strong> </strong>- Crypto менингит</li><li style=\"font-size: 1em;\"><font color=\"#7e22ce\"><i>I </i></font>- Blasto-, Cocco-, Histo- микози</li><li style=\"font-size: 1em;\"><i><font color=\"#7e22ce\">V</font></i> - Аспергилоза</li></ul><li style=\"font-size: 1em;\"><strong>Повърхностни микози</strong>:&nbsp;</li><ul><li style=\"font-size: 1em;\"><font color=\"#7e22ce\"><i>F</i></font> - Муко-кутанна кандидоза</li><li style=\"font-size: 1em;\"><font color=\"#7e22ce\"><i>I </i></font>- Онихомикоза.</li></ul></ul><li style=\"font-size: 1em;\"><strong><font color=\"#af3a12\">НЛР</font></strong>:</li><ul><li style=\"font-size: 1em;\">ГИТ, алергия</li><li style=\"font-size: 1em;\"><strong><font color=\"#dd0a0a\">Чернодробни нарушения</font></strong> (<i style=\"\"><font color=\"#7e22ce\">K, I</font></i>).</li><li style=\"font-size: 1em;\">Инхибиране на стероидогенезата (<i><font color=\"#7e22ce\">K</font></i>).</li><li style=\"font-size: 1em;\">Хипокалиемия (<i><font color=\"#7e22ce\">I</font></i>).</li><li style=\"font-size: 1em;\">Зрителни увреждания (<font color=\"#7e22ce\"><i>V</i></font>)</li></ul><li style=\"font-size: 1em;\"><strong><font color=\"#af3a12\">Препоръка</font></strong>: Да се избягва употребата по време на <strong>бременност</strong>.</li><li style=\"font-size: 1em;\"><strong><font color=\"#af3a12\">Лекарствени взаимодействия</font></strong>: <font color=\"#dd0a0a\"><strong>NB! Мощни CYP и Р-др инхибитори</strong> (<strong>№1 - <u>Ketoconazole</u></strong>)</font>.</li></ul><hr><p style=\"font-size: 1em;\"><b>Синтетични лекарства -  Антиметаболити - <font color=\"#7e22ce\"><i>Flucytosine</i></font></b></p><ul><li style=\"font-size: 1em;\"><strong><font color=\"#af3a12\">Фармакокинетика</font></strong>:&nbsp;</li><ul><li style=\"font-size: 1em;\">Орално</li><li style=\"font-size: 1em;\">Високи ЦНС концентрации</li><li style=\"font-size: 1em;\">Кратък полуживот</li></ul><li style=\"font-size: 1em;\"><strong><font color=\"#af3a12\">Фармакодинамика</font></strong>:</li><ul><li style=\"font-size: 1em;\"><p>В гъбичната клетка се </p>превръща (чрез цитозин-деаминаза) в <strong>5-флуороурацил (5-FU)</strong> → инхибира синтеза на <strong>ДНК и РНК</strong>.</li><li style=\"font-size: 1em;\">Човешките клетки нямат <strong>цитозин-деаминаза&nbsp;</strong><p style=\"font-size: 1em;\">→ селективна токсичност.</p></li></ul><li style=\"font-size: 1em;\"><strong><font color=\"#af3a12\">Противогъбичков спектър (<u>ССС</u>) - тесен спектър</font></strong>:</li><ul><li style=\"font-size: 1em;\"><i><font color=\"#3b82f6\">Candida spp</font><font color=\"#dd0a0a\">.</font></i>, <i><font color=\"#3b82f6\">Cryptococcal meningitis</font></i>, <i><font color=\"#3b82f6\">Chromoblastomycosis</font></i>.</li></ul><li style=\"font-size: 1em;\"><strong><font color=\"#af3a12\">НЛР</font></strong>:&nbsp;</li><ul><li style=\"font-size: 1em;\"><b><font color=\"#dd0a0a\">Потискане на костния мозък</font>&nbsp;</b><p style=\"font-size: 1em;\">(активиране от чревната флора)<b>\r\n</b></p></li><li style=\"font-size: 1em;\">ГИТ, алергия</li><li style=\"font-size: 1em;\">Чернодробно увреждане.</li><li style=\"font-size: 1em;\"><p style=\"font-size: 1em;\"><i>(в бързо-делящи се клетки 5-FU е ппц за тумори)</i></p></li></ul><li style=\"font-size: 1em;\"><strong><font color=\"#af3a12\">Комбинации</font></strong>:</li><ul><li style=\"font-size: 1em;\">Никога не се използва самостоятелно (бързо развитие на <strong>резистентност</strong>).</li><li style=\"font-size: 1em;\"><font color=\"#dd0a0a\">В комбинация с </font><i style=\"\"><strong style=\"\"><font color=\"#7e22ce\">Ampho B</font></strong><font color=\"#dd0a0a\">/</font><strong style=\"\"><font color=\"#7e22ce\">Азоли</font></strong></i>.</li></ul></ul><hr><h4 style=\"color: rgb(124, 45, 18);\">II. Лекарства за повърхностни микози</h4>1. <b>Антибиотици:</b><ul><li><i><font color=\"#7e22ce\"><b>Nystatin</b></font></i></li></ul>2.<b> Синтетични лекаства:</b><ul><li><b>а) Азоли</b></li><ul><li><font color=\"#7e22ce\"><i>Ketoconazole</i></font></li><li><font color=\"#7e22ce\"><i><b>Miconazole</b></i></font></li><li><font color=\"#7e22ce\"><i>Clotrimazole</i></font></li><li><font color=\"#7e22ce\"><i>Econazole</i></font></li></ul><li><b>b) Алиламини</b></li><ul><li><font color=\"#7e22ce\"><i>Naftifine</i></font></li><li><font color=\"#7e22ce\"><i>Terbinafine</i></font></li></ul><li><b>c) Други</b></li><ul><li><font color=\"#7e22ce\"><i>Ciclopirox olamine</i></font></li><li><font color=\"#7e22ce\"><i>Amorolfine</i></font></li><li><font color=\"#7e22ce\"><i>Salycylic acid (в ръководство)</i></font></li></ul></ul><br><h3 style=\"color: rgb(124, 45, 18);\"><font color=\"#3a5a40\">1. <span style=\"font-size: 1.05em;\">Антибиотици</span></font></h3><p style=\"font-size: 1em;\"><b><font color=\"#7e22ce\"><i>Nystatin</i></font></b></p><ul><li style=\"font-size: 1em;\"><strong><font color=\"#af3a12\">Вид</font></strong>: Полиенов антибиотик, като <i><font color=\"#7e22ce\">Amphotericin B</font></i></li><li style=\"font-size: 1em;\"><font color=\"#af3a12\"><b>Фармакокинетика:&nbsp;</b></font></li><ul><li style=\"font-size: 1em;\"><p style=\"\"><font color=\"#000000\">Твърде <b style=\"\">токсичен </b>за системна употреба</font></p><font color=\"#000000\"></font></li><li style=\"font-size: 1em;\"><font color=\"#000000\"><p style=\"\">Незначителна резорбция през кожата и</p><p style=\"\">лигавиците – ниска токсичност</p></font></li><li style=\"font-size: 1em;\"><p style=\"\"><font color=\"#000000\">Като </font><i style=\"\"><font color=\"#7e22ce\">Ampho</font></i><font color=\"#000000\"> няма орална бионаличност, но </font></p><p style=\"color: rgb(0, 0, 0);\">действа локално в ГИТ</p></li></ul><li style=\"font-size: 1em;\"><strong><font color=\"#af3a12\">Механизъм на действие</font></strong>: Свързва <strong>стерола</strong> и образува пори в мембраната (като <i><font color=\"#7e22ce\">Ampho B</font></i>)</li><li style=\"font-size: 1em;\"><strong><font color=\"#af3a12\">Спектър</font></strong>: <font color=\"#3b82f6\" style=\"\">Candida albicans</font></li><li style=\"font-size: 1em;\"><strong><font color=\"#af3a12\">Клинична употреба</font></strong>:&nbsp;</li><ul><li style=\"font-size: 1em;\"><font color=\"#3b82f6\">Кожна кандидоза</font></li><li style=\"font-size: 1em;\"><font color=\"#3b82f6\">Вагинална кандидоза</font></li><li style=\"font-size: 1em;\"><font color=\"#3b82f6\">Орална кандидоза (COOP)</font>.</li></ul></ul><h3 style=\"color: rgb(124, 45, 18);\"><font color=\"#3a5a40\">2. Синтетични лекарства</font></h3><p style=\"font-size: 1em;\"><b><font color=\"#7e22ce\">а. Азоли (имидазоли)</font></b></p><ul><li><strong style=\"font-size: 1em;\"><font color=\"#af3a12\">Представители</font></strong><span style=\"font-size: 1em;\">: </span><span style=\"font-size: 1em;\"><i><font color=\"#7e22ce\">Ketoconazole</font></i>, <i><font color=\"#7e22ce\">Miconazole</font></i>, <i><font color=\"#7e22ce\">Clotrimazole</font></i>, <i><font color=\"#7e22ce\">Econazole</font></i></span></li><li style=\"font-size: 1em;\"><strong><font color=\"#af3a12\">Клинична употреба</font></strong>:</li><ul><li style=\"font-size: 1em;\"><b><i><font color=\"#7e22ce\">Clotrimazole</font></i></b>, <b><i><font color=\"#7e22ce\">Econazole</font></i></b>: <font color=\"#3b82f6\">Вагинална кандидоза</font></li><li style=\"font-size: 1em;\"><i><b><font color=\"#7e22ce\">Ketoconazole</font></b></i>: <font color=\"#3b82f6\">Серобеен дерматит, Дерматофитни инфекции</font></li><li style=\"font-size: 1em;\"><b><i><font color=\"#7e22ce\">Miconazole</font></i></b>: <font color=\"#3b82f6\">Coop</font></li></ul></ul><p style=\"font-size: 1em;\"><b><font color=\"#7e22ce\">b. Алиламини</font></b></p><ul><li style=\"font-size: 1em;\"><strong><font color=\"#af3a12\">Представители</font></strong>: <i><font color=\"#7e22ce\">Naftifine </font></i>(<u>локално</u>), <i><font color=\"#7e22ce\">Terbinafine </font></i>(<u>орално и локално</u>).</li><li style=\"font-size: 1em;\"><b style=\"color: rgb(175, 58, 18);\">Фармакокинетика (</b><i style=\"\"><font color=\"#7e22ce\">Terbinafine</font></i><b style=\"color: rgb(175, 58, 18);\">):</b></li><ul><li style=\"font-size: 1em;\"><font color=\"#000000\">Орална резорбция</font></li><li style=\"font-size: 1em;\"><font color=\"#000000\">Разпределение в кожа и нокти (кератофилен)</font></li><li style=\"font-size: 1em;\"><font color=\"#000000\">Полуживот - 17 ч.</font></li></ul><li style=\"font-size: 1em;\"><strong><font color=\"#af3a12\">Фармакодинамика</font></strong>:</li><ul><li style=\"font-size: 1em;\">Инхибират сквален-епоксидазата → блокират синтеза на <strong>ергостерол</strong>.</li><li style=\"font-size: 1em;\">Натрупване на токсичен сквален → разрушаване на клетъчната мембрана.</li><li style=\"font-size: 1em;\"><strong>Фунгицидно действие</strong>.</li></ul><li style=\"font-size: 1em;\"><strong><font color=\"#af3a12\">Противогъбичков спектър</font></strong>:&nbsp;</li><ul><li style=\"font-size: 1em;\">Най-широкият&nbsp;за дерматофити, охиномикози.</li></ul><li style=\"font-size: 1em;\"><strong><font color=\"#af3a12\">Клинична употреба</font></strong>:&nbsp;</li><ul><li style=\"font-size: 1em;\"><font color=\"#3b82f6\">Дерматофитни инфекции, Онихомикози</font>.</li><li style=\"font-size: 1em;\">Орален <strong>Terbinafine</strong> (12 седмици) – 90% успеваемост при <strong>онихомикоза</strong>.</li></ul><li style=\"font-size: 1em;\"><strong><font color=\"#af3a12\">НЛР </font>(<font color=\"#7e22ce\"><i>Terbinafine</i></font>)</strong>:&nbsp;</li><ul><li style=\"font-size: 1em;\">ГИТ</li><li style=\"font-size: 1em;\"><strong>Хепатотоксичност</strong>.</li></ul></ul><p style=\"font-size: 1em;\"><b><font color=\"#7e22ce\">с. Други</font></b></p><ul><li style=\"font-size: 1em;\"><strong><font color=\"#af3a12\">Представители</font></strong>: <i><font color=\"#7e22ce\">Ciclopirox olamine</font></i><strong>, </strong><i><font color=\"#7e22ce\">Amorolfine</font></i> (лакове за нокти), <i><font color=\"#7e22ce\">Salicylic acid</font></i></li><li style=\"font-size: 1em;\"><strong><font color=\"#af3a12\">Спектър</font></strong>: <font color=\"#3b82f6\">Дерматофити</font>,<strong> </strong><font color=\"#3b82f6\">Candida</font>.</li><li style=\"font-size: 1em;\"><strong><font color=\"#af3a12\">Успаваемост:</font></strong></li><ul><li style=\"font-size: 1em;\"><p style=\"\"><b style=\"\"><font color=\"#7e22ce\"><i>Ciclopirox olamine</i></font></b><font color=\"#000000\"> - 5.5 - 8.5%</font></p><b style=\"color: rgb(175, 58, 18);\"></b></li><li style=\"font-size: 1em;\"><p style=\"\"><b style=\"\"><font color=\"#7e22ce\"><i>Amorolfine </i></font></b><font color=\"#000000\">- </font></p><p style=\"\"><font color=\"#000000\">Проучвания през 90-те – 38-46%</font></p></li><ul><li style=\"font-size: 1em;\"><span style=\"font-size: 1em;\">Локална монотерапия</span><span style=\"font-size: 1em;\"> с </span><span style=\"font-size: 1em;\"><i><font color=\"#7e22ce\">Amorolfine</font></i></span><span style=\"font-size: 1em;\"> не е ефективна за постигане на пълно излекуване на </span><span style=\"font-size: 1em;\">онихомикозата</span><span style=\"font-size: 1em;\">.</span></li></ul></ul><li style=\"font-size: 1em;\">Подобрена успеваемост при <strong>комбиниране</strong>&nbsp;- орален <strong><i><font color=\"#7e22ce\">terbinafine</font></i>/<i><font color=\"#7e22ce\">itraconazole</font></i></strong><i><font color=\"#7e22ce\"> </font></i>+ лак (<p><i><font color=\"#7e22ce\"><b>ciclopirox</b></font></i>/<i><font color=\"#7e22ce\"><b>amorolfine</b></font></i>)</p>.</li></ul><h2><hr></h2><h2></h2><h1><hr></h1><h1>Антитуберкулозни лекарства</h1><h3>І. Лекарства от първи ред (First-line drugs)</h3><p>Лекарствата от първи ред формират <strong>основната схема</strong> за лечение на <strong>чувствителната туберкулоза</strong>. Те се характеризират с <strong>висока активност</strong> срещу <em>Mycobacterium tuberculosis</em> и относително <strong>по-нисък профил на токсичност</strong>.</p><h4><i><font color=\"#7e22ce\">Rifampicin</font></i></h4><ul><li><strong>Механизъм на действие</strong>: Има <strong>бактерицидно</strong> действие, като инхибира <strong>ДНК-зависимата РНК полимераза</strong> на в прокариотните клетки (вкл. в микобактериите), но не в еукариотните.</li><li><strong>Ключови ефекти и особености</strong>:</li><ul><li>Изключително важен компонент в лечението на <strong>туберкулоза</strong>.</li><li>Мощен <strong><font color=\"#dd0a0a\">индуктор на чернодробните ензими</font></strong> (CYP450), което налага внимателно проследяване при комбиниране с други лекарства (напр. орални контрацептиви, антикоагуланти, антиретровирусни лекарства).</li></ul><li><strong>Нежелани лекарствени реакции (НЛР)</strong>:</li><ul><li><strong><font color=\"#dd0a0a\">Хепатотоксичност</font></strong>.</li><li><strong><font color=\"#dd0a0a\">Оранжево-червено оцветяване</font></strong> на телесните течности (урина, сълзи, пот), което е безобидно, но трябва да се информира пациентът.</li></ul></ul><h4><i><font color=\"#7e22ce\">Isoniazid</font></i></h4><ul><li><strong>Механизъм на действие</strong>: Притежава силно <strong>бактерицидно</strong> действие, като специфично инхибира синтеза на<b> <font color=\"#dd0a0a\">миколова киселина</font></b> – жизненоважен компонент за изграждането на клетъчната стена на микобактериите.</li><li><strong>Ключови ефекти и особености</strong>:</li><ul><li>Метаболизира се чрез <font color=\"#dd0a0a\"><strong>ацетилиране</strong>&nbsp;</font>от <b><font color=\"#dd0a0a\">N-ацетилтрансфераза 2</font></b> в черния дроб, като активността на NAT2 е <b><font color=\"#dd0a0a\">генетично полиморфна</font></b>, което означава, че хората могат да бъдат класифицирани като:</li><ul><li><p><b>Бързи ацетилатори </b>(метаболизират лекарството бързо).</p></li><li><p><b>Бавни ацетилатори</b> (метаболизират лекарството бавно, което води до по-високи и по-продължителни плазмени концентрации).</p></li></ul><li>За да се предотврати най-честата НЛР, се прилага едновременно с <font color=\"#dd0a0a\"><strong>пиридоксин</strong> </font>(<strong>витамин В6</strong>).</li></ul><li><strong>Нежелани лекарствени реакции (НЛР)</strong>:</li><ul><li><strong><font color=\"#dd0a0a\"><u>Периферна невропатия</u></font></strong> (поради антагонизъм с <strong>пиридоксина</strong>).</li><li><strong><font color=\"#dd0a0a\">Хепатотоксичност</font></strong>.</li></ul></ul><h4><i><font color=\"#7e22ce\">Ethambutol</font></i></h4><ul><li><strong>Механизъм на действие</strong>: Има предимно <strong>бактериостатично</strong> действие. Инхибира синтеза на арабиногалактан – ключов полимер в клетъчната стена.</li><li><strong>Ключови ефекти и особености</strong>:</li><ul><li>Основната му роля е да <strong><font color=\"#dd0a0a\">предотвратява развитието на резистентност</font></strong> към другите лекарства в схемата.</li></ul><li><strong>Нежелани лекарствени реакции (НЛР)</strong>:</li><ul><li><font color=\"#dd0a0a\"><strong>Очен неврит</strong> </font>(<strong><font color=\"#dd0a0a\"><u>ретробулбарен неврит</u></font></strong>), който може да доведе до <strong>нарушено цветоусещане</strong> (невъзможност за разграничаване на зелено и червено) и намалена зрителна острота. Този ефект е дозозависим и е обратим при ранно спиране.</li><li><font color=\"#65a30d\">Запомни E - eye</font></li></ul></ul><h4><i><font color=\"#7e22ce\">Pyrazinamide</font></i></h4><ul><li><strong>Механизъм на действие</strong>: Има <strong>бактерицидно</strong> действие, но е най-активен в <strong>кисела среда</strong>. Това го прави изключително ефективен срещу <strong>нерепликиращи се микобактерии</strong>, разположени вътре в <strong>макрофагите</strong> и в <strong>казеозната тъкан</strong> на туберкулозните лезии.</li><li><strong>Ключови ефекти и особености</strong>:</li><ul><li>Необходим е за <strong>съкращаване на общата продължителност</strong> на лечението (използва се в интензивната фаза).</li></ul><li><strong>Нежелани лекарствени реакции (НЛР)</strong>:</li><ul><li><strong><font color=\"#dd0a0a\">Хепатотоксичност</font></strong>.</li><li><strong><font color=\"#dd0a0a\"><u>Хиперурикемия</u></font>,</strong>&nbsp;която може да провокира пристъпи на <font color=\"#dd0a0a\"><strong>подагра</strong> </font>или <strong><font color=\"#dd0a0a\">артралгия</font></strong>.</li></ul></ul><hr><h3>ІІ. Лекарства от втори ред (Second-line drugs)</h3><p>Тези лекарства се използват главно за лечение на <strong>резистентна туберкулоза</strong>, или когато лекарствата от първи ред са <strong>противопоказани</strong> или се наблюдават <strong>тежки нежелани реакции</strong>. Те са по-малко ефективни и/или имат <strong>по-висок риск от токсичност</strong>.</p><h4><i><font color=\"#7e22ce\">Streptomycin</font></i></h4><ul><li><strong>Група</strong>: Аминогликозиден антибиотик.</li><li><strong>Механизъм на действие</strong>: <strong>Бактерицидно</strong> действие, <font color=\"#dd0a0a\">инхибира <strong>синтеза на протеини</strong></font> чрез свързване с 30S субединицата на рибозомата.</li><li><strong>Приложение</strong>: Прилага се <b>парентерално </b>(инжекционно).</li><li><strong>Нежелани лекарствени реакции (НЛР)</strong>:</li><ul><li><font color=\"#dd0a0a\"><strong>Ототоксичност</strong></font>.</li><li><strong><font color=\"#dd0a0a\">Нефротоксичност</font></strong>.</li></ul></ul><h4><i><font color=\"#7e22ce\">Clarithromycin</font></i></h4><ul><li><strong>Група</strong>: Макролиден антибиотик.</li><li><strong>Механизъм на действие</strong>: <strong>Бактериостатично</strong>, инхибира <strong>протеиновия синтез</strong> чрез свързване с 50S субединицата на рибозомата.</li><li><strong>Ключови ефекти и особености</strong>:</li><ul><li>Основно се използва за лечение на инфекции, причинени от <strong>нетипични микобактерии</strong> (напр. <em>Mycobacterium avium complex - MAC</em>), особено при пациенти с <strong><font color=\"#dd0a0a\">HIV/СПИН</font></strong>.</li><li>Рядко се включва в схемите за лечение на <em>Mycobacterium tuberculosis</em>.</li></ul></ul><h4><i><font color=\"#7e22ce\">Флуорирани хинолони</font></i>&nbsp;</h4><ul><li><strong>Представители</strong>: <strong><i><font color=\"#7e22ce\">Levofloxacin</font></i></strong>, <strong><i><font color=\"#7e22ce\">Moxifloxacin</font></i></strong>.</li><li><strong>Механизъм на действие</strong>: <strong>Бактерицидно</strong> действие, инхибират ключови бактериални ензими – <strong>ДНК-гираза</strong> и <strong>топоизомераза IV</strong>, които са необходими за репликацията, транскрипцията и възстановяването на ДНК.</li><li><strong>Ключови ефекти и особености</strong>:</li><ul><li>Те са <strong>критични лекарства</strong> при лечението на <strong><font color=\"#dd0a0a\">мултирезистентна туберкулоза</font> (MDR-TB)</strong>.</li></ul><li><strong>Нежелани лекарствени реакции (НЛР)</strong>:</li><ul><li><strong><font color=\"#dd0a0a\">СЧ нарушения</font></strong>.</li><li><font color=\"#dd0a0a\"><strong>Продължаване на QT интервала</strong> </font>(риск от аритмии).</li><li>Рядко: <strong><font color=\"#dd0a0a\">увреждане</font></strong> и <strong><font color=\"#dd0a0a\">руптура на сухожилията</font></strong> (напр. Ахилесовото сухожилие).</li></ul></ul><hr><hr><h1 style=\"font-size: 1.5em; color: rgb(124, 45, 18);\">Противовирусни лекарства</h1><h3 style=\"font-size: 1.1em; color: rgb(124, 45, 18);\">Общи принципи на действие</h3><ul><li style=\"font-size: 1em;\">Вируси – облигатни вътреклетъчни паразити.</li><li style=\"font-size: 1em;\">Много противовирусни лекарства използват <b>Антиметаболитния принцип</b> (<b>Нуклеозидни аналози</b>).</li><ul><li style=\"font-size: 1em;\"><strong><font color=\"#af3a12\">Механизъм</font></strong>: Вирус-специфична киназа ги превръща до активен <strong>трифосфат</strong> → инкорпориране във вирусната <strong>ДНК</strong> → инхибиране на вирусната <strong>ДНК полимераза</strong> → инхибиране на <strong>ДНК синтеза</strong>.</li></ul></ul><h3 style=\"font-size: 1.1em; color: rgb(124, 45, 18);\">I. Лекарства при Herpes simplex virus и Varicella zoster virus инфекции</h3><ul><li style=\"font-size: 1em;\"><strong><font color=\"#af3a12\">Представители</font></strong>: <i style=\"\"><font color=\"#7e22ce\" style=\"\"><b>Aciclovir</b></font></i>, <font color=\"#7e22ce\" style=\"\"><i>Valaciclovir</i></font>.</li><li style=\"font-size: 1em;\"><strong><font color=\"#af3a12\">Фармакокинетика</font></strong>:</li><ul><li style=\"font-size: 1em;\"><strong>Орална бионаличност</strong>: <font color=\"#3b82f6\"><strong>Ниска</strong> </font>(<i style=\"\"><font color=\"#7e22ce\">Aciclovir</font></i>) и <font color=\"#3b82f6\"><strong>Висока</strong> </font>(<i style=\"\"><font color=\"#7e22ce\">Valaciclovir</font></i><i><font color=\"#7e22ce\" style=\"\">&nbsp;</font></i>- prodrug).</li><li style=\"font-size: 1em;\">Широко разпределение вкл. ЦНС.</li><li style=\"font-size: 1em;\"><p>Бъбречна екскреция</p></li><li style=\"font-size: 1em;\"><p>Кратък t ½ - 5 пъти дневно</p></li></ul><li style=\"font-size: 1em;\"><strong><font color=\"#af3a12\">Фармакодинамика</font></strong>:</li><ul><li style=\"font-size: 1em;\"><strong>Антиметаболити</strong>, активирани от вирусната <strong>herpes thymidine kinase</strong> (само в инфектирани клетки).</li><li style=\"font-size: 1em;\">Инхибират вирусната <strong>ДНК-полимераза</strong> и прекъсват <strong>ДНК веригата</strong>.</li></ul><li style=\"font-size: 1em;\"><strong><font color=\"#af3a12\">Клинична </font>употреба</strong>:</li><li style=\"font-size: 1em;\"><p><i><font color=\"#65a30d\">Скъсява продължителността на симптомите на вирусното разпространение и заздравяване на лезиите</font></i></p></li><ul><li style=\"font-size: 1em;\"><strong>Herpes simplex virus (HSV)</strong>:&nbsp;</li><ul><li style=\"font-size: 1em;\">Генитален и лабиален херпес (локално, орално)</li><li style=\"font-size: 1em;\">Херпесен енцефалит (i.v.)</li><li style=\"font-size: 1em;\">Очни херпесни инфекции (локално, орално)</li><li style=\"font-size: 1em;\">Превенция през бременността</li></ul><li style=\"font-size: 1em;\"><strong>Varicella zoster virus (VZV)</strong>:&nbsp;</li><ul><li style=\"font-size: 1em;\">Изисква по-високи дози</li><li style=\"font-size: 1em;\"><strong>Варицела</strong> (до 24 ч. от началото на обрива)</li><li style=\"font-size: 1em;\"><strong>Кожен зостер</strong> (до 72 ч.)</li></ul></ul><li style=\"font-size: 1em;\"><strong><font color=\"#af3a12\">НЛР</font></strong>:&nbsp;</li><ul><li style=\"font-size: 1em;\">Добре поносими</li><li style=\"font-size: 1em;\">Чести - гадене, главоболие.</li><li style=\"font-size: 1em;\"><p>Редки (iv)- тремор, гърчове, </p><p>обратима неутропения и </p><p>бъбречна токсичност (<font color=\"#7e22ce\"><i style=\"\">Aciclovir</i></font>)</p></li></ul></ul><h3 style=\"font-size: 1.1em; color: rgb(124, 45, 18);\"><hr></h3><h3 style=\"font-size: 1.1em; color: rgb(124, 45, 18);\">II. Противогрипни лекарства</h3><h4 style=\"font-size: 1.05em; color: rgb(124, 45, 18);\">1. Инхибитори на вирусното събличане</h4><ul><li style=\"font-size: 1em;\"><strong><font color=\"#af3a12\">Представители</font></strong>: <i><font color=\"#7e22ce\">Amantadine</font></i><strong>, </strong><i><font color=\"#7e22ce\">Rimantadine</font></i>.</li><li style=\"font-size: 1em;\"><strong><font color=\"#af3a12\">Фармакодинамика</font></strong>:</li><ul><li style=\"font-size: 1em;\">Инхибират М2 протеина на <strong>Influenza A</strong> вируса → блокира <strong>събличането</strong> на вирусната <strong>РНК</strong>.</li></ul><li style=\"font-size: 1em;\"><strong><font color=\"#af3a12\">Клинична употреба</font></strong>:&nbsp;</li><ul><li style=\"font-size: 1em;\"><p><i><font color=\"#7e22ce\">Rimantadine</font><font color=\"#dd0a0a\"> </font></i>се понася по-добре и има по-висока активност (<font color=\"#dd0a0a\">R &gt;&gt; A</font>)</p></li><li style=\"font-size: 1em;\">Профилактика и начално лечение при <strong>грип тип А</strong>.</li><li style=\"font-size: 1em;\"><p><b><font color=\"#dd0a0a\">NB! Само при инфлуенца тип A</font></b></p></li><li style=\"font-size: 1em;\"><p><font color=\"#dd0a0a\"><b>Висока степен на резистентност</b></font></p></li></ul><li style=\"font-size: 1em;\"><strong><font color=\"#af3a12\">НЛР</font></strong>:&nbsp;</li><ul><li style=\"font-size: 1em;\">Гадене, нарушения на съня (<font color=\"#7e22ce\" style=\"font-size: 1em;\"><i>Amantadine</i></font><span style=\"font-size: 1em;\">)</span></li><li style=\"font-size: 1em;\"><strong style=\"font-size: 1em;\">Тератогенен</strong><span style=\"font-size: 1em;\">.</span></li></ul></ul><h4 style=\"font-size: 1.05em; color: rgb(124, 45, 18);\">2. Невраминидазни инхибитори</h4><ul><li style=\"font-size: 1em;\"><strong><font color=\"#af3a12\">Представители</font></strong>: <i style=\"\"><font color=\"#7e22ce\">Oseltamivir</font></i><b>, </b><i><font color=\"#7e22ce\">Zanamivir</font></i>.</li><li style=\"font-size: 1em;\"><p style=\"color: rgb(175, 58, 18); font-weight: bold;\">Фармакокинетика: </p><p style=\"\"><font color=\"#000000\">Орално (</font><i style=\"\"><font color=\"#7e22ce\">O</font></i><font color=\"#000000\">) или инхалационно (</font><i style=\"\"><font color=\"#7e22ce\">Z</font></i><font color=\"#000000\">)</font></p></li><li style=\"font-size: 1em;\"><strong><font color=\"#af3a12\">Фармакодинамика</font></strong>: Инхибират вирусния ензим <strong>невраминидаза</strong> → предотвратяват освобождаването на новообразуваните вирусни частици.</li><li style=\"font-size: 1em;\"><strong><font color=\"#af3a12\">Клинична употреба</font></strong>:&nbsp;</li><ul><li style=\"font-size: 1em;\"><font color=\"#dd0a0a\">Действа срещу <strong>Influenza A</strong> и <strong>B</strong></font>.&nbsp;</li><li style=\"font-size: 1em;\">Превенция и начална терапия.</li></ul><li style=\"font-size: 1em;\"><strong><font color=\"#af3a12\">НЛР</font></strong>:&nbsp;</li><ul><li style=\"font-size: 1em;\"><i><font color=\"#7e22ce\">Oseltamivir</font></i>&nbsp;- ГИТ, кожни обриви</li><li style=\"font-size: 1em;\"><i><font color=\"#7e22ce\">Zanamivir</font></i>&nbsp;-&nbsp;бронхоспазъм, кашлица</li></ul></ul><h3 style=\"font-size: 1.1em; color: rgb(124, 45, 18);\"><hr></h3><h3 style=\"font-size: 1.1em; color: rgb(124, 45, 18);\">III. Антиретровирусни лекарства (за HIV/СПИН)</h3><h4 style=\"font-size: 1.05em;\"><span style=\"color: rgb(124, 45, 18);\">Жизнен цикъл на HIV и места на действие на АРВЛ </span><font color=\"#65a30d\">(бонус)</font></h4><ol><li><b>Навлизане в клетката (CD4⁺ Т-лимфоцит):</b></li></ol><ul><li>Вирусът се прикрепя чрез <b>gp120</b> към <b>CD4 </b>рецептора и ко-рецепторите CCR5/CXCR4, след което слива мембраните.</li><li><b>Фузионни инхибитори</b>: <font color=\"#7e22ce\"><i>Enfuvirtide</i></font>, <font color=\"#7e22ce\"><i>Maraviroc</i></font></li></ul><b>2. Обратна транскрипция</b><ul><li>Вирусната РНК се превръща в ДНК чрез ензима <b>обратната транскриптаза</b>.</li><li><b>Нуклеозидни инхибитори (NRTIs)</b>: <i><font color=\"#7e22ce\">Zidovudine</font></i>, <i><font color=\"#7e22ce\">Lamivudine</font></i></li><ul><li><b>За превенция на здарви индивиди</b>:&nbsp;&nbsp;<i><font color=\"#7e22ce\">Emtricitabine +</font></i>&nbsp;<i><font color=\"#7e22ce\">Tenofovir = Truvada</font></i></li></ul><li><b>Ненуклеозидни инхибитори (NNRTIs)</b>: <i><font color=\"#7e22ce\">Efavirenz</font></i>, <i><font color=\"#7e22ce\">Nevirapine</font></i></li></ul><b>3. Интеграция в клетъчния геном</b><ul><li>Вирусната ДНК се вгражда в човешката чрез ензима <b>интеграза</b>.</li><li><b>Интегразни инхибитори</b>: <i><font color=\"#7e22ce\">Raltegravir</font></i>, <i><font color=\"#7e22ce\">Dolutegravir</font></i></li></ul><b>4. Транскрипция и транслация:</b><ul><li><p> Клетката произвежда вирусни белтъци и ензими</p></li></ul><b>5. Сглобяване и узряване:</b><br><ul><li><b>Протеазата </b><p>разцепва вирусните полипротеини -&gt; оформя се зрял вирус.</p></li><li><p><b>Протеазни инхибитори</b>: <i><font color=\"#7e22ce\">Ritonavir</font></i>, <i><font color=\"#7e22ce\">Indinavir</font></i>, <i><font color=\"#7e22ce\">Lopinavir</font></i>, <i><font color=\"#7e22ce\">Atazanavir</font></i></p></li></ul><br><h4>Курс на HIV инфекцията / СПИН <font color=\"#65a30d\">(бонус)</font></h4><ol><li><b>Остра HIV инфекция (първичен стадий):</b></li><ul><li>Настъпва 2–4 седмици след заразяване. </li><li>Проявява се с грипоподобни симптоми (треска, лимфаденопатия, фарингит). </li><li>Висока вирусна репликация и спад на CD4⁺ клетките.</li></ul></ol><b>2. Латентен (хроничен) стадий:</b><ul><li>Вирусът персистира в лимфните тъкани.</li><li>CD4⁺ клетките постепенно намаляват. </li><li>Пациентът може да е безсимптомен години наред.</li></ul><b>3. Симптоматичен стадий / СПИН:</b><ul><li>Тежък имунен дефицит (CD4⁺ &lt;200/µL). </li><li>Появяват се опортюнистични инфекции (Pneumocystis jirovecii, Candida, CMV) и неоплазии (сарком на Kaposi, лимфоми).</li></ul><h4 style=\"font-size: 1.05em; color: rgb(124, 45, 18);\"><br></h4><h4 style=\"font-size: 1.05em; color: rgb(124, 45, 18);\">1. Инхибитори на обратната транскриптаза</h4><p style=\"font-size: 1em;\"><b>а) Нуклеозидни лекарства (NRTIs)</b></p><ul><li style=\"font-size: 1em;\"><strong><font color=\"#af3a12\">Представители</font></strong>: <i><font color=\"#7e22ce\">Zidovudine, Lamivudine,&nbsp;</font></i></li><ul><li style=\"font-size: 1em;\"><p style=\"\"><font color=\"#000000\" style=\"\"><b>За превенция на здрави индивиди</b>:</font><font color=\"#7e22ce\" style=\"font-style: italic;\"> </font></p><font color=\"#7e22ce\" style=\"font-style: italic;\">Emtricitabine + Tenfovir = Truvada</font></li></ul><li style=\"font-size: 1em;\"><strong><font color=\"#af3a12\">Механизъм</font></strong>:&nbsp;</li><ul><li style=\"font-size: 1em;\"><strong>Антиметаболити</strong>, които&nbsp;<p>след фосфорилиране от клетъчни кинази се вграждат във вирусната ДНК и</p> блокират <strong>обратната транскриптаза</strong>.</li></ul><li style=\"font-size: 1em;\"><strong><font color=\"#af3a12\">Клинична употреба</font></strong>:&nbsp;</li><ul><li style=\"font-size: 1em;\"><p>Основна част в антиретровирусната терапия (<b>АРТ</b>) - обикновено <b>двойна комбинация</b> (напр. <i><font color=\"#7e22ce\">T + E</font></i>)</p></li><li style=\"font-size: 1em;\"><p>При бременни със СПИН (<i><font color=\"#7e22ce\">T, L, E//Z</font></i>)</p></li><li style=\"font-size: 1em;\"><p>За лечение на хепатит B (<font color=\"#7e22ce\"><i>T, <b><u>Lamivudine</u></b>, E</i></font>) (<font color=\"#65a30d\">не знам защо Lamivudine не го дават при хепатит B частта, но се пада на теста</font>)</p></li><li style=\"font-size: 1em;\"><p><font color=\"#65a30d\">Пре-експозиционна профилактика (PrEP) - </font><i style=\"\"><font color=\"#7e22ce\">Truvada </font></i><font color=\"#65a30d\">(</font><font color=\"#7e22ce\"><i>Tenofovir </i></font><font color=\"#65a30d\">+ </font><font color=\"#7e22ce\"><i>Emtricitabine</i></font><font color=\"#65a30d\">)</font></p></li></ul><li style=\"font-size: 1em;\"><strong><font color=\"#af3a12\">Нежелани ефекти</font></strong>:&nbsp;</li><ul><li style=\"font-size: 1em;\">ГИТ</li><li style=\"font-size: 1em;\">Потискане на костния мозък (<i><font color=\"#7e22ce\">Zidovudine</font></i>)</li><li style=\"font-size: 1em;\">Миопатия (<i><font color=\"#7e22ce\">Zidovudine</font></i>)</li><li style=\"font-size: 1em;\">Нефротоксичност (<i><font color=\"#7e22ce\">Tenofovir</font></i>)</li><li style=\"font-size: 1em;\">Митохондриална токсичност&nbsp;- панкреатит, лактоцидоза</li></ul></ul><p style=\"font-size: 1em;\"><b>б) Не-нуклеозидни лекарства (NNRTIs)</b></p><ul><li style=\"font-size: 1em;\"><strong><font color=\"#af3a12\">Представители</font></strong>: <i><font color=\"#7e22ce\">Efavirenz, Nevirapine</font></i>.</li><li style=\"font-size: 1em;\"><font color=\"#af3a12\"><b>Фармакокинетика:</b></font></li><ul><li style=\"font-size: 1em;\"><font color=\"#000000\" style=\"\"><p style=\"\">Орално</p></font></li><li style=\"font-size: 1em;\"><font color=\"#000000\"><p style=\"\">Проникват в ЦНС</p></font></li><li style=\"font-size: 1em;\"><font color=\"#000000\"><span style=\"white-space-collapse: preserve;\">CYP3A4 <p>метаболизъм</p></span></font></li><li style=\"font-size: 1em;\"><font color=\"#000000\"><span style=\"white-space-collapse: preserve;\"><p style=\"\">Дълъг t½: еднократно дневно</p><b></b></span></font></li></ul><li style=\"font-size: 1em;\"><strong><font color=\"#af3a12\">Механизъм</font></strong>: Свързват се <strong>директно</strong> с <strong>обратната транскриптаза</strong> (без фосфорилиране).</li><li style=\"font-size: 1em;\"><strong><font color=\"#af3a12\">Клинична употреба</font></strong>: Компонент на комбинирана <strong>АРТ</strong> терапия <p> – <b><font color=\"#dd0a0a\">NNRTI + два NRTIs</font>.</b></p></li><li style=\"font-size: 1em;\"><strong><font color=\"#af3a12\">Нежелани ефекти</font></strong>:&nbsp;</li><ul><li style=\"font-size: 1em;\">Кожни обриви (вкл. Stevens-Johnson синдром)</li><li style=\"font-size: 1em;\">Чернодробни увреждания, панкреатит, дислипидемия</li><li style=\"font-size: 1em;\"><p>ЦНС – депресия, тревожност, проблеми със съня (<i><font color=\"#7e22ce\">E</font></i>)</p></li></ul><li style=\"font-size: 1em;\"><strong><font color=\"#af3a12\">Лекарствени взаимодействия</font></strong>:&nbsp;</li><ul><li style=\"font-size: 1em;\"><font color=\"#dd0a0a\"><strong></strong><p> CYP - индуктори </p></font></li></ul></ul><br><h4 style=\"font-size: 1.05em; color: rgb(124, 45, 18);\">2. Протеазни инхибитори (PIs)</h4><ul><li style=\"font-size: 1em;\"><strong><font color=\"#af3a12\">Представители</font></strong>: <i style=\"\"><font color=\"#7e22ce\" style=\"\"><b>Ritonavir</b>, <b>Indinavir&nbsp;</b></font></i></li><ul><li style=\"font-size: 1em;\"><font color=\"#000000\"><b>Усилени представители на ПИ (Boosted PIs)</b>:</font></li><ul><li style=\"font-size: 1em;\"><p style=\"\"><font color=\"#000000\">С</font><i style=\"\"><font color=\"#000000\"> </font><font color=\"#7e22ce\">ritonavir</font><font color=\"#000000\">, </font></i><font color=\"#000000\">напр<i style=\"\">. </i></font><i style=\"color: rgb(126, 34, 206);\"><b>lopinavir </b></i><i style=\"\"><font color=\"#000000\">(</font></i><i style=\"color: rgb(126, 34, 206);\">Kaletra</i><i style=\"\"><font color=\"#000000\">)</font></i></p></li><li style=\"font-size: 1em;\"><p style=\"\"><font color=\"#000000\">С</font><i style=\"color: rgb(126, 34, 206);\"> cobicistat</i><i style=\"\"><font color=\"#000000\">,</font></i><i style=\"color: rgb(126, 34, 206);\"> </i><font color=\"#000000\">напр.</font><i style=\"color: rgb(126, 34, 206);\"> <b>atazanavir </b></i><i style=\"\"><font color=\"#000000\">(</font></i><i style=\"color: rgb(126, 34, 206);\">Evotaz</i><i style=\"\"><font color=\"#000000\">)</font></i></p></li></ul></ul><li style=\"font-size: 1em;\"><strong><font color=\"#af3a12\">Фармакокинетика:</font></strong></li><ul><li style=\"font-size: 1em;\"><font color=\"#000000\"><p style=\"\">Орално</p></font></li><li style=\"font-size: 1em;\"><font color=\"#000000\"><p style=\"\">Проникват в ЦНС</p></font></li><li style=\"font-size: 1em;\"><font color=\"#000000\"><p style=\"\">CYP3A4 метаболизъм</p></font></li><li style=\"font-size: 1em;\"><p style=\"\"><font color=\"#dd0a0a\">NB! CYP 3A4 инхибиране</font></p></li><ul><li style=\"font-size: 1em;\"><p style=\"\"><font color=\"#dd0a0a\">“Boosting” ефект</font><font color=\"#000000\">: </font><i style=\"\"><font color=\"#7e22ce\">Ritonavir </font></i><font color=\"#000000\">и </font><i style=\"\"><font color=\"#7e22ce\">Cobicistat </font></i><font color=\"#000000\">са мощни инхибитори на CYP3A4. Те се комбинират с </font></p><p style=\"\"><i style=\"\"><font color=\"#7e22ce\">Atazanavir</font></i><font color=\"#000000\"> или </font><i style=\"\"><font color=\"#7e22ce\">Lopinavir</font></i><font color=\"#000000\">, за да усилят техния ефект (↑t½,</font><font color=\"#000000\"> редуцира се дозата)</font></p></li></ul></ul><li style=\"font-size: 1em;\"><strong><font color=\"#af3a12\">Механизъм</font></strong>: Инхибират вирусната <strong>протеаза</strong> → вирусите остават <strong>незрели и неинфекциозни</strong>.</li><li style=\"font-size: 1em;\"><strong><font color=\"#af3a12\">Клинична употреба</font></strong>:</li><ul><li style=\"font-size: 1em;\">Компонент на комбинирана <strong>АРТ</strong> терапия -&nbsp;<p><b><font color=\"#dd0a0a\">два NRTIs + усилен протеазен инхибитор</font></b>.</p></li><li style=\"font-size: 1em;\"><strong></strong><p>При бременни със СПИН (<b><i><font color=\"#7e22ce\">A,D</font></i></b>)</p></li></ul><li style=\"font-size: 1em;\"><strong><font color=\"#af3a12\">НЛР</font></strong>:&nbsp;</li><ul><li style=\"font-size: 1em;\">Метаболитни - дислипидемия, хиперглицемия, липодистрофия</li><li style=\"font-size: 1em;\">Хепатотоксичност</li><li style=\"font-size: 1em;\">ГИТ</li><li style=\"font-size: 1em;\">Нарушения в сърдечната проводимост</li><li style=\"font-size: 1em;\">Кожни обриви</li></ul></ul><br><h4 style=\"font-size: 1.05em; color: rgb(124, 45, 18);\">3. Интегразни инхибитори (INSTIs)</h4><ul><li style=\"font-size: 1em;\"><strong><font color=\"#af3a12\">Представители</font></strong>: <i><font color=\"#7e22ce\">Dolutegravir</font>, <font color=\"#7e22ce\">Elvitegravir</font>, <font color=\"#7e22ce\">Raltegravir</font></i>.</li><li style=\"font-size: 1em;\"><strong><font color=\"#af3a12\">Фармакокинетика:</font></strong></li><ul><li style=\"font-size: 1em;\"><font color=\"#000000\">Орално</font></li><li style=\"font-size: 1em;\"><font color=\"#000000\">Чернодробен метаболизъм</font></li></ul><li style=\"font-size: 1em;\"><strong><font color=\"#af3a12\">Механизъм</font></strong>: Инхибират вирусната <strong>интеграза</strong> → блокира се репликацията на <strong>HIV</strong>.</li><li style=\"font-size: 1em;\"><strong><font color=\"#af3a12\">Клинична употреба</font></strong>:&nbsp;</li><ul><li style=\"font-size: 1em;\">Първа линия АРТ<p style=\"\">: <b><font color=\"#dd0a0a\">INSTI + два NRTIs</font></b></p></li><li style=\"font-size: 1em;\">Пост-експозиционна профилактика</li><li style=\"font-size: 1em;\"><p style=\"\">При бременни със СПИН (<font color=\"#7e22ce\" style=\"\"><i>D, R</i></font>)</p></li></ul><li style=\"font-size: 1em;\"><strong><font color=\"#af3a12\">НЛР</font></strong>:&nbsp;</li><ul><li style=\"font-size: 1em;\">Свръхчувствителност</li><li style=\"font-size: 1em;\">ГИТ</li><li style=\"font-size: 1em;\">Хипергликемия</li></ul></ul><h4>4. Фузионни инхибитори</h4><ul><li><strong><font color=\"#c1441a\">Представители</font></strong>: <em></em><p><i><font color=\"#7e22ce\">Enfuvirtide</font></i>, </p><p><i><font color=\"#7e22ce\">Maraviroc</font></i></p></li><li><strong><font color=\"#c1441a\">Фармакокинетика</font>:</strong></li><ul><li><p style=\"\"><i><font color=\"#7e22ce\">Enfuvirtide </font></i>– подкожно приложение</p></li><li><p style=\"\"><i><font color=\"#7e22ce\">Maraviroc </font></i>– орално; метаболизира се от CYP3A4.</p></li></ul><li><strong><font color=\"#c1441a\">Механизъм</font></strong>:&nbsp;</li><ul><li><p><i><font color=\"#7e22ce\">Enfuvirtide </font></i>– свързва <font color=\"#3b82f6\">gp41</font> и инхибира прикрепването и проникването на вируса</p></li><li><p><i><font color=\"#7e22ce\">Maraviroc </font></i>– свързва <font color=\"#3b82f6\">CCR5 ко-рецептора</font> на гостоприемника и инхибира HIV проникването</p></li></ul><li><strong><font color=\"#c1441a\">Клинична употреба</font></strong>:</li><ul><li><p><i><font color=\"#7e22ce\">Enfuvirtide</font></i>: използва се при резистентни HIV щамове.</p></li><li><p><i><font color=\"#7e22ce\">Maraviroc</font></i>: активен срещу CCR5-тропни вируси.</p></li></ul><li><strong><font color=\"#c1441a\">НЛР</font></strong>:</li><ul><li><p><i><font color=\"#7e22ce\">Enfuvirtide </font></i>- локална болка, безсъние, главоболие.</p></li><li><p><i><font color=\"#7e22ce\">Maraviroc </font></i>- кашлица, хепатотоксичност.</p></li></ul></ul><span style=\"white-space-collapse: preserve;\"><br></span><h4 style=\"white-space-collapse: preserve;\">5. Фиксирани комбинации - примери:</h4><ul style=\"white-space-collapse: preserve;\"><li><p><font color=\"#7e22ce\"><i>Elvitegravir</i></font>, <i><font color=\"#7e22ce\">cobicistat</font></i>, <i><font color=\"#7e22ce\">emtricitabine </font></i>and <i><font color=\"#7e22ce\">tenofovir alafenamide </font></i>(Genvoya)</p></li></ul><span style=\"white-space-collapse: preserve;\"><br></span><h4><span style=\"white-space-collapse: preserve;\">Принципи на HIV терапията:</span></h4><ul><li><span style=\"white-space-collapse: preserve;\"><p>Основната цел е да се намали вирусното натоварване до недетектируеми нива</p></span></li><li><span style=\"white-space-collapse: preserve;\"><p>Лечението трябва да започне максимално бързо след диагнозата</p></span></li><li><span style=\"white-space-collapse: preserve;\"><p>Терапията е доживотна</p></span></li><li><span style=\"white-space-collapse: preserve;\"><p>За избягване на резистентност се използва комбинация от лекарства (два NRTIs +….)</p></span></li></ul><hr><h3 style=\"font-size: 1.1em; color: rgb(124, 45, 18);\">IV. Лекарства за хепатит В</h3><ul><li style=\"font-size: 1em;\"><strong>Нуклеозидни аналози</strong>: <i style=\"\"><font color=\"#7e22ce\" style=\"\">Entecavir</font></i><b>, </b><i style=\"\"><font color=\"#7e22ce\" style=\"\">Tenofovir, Lamivudine</font></i>.</li><ul><li style=\"font-size: 1em;\"><strong><font color=\"#af3a12\">Фармакокинетика:</font></strong></li><ul><li style=\"font-size: 1em;\"><font color=\"#000000\">Орално</font></li><li style=\"font-size: 1em;\"><font color=\"#000000\">Еднократно дневно</font></li></ul><li style=\"font-size: 1em;\"><strong><font color=\"#af3a12\">Фармакодинамика</font></strong>:&nbsp;</li><ul><li style=\"font-size: 1em;\"><p>„Троянски кон“ – след фосфорилиране в клетката инхибират </p><p>вирусната <b>ДНК полимераза</b>, като се вграждат във вирусната ДНК </p><p>и прекъсват синтеза ѝ.</p></li></ul><li style=\"font-size: 1em;\"><p><b><font color=\"#c1441a\">Клинична употреба</font></b>:</p></li><ul><li style=\"font-size: 1em;\"><p><font color=\"#3b82f6\">Първа линия за лечение на хепатит B</font></p></li><li style=\"font-size: 1em;\"><span style=\"white-space-collapse: preserve;\"><i><font color=\"#7e22ce\">Tenofovir </font></i>при бременност</span></li></ul><li style=\"font-size: 1em;\"><strong><font color=\"#af3a12\">НЛР</font></strong>:&nbsp;</li><ul><li style=\"font-size: 1em;\">ГИТ</li><li style=\"font-size: 1em;\"><p>Нефротоксичност (<i><font color=\"#7e22ce\">Tenofovir</font></i>)</p></li><li style=\"font-size: 1em;\">Лактатна ацидоза</li></ul></ul><li><b>Интерферони</b>: <i><font color=\"#7e22ce\">inferferon alfa-2a, peginterferon alfa 2-a</font></i></li><ul><li><b><font color=\"#c1441a\">Фармакокинетика</font>:</b></li><ul><li>s.c, i.v</li><li><p style=\"\">Пегилиране → удължен полуживот и по-рядко дозиране</p></li></ul><li><b><font color=\"#c1441a\">Фармакодинамика</font>:</b></li><ul><li><p style=\"\">Индуцират антивирусни вътреклетъчни сигнали </p><p style=\"\">последвано от инхибиция на вирусния цикъл.</p></li><li><p style=\"\"><font color=\"#3b82f6\">Имуномодулиращ ефект</font> – стимулират фагоцитната </p><p style=\"\">активност на макрофагите и оцеляването на </p><p style=\"\">цитотоксичните Т-клетки.</p></li></ul><li><b><font color=\"#c1441a\">Клинична употреба:</font></b></li><ul><li><font color=\"#3b82f6\">Втора линия за лечение на хепатит B</font></li></ul><li><b><font color=\"#c1441a\">НЛР</font>:</b></li><ul><li><p style=\"\"><b>Ранни </b>– грипо-подобен синдром</p></li><li><p style=\"\"><b>Късни </b>– невротоксичност, миелосупресия, индукция на авто-антитела</p></li></ul></ul></ul><h3 style=\"font-size: 1.1em; color: rgb(124, 45, 18);\"><hr></h3><h3 style=\"font-size: 1.1em; color: rgb(124, 45, 18);\">VI. Лекарства при хепатит С</h3><ul><li style=\"font-size: 1em;\"><b>Конвенциална терапия:&nbsp;</b><p style=\"\"><font color=\"#7e22ce\" style=\"\"><i style=\"\">Ribavirin + peginterferon alpha</i></font><b>.</b></p></li><ul><li style=\"font-size: 1em;\"><strong>Антиметаболити</strong>: <i><font color=\"#7e22ce\">Ribavirin</font></i>.</li><ul><li style=\"font-size: 1em;\"><font color=\"#af3a12\"><b>Фармакокинетика:</b></font></li><ul><li style=\"font-size: 1em;\"><font color=\"#000000\">Орално</font></li><li style=\"font-size: 1em;\"><font color=\"#000000\" style=\"\">ЦНС</font></li><li style=\"font-size: 1em;\"><font color=\"#000000\" style=\"\">Бавна екскреция</font></li></ul><li><font color=\"#af3a12\" style=\"font-weight: bold;\">Фармакодинамика:</font><font color=\"#000000\" style=\"\"> аналог на нуклеозиди</font></li><li><font color=\"#af3a12\"><b>НЛР:</b></font></li><ul><li><font color=\"#000000\">Хемолитична анемия</font></li><li><font color=\"#000000\">Тератогенен</font></li></ul></ul></ul></ul><font color=\"#000000\"><br></font><ul><li style=\"font-size: 1em;\"><strong>Ново! - </strong><b><p>Директно действащи анти-HCV лекарства срещу специфични не-структурни (NS) вирусни</p><p>протеини </p></b></li><ul><li style=\"font-size: 1em;\"><strong>Протеазни (NS3/4A) инхибитори</strong> (<strong>-previrs</strong>): <i style=\"\"><font color=\"#7e22ce\">Glecaprevir</font></i><b>, </b><i style=\"\"><font color=\"#7e22ce\">Simeprevir</font></i></li><li style=\"font-size: 1em;\"><strong>Инхибитори на РНК-полимеразата (NS5B)</strong> (<strong>-buvirs</strong>): <i><font color=\"#7e22ce\">Sofosbuvir</font></i><strong> </strong>(нуклеозиден), <i><font color=\"#7e22ce\">Dasabuvir</font></i><strong> </strong>(не-нуклеозиден)</li><li style=\"font-size: 1em;\"><strong>Неструктурни протеини NS5A инхибитори</strong> (<strong>-tasvirs</strong>): <i><font color=\"#7e22ce\">Pibrentasvir, Velpatasvir</font></i>.</li><li style=\"font-size: 1em;\"><strong><p><font color=\"#923111\">Пангенотипни комбинации (примери)</font></p></strong>:&nbsp;</li><ul><li style=\"font-size: 1em;\"><i><font color=\"#7e22ce\"><p>Glecaprevir + Pibrentasvir = Mavyrеt, </p><p>Sofosbuvir + Velpatasvir = Epclusa</p></font></i></li></ul><li style=\"font-size: 1em;\"><p><b><font color=\"#923111\">Клинична употреба</font></b>: </p><p>Фиксирани комбинации от 2-3 лекарства с</p><p>различен механизъм на действие</p>\r\n<strong></strong></li><li style=\"font-size: 1em;\"><p><b><font color=\"#923111\">Предимства на новите лекарства</font></b>:</p></li><ul><li style=\"font-size: 1em;\"><p><b><font color=\"#65a30d\">95-100%!!!</font> </b>успеваемост</p></li><li style=\"font-size: 1em;\"><p>8-12 седмици на терапия</p></li><li style=\"font-size: 1em;\"><p>По-добра поносимост</p></li></ul><li><span style=\"white-space-collapse: preserve;\"><b><font color=\"#923111\">Недостатъци</font></b>:</span></li><ul><li><span style=\"white-space-collapse: preserve;\"><p>Скъпи – 50К-100К $ за курс</p></span></li><li><span style=\"white-space-collapse: preserve;\"><p>Генотип-зависими</p></span></li></ul></ul></ul><div><span style=\"font-size: inherit; white-space-collapse: preserve;\"><br></span></div><p style=\"font-size: 1em;\"><script></p><p>renderMathInElement(document.body, {</p><p>  delimiters: [</p><p>    {left: '$$', right: '$$', display: true},</p><p>    {left: '$', right: '$', display: false}</p><p>  ]</p><p>});</p><p></script></p><style></p><p>    body { </p><p>      font-family: \"Open Sans\", Arial, sans-serif; </p><p>      max-width: 1550px; </p><p>      margin: 0.5rem auto; </p><p>      padding: 0 1rem; </p><p>      line-height: 1.8; </p><p>      color: #1f2937; </p><p>    }</p><p>    h1, h2, h3, h4 { </p><p>      font-weight: 600; </p><p>      margin-top: 0.8em;</p><p>      margin-bottom: 0.3em;</p><p>      color: #3a5a40;</p><p>    }</p><p>    h1 { font-size: 1.5em; }</p><p>    h2 { font-size: 1.3em; }</p><p>    h3 { font-size: 1.1em; }</p><p>    h4 { font-size: 1.05em; }</p><p>    h3 + h4 { margin-top: 0.3em; }</p><p>    p { </p><p>      margin: 0.7em 0; </p><p>      white-space: pre-wrap;</p><p>    }</p><p>    p + ul, p + ol { margin-top: -0.5em; }</p><p>    h1 + p, h2 + p, h3 + p, h4 + p,</p><p>    h1 + ul, h2 + ul, h3 + ul, h4 + ul,</p><p>    h1 + ol, h2 + ol, h3 + ol, h4 + ol { </p><p>      margin-top: 0.1em; </p><p>    }</p><p>    ul, ol { </p><p>      margin: 0.3em 0; </p><p>      padding-left: 1.5em; </p><p>    }</p><p>    li { margin: 0.15em 0; }</p><p>    ul ul { list-style-type: circle; }</p><p>    ul ul ul { list-style-type: square; }</p><p>    strong { font-weight: 600; }</p><p>    em { font-style: italic; }</p><p>    code { </p><p>      background: rgba(218, 215, 205, 0.3); </p><p>      padding: 2px 6px; </p><p>      border-radius: 3px; </p><p>      font-family: \"Courier New\", monospace; </p><p>      font-size: 0.9em; </p><p>    }</p><p>    pre {</p><p>      background: rgba(255, 255, 255, 0.5);</p><p>      padding: 12px;</p><p>      border-radius: 4px;</p><p>      overflow-x: auto;</p><p>      margin: 0.5em 0;</p><p>      font-family: \"Courier New\", monospace;</p><p>    }</p><p>    pre code {</p><p>      background: none;</p><p>      padding: 0;</p><p>    }</p><p>    blockquote {</p><p>      border-left: 3px solid #a3b18a;</p><p>      padding-left: 1em;</p><p>      margin: 0.5em 0;</p><p>      font-style: italic;</p><p>      color: #3a5a40;</p><p>    }</p><p>    table { </p><p>      border-collapse: collapse; </p><p>      margin: 0.75em 0; </p><p>      width: 100%; </p><p>      table-layout: auto;</p><p>    }</p><p>    th, td { </p><p>      border: 1px solid rgba(146, 64, 14, 0.35); </p><p>      padding: 6px 10px; </p><p>      text-align: left; </p><p>      vertical-align: top;</p><p>      height: 24px;</p><p>      line-height: 1.2;</p><p>    }</p><p>    thead th { </p><p>      background: rgba(196, 127, 9, 0.08); </p><p>      font-weight: 600; </p><p>    }</p><p>    tbody tr:nth-child(odd) { </p><p>      background: rgba(146, 64, 14, 0.03); </p><p>    }</p><p>    img { </p><p>      max-width: 100%; </p><p>      height: auto; </p><p>    }</p><p>    a { </p><p>      color: #a3b18a; </p><p>      text-decoration: underline; </p><p>    }</p><p>    a:hover {</p><p>      color: #d97706;</p><p>    }</p><p>    /<em> Keep <p> tags inside list items on same line (as they appear in editor) </em>/</p><p>    li p {</p><p>      margin: 0 !important;</p><p>      padding: 0 !important;</p><p>      display: inline !important;</p><p>      line-height: 1 !important;</p><p>    }</p><p>    /<em> Prevent nested list paragraph issues </em>/</p><p>    li > ul,</p><p>    li > ol {</p><p>      margin: 0.3em 0 0 0;</p><p>      padding-left: 1.5em;</p><p>    }</p><p>    /<em> Ensure list structure is clean </em>/</p><p>    ul ul, ul ol,</p><p>    ol ul, ol ol {</p><p>      margin-top: 0.2em;</p><p>      padding-left: 1.5em;</p><p>    }</p><p>    @media (max-width: 768px) {</p><p>      body {</p><p>        max-width: 100%;</p><p>        margin: 0.5rem 0;</p><p>        padding: 0 0.5rem;</p><p>        font-size: 16px;</p><p>      }</p><p>      h1 { font-size: 1.3em; }</p><p>      h2 { font-size: 1.1em; }</p><p>      h3 { font-size: 1em; }</p><p>      p { margin: 0.5em 0; }</p><p>      ul, ol { padding-left: 1.2em; }</p><p>      li { margin: 0.1em 0; }</p><p>      table { font-size: 0.9em; }</p><p>      th, td { padding: 4px 6px; }</p><p>    }</p><p>  </style>\r\n<h1 style=\"font-size: 1.5em;\">Лекарства, повлияващи хипоталамуса и хипофизата</h1><p style=\"font-size: 1em;\">Доц. д-р <strong>Силвия Ганчева</strong>, д.м.</p><h3 style=\"font-size: 1.1em;\"><span style=\"font-size: 1.1em;\">Хипоталамус и хипофиза</span></h3><h4 style=\"font-size: 1.05em;\">Хипоталамус:</h4><ul><li style=\"font-size: 1em;\">Част от <strong>лимбичната система</strong>.</li><li style=\"font-size: 1em;\">Разположен под таламуса и над хипофизата.</li><li style=\"font-size: 1em;\">Въвлечен в регулацията на множество функции, вкл. телесна температура, глад, жажда, циркаден ритъм.</li><li style=\"font-size: 1em;\">Осъществява връзката между <strong>нервната</strong> и <strong>ендокринната система</strong> посредством <strong>хипофизата</strong>.</li></ul><h4 style=\"font-size: 1.05em;\">Хипофиза:</h4><ul><li style=\"font-size: 1em;\"><strong>Ендокринна жлеза</strong>.</li><li style=\"font-size: 1em;\">Разположена в основата на мозъка в турското седло.</li><li style=\"font-size: 1em;\">Състои се от две части:</li><ul><li style=\"font-size: 1em;\"><strong>Предна хипофиза</strong> (<strong>аденохипофиза</strong>).</li><li style=\"font-size: 1em;\"><strong>Задна хипофиза</strong> (<strong>неврохипофиза</strong>).</li></ul><li style=\"font-size: 1em;\">„Диригентът\" на ендокринната система&nbsp;- регулира функцията на периферните ендокринни жлези.</li></ul><h4 style=\"font-size: 1.05em;\">Връзка между Хипоталамуса и Хипофизата:</h4><ul><li style=\"font-size: 1em;\">Нервни влакна, пренасящи хормони, синтезирани в хипоталамуса, които се съхраняват и освобождават от задната хипофиза.</li><li style=\"font-size: 1em;\">Кръвоносни съдове (портална венозна система), пренасящи малки регулаторни молекули (хормони) от хипоталамуса към предната хипофиза.</li></ul><h4 style=\"font-size: 1.05em;\">Аденохипофиза</h4><ul><li style=\"font-size: 1em;\">Хормоните на предната хипофиза са <strong>пептидни молекули</strong>.</li><li style=\"font-size: 1em;\">Физиологичната роля на повечето от тях е да стимулират функцията на периферните ендокринни жлези.</li><li style=\"font-size: 1em;\">Секрецията на всеки хормон се регулира от един или повече хипоталамични фактори (хормони).</li></ul><h4 style=\"font-size: 1.05em;\">Регулация чрез отрицателна обратна връзка:</h4><ul><li style=\"font-size: 1em;\">Освобождаването на хормоните на предната хипофиза и на съответните регулаторни хипоталамични фактори се регулира чрез отрицателна обратна връзка.</li><li style=\"font-size: 1em;\">Периферният хормон потиска освобождаването на съответния и <strong>хипофизен</strong>, и <strong>хипоталамичен хормон</strong>.</li><li style=\"font-size: 1em;\">Хипофизният хормон потиска освобождаването на съответния <strong>хипоталамичен фактор</strong>.</li></ul><h4 style=\"font-size: 1.05em;\">Взаимодействие на Хипоталамични и Хипофизни Хормони:</h4><table><tbody><tr><td style=\"font-size: 1em;\"><b>Хипоталамичен фактор</b></td><td style=\"font-size: 1em;\"><b>Хипофизен хормон</b></td><td style=\"font-size: 1em;\"><b>Таргетен орган</b></td></tr><tr><td style=\"font-size: 1em;\">GHRH (+) / Соматостатин (-)</td><td style=\"font-size: 1em;\">Растежен хормон (GH)</td><td style=\"font-size: 1em;\">Кости, мускули, черен дроб</td></tr><tr><td style=\"font-size: 1em;\">Тиреотропин-рилийзинг хормон (TRH) (+)</td><td style=\"font-size: 1em;\">Тиреоид-стимулиращ хормон (TSH)</td><td style=\"font-size: 1em;\">Щитовидна жлеза</td></tr><tr><td style=\"font-size: 1em;\">Кортикотропин-рилийзинг хормон (CRH) (+)</td><td style=\"font-size: 1em;\">Адренокортикотропен хормон (ACTH)</td><td style=\"font-size: 1em;\">Кора на надбъбречната жлеза</td></tr><tr><td style=\"font-size: 1em;\">Гонадотропин-рилийзинг хормон (GnRH) (+)</td><td style=\"font-size: 1em;\">Фоликуло-стимулиращ хормон (FSH) / Лутеинизиращ хормон (LH)</td><td style=\"font-size: 1em;\">Полови жлези</td></tr><tr><td style=\"font-size: 1em;\">Допамин (-)</td><td style=\"font-size: 1em;\">Пролактин</td><td style=\"font-size: 1em;\">Млечна жлеза</td></tr></tbody></table><h3 style=\"font-size: 1.1em;\"><hr></h3><h3 style=\"font-size: 1.1em;\">Растежен хормон (соматотропин)</h3><ul><li style=\"font-size: 1em;\">По време на детството е необходим за достигане на крайния ръст.</li><li style=\"font-size: 1em;\">При възрастни участва в регулацията на липидния и въглехидратния метаболизъм и костната маса.</li><li style=\"font-size: 1em;\">Секрецията му следва специфичен <strong>циркаден ритъм</strong>, като пикът на освобождаването е през <strong>нощта</strong> (по време на дълбоката фаза на съня).</li><li style=\"font-size: 1em;\">Ефектите са както <strong>директни</strong>, така и <strong>индиректни</strong> чрез отделяне на <strong>инсулино-подобен растежен фактор-1</strong> (<strong>insulin-like growth factor-1, IGF-1</strong>) основно от <strong>черния дроб</strong>.</li><li style=\"font-size: 1em;\">Рецепторите на <strong>растежния хормон</strong> и на <strong>IGF-1</strong> принадлежат към фамилията на <strong><u>ензим-свързаните рецептори</u></strong>.</li><li style=\"font-size: 1em;\"><p style=\"font-size: 1em;\">Освобождаването на растежния хормон се регулира от хипоталамични фактори:</p></li></ul><ul><ul><li style=\"font-size: 1em;\">Growth hormone releasing hormone (GHRH) – стимулатор.</li><li style=\"font-size: 1em;\">Соматостатин – инхибитор.</li></ul></ul><ul><li style=\"font-size: 1em;\"><strong>Дефицитът</strong> на растежен хормон:</li><ul><li style=\"font-size: 1em;\">При деца води до <strong>питуитарен (хипофизарен) нанизъм</strong>.</li><li style=\"font-size: 1em;\">При възрастни се свързва с нарушения на <strong>енергийния метаболизъм</strong> със <strong>затлъстяване</strong>, намаляване на <strong>мускулната маса</strong> и <strong>костната минерална плътност</strong>, <strong>астения</strong>, <strong>дислипидемия</strong>.</li></ul><li style=\"font-size: 1em;\"><strong>Излишъкът</strong> на растежен хормон (при <strong>аденоми на хипофизата</strong>):</li><ul><li style=\"font-size: 1em;\">При деца води до <strong>гигантизъм</strong>.</li><li style=\"font-size: 1em;\">При възрастни води до <strong>акромегалия</strong>.</li></ul></ul><h3 style=\"font-size: 1.1em;\"><hr></h3><h3 style=\"font-size: 1.1em;\"><font color=\"#7e22ce\">Somatropin </font>(Агонист на Растежния хормон)</h3><ul><li style=\"font-size: 1em;\"><strong>Somatropin</strong> е <strong>пептидно лекарство</strong>, получава се чрез <strong>рекомбинантна ДНК технология</strong> и е със структура, идентична на ендогенния човешки растежен хормон.</li></ul><h4 style=\"font-size: 1.05em;\">Фармакокинетика:</h4><ul><li style=\"font-size: 1em;\"><strong>Подкожно инжектиране</strong> (поради пептидната си природа, не може перорално).</li><li style=\"font-size: 1em;\">Кратък плазмен полуживот =&gt; <strong>ежедневно приложение</strong>.</li><li style=\"font-size: 1em;\">Налични са лекарствени форми с <strong>продължително действие</strong> (<strong>депо препарати</strong>) за подкожно приложение веднъж или два пъти месечно.</li></ul><h4 style=\"font-size: 1.05em;\">Механизъм на действие:</h4><ul><li style=\"font-size: 1em;\">Идентично действие с това на ендогенния <strong>растежен хормон</strong>.</li><li style=\"font-size: 1em;\">Somatropin се свързва и активира рецепторите на растежния хормон.</li><li style=\"font-size: 1em;\">Една молекула Somatropin активира и двата рецептора в двойката.</li><li style=\"font-size: 1em;\"><b>Димеризацията </b>на рецепторите води до активирането на <b>вътреклетъчни сигнални</b> <b>пътища&nbsp;</b></li></ul><h4 style=\"font-size: 1.05em;\">Ефекти:</h4><ul><li style=\"font-size: 1em;\">Повишена синтеза на <strong>IGF-1</strong> основно в <strong>черния дроб</strong>, но също и в <strong>костите</strong>, <strong>хрущялната тъкан</strong>, <strong>скелетната мускулатура</strong>.</li><li style=\"font-size: 1em;\">При деца се стимулира растежа на <strong>дългите кости</strong> (до сливането на <strong>епифизеалните плочки</strong>).</li><li style=\"font-size: 1em;\"><strong>Анаболен ефект</strong> в <strong>скелетните мускули</strong> =&gt; увеличаване на <strong>мускулната маса</strong>.</li><li style=\"font-size: 1em;\"><strong>Катаболен ефект</strong> в <strong>мастната тъкан</strong> =&gt; намаляване на <strong>затлъстяването</strong>.</li></ul><h4 style=\"font-size: 1.05em;\">Ефекти върху инсулиновата чувствителност:</h4><ul><li style=\"font-size: 1em;\"><strong>Растежният хормон</strong> намалява <strong>инсулиновата чувствителност</strong> и може да доведе до <strong><font color=\"#dd0a0a\">хипергликемия</font></strong>.</li><li style=\"font-size: 1em;\"><strong>IGF-1</strong> има <strong>инсулино-подобни ефекти</strong> и може да доведе до <strong><font color=\"#dd0a0a\">хипогликемия</font></strong>.</li></ul><h4 style=\"font-size: 1.05em;\">Клинично приложение:</h4><ul><li style=\"font-size: 1em;\"><strong>Заместителна терапия</strong> при деца с <strong><font color=\"#dd0a0a\">питуитарен нанизъм</font></strong><font color=\"#dd0a0a\"> </font>(ако терапията започне в ранна възраст, децата достигат генетично детерменирания им краен ръст).</li><li style=\"font-size: 1em;\">Стимулиране на растежа при деца с нисък ръст, който <strong>не се дължи на дефицит на растежен хормон</strong> (клиничният ефект е по-слаб).</li><li style=\"font-size: 1em;\">Заболявания, свързани с генерализирани и тежки <strong>катаболитни състояния</strong> (напр. <strong>кахексия</strong> при пациенти със <strong>СПИН</strong>).</li><li style=\"font-size: 1em;\">Злоупотреба от спортисти за повишаване на мускулната маса и намаляване на мастната тъкан (<strong>допинг</strong>; забранен за употреба от антидопинговите организации).</li></ul><h4 style=\"font-size: 1.05em;\">Нежелани лекарствени реакции:</h4><ul><li style=\"font-size: 1em;\">Малко нежелани ефекти и добра поносимост при деца с <strong>питуитарен нанизъм</strong>.</li><li style=\"font-size: 1em;\">При възрастни нежеланите ефекти са значително по-чести.</li><li style=\"font-size: 1em;\"><strong><font color=\"#dd0a0a\">Псевдотумор церебри</font></strong><font color=\"#dd0a0a\"> </font>(симптоми на повишено <strong>вътречерепно налягане</strong>).</li><li style=\"font-size: 1em;\"><strong><font color=\"#dd0a0a\">Гинекомастия</font></strong>, <strong><font color=\"#dd0a0a\">панкреатит</font></strong>, <strong><font color=\"#dd0a0a\">хипергликемия</font></strong>, нарастване на <strong><font color=\"#dd0a0a\">пигментни невуси</font></strong>.</li><li style=\"font-size: 1em;\">Теоретично се очаква повишаване на риска от <strong>злокачествени заболявания</strong> =&gt; противопоказан е при пациенти с известно <strong>активно малигнено заболяване</strong>.</li></ul><h3 style=\"font-size: 1.1em;\"><hr></h3><h3 style=\"font-size: 1.1em;\">Антагонисти на растежния хормон</h3><ul><li style=\"font-size: 1em;\">Използват се за подобряване на симптомите при излишък на <strong>растежен хормон</strong> при пациенти с <strong>акромегалия</strong> и <strong>гигантизъм</strong>.</li></ul><h4 style=\"font-size: 1.05em;\"><font color=\"#7e22ce\">Соматостатин</font></h4><ul><li style=\"font-size: 1em;\"><strong>Пептид</strong>, който се произвежда в <strong>хипоталамуса</strong> и <strong>ендокринния панкреас</strong>.</li><li style=\"font-size: 1em;\">В хипофизата потиска освобождаването на растежен хормон и TSH.</li><li style=\"font-size: 1em;\">В <strong>ГИТ</strong> потиска освобождаването на глюкагон, инсулин и локални хормони (гастрин, VIP и др.), както и секрецията на солна киселина и панкреатични ензими.</li><li style=\"font-size: 1em;\">Има много <strong>кратък плазмен полуживот</strong> (1-3 мин) =&gt; не е подходящ за лечение на хронични заболявания.</li></ul><h4 style=\"font-size: 1.05em;\"><font color=\"#7e22ce\">Octreotide</font></h4><ul><li style=\"font-size: 1em;\"><strong>По-мощен аналог</strong> на <strong>соматостатина</strong>.</li><li style=\"font-size: 1em;\">Оказва <strong>по-силен потискащ ефект</strong> върху секрецията на <strong>растежен хормон</strong>, отколкото върху тази на <strong>инсулин</strong>.</li><li style=\"font-size: 1em;\"><strong>По-дълго действащ</strong> от <strong>соматостатина</strong>.</li><li style=\"font-size: 1em;\">Прилага се <strong>подкожно</strong> на всеки 8 часа.</li><li style=\"font-size: 1em;\">Съществуват <strong>депо препарати</strong> за мускулно приложение 1 път месечно.</li><li style=\"font-size: 1em;\"><b>Клинично приложение</b>:</li><ul><li style=\"font-size: 1em;\"><strong><font color=\"#dd0a0a\">Акромегалия</font></strong>.</li><li style=\"font-size: 1em;\"><font color=\"#dd0a0a\"><strong>Периферни хормон-секретиращи тумори</strong> </font>- карциноиден тумор, инсулином, глюкагоном, випом, гастрином и пр.</li><li style=\"font-size: 1em;\"><strong><font color=\"#dd0a0a\">Остро кървене от езофагеални варици</font></strong>.</li></ul><li style=\"font-size: 1em;\"><b>Нежелани лекарствени реакции</b>:</li><ul><li style=\"font-size: 1em;\"><strong><font color=\"#dd0a0a\">Гастроинтестинални смущения</font></strong>.</li><li style=\"font-size: 1em;\"><strong><font color=\"#dd0a0a\">Жлъчна стаза</font></strong> и <strong><font color=\"#dd0a0a\">жлъчни камъни</font></strong>.</li><li style=\"font-size: 1em;\"><font color=\"#dd0a0a\"><strong>Болка</strong> на мястото на инжектиране</font>.</li></ul></ul><h4 style=\"font-size: 1.05em;\"><font color=\"#7e22ce\">Pegvisomant</font></h4><ul><li style=\"font-size: 1em;\"><strong>Модифициран аналог</strong> на <strong>растежния хормон</strong>.</li><li style=\"font-size: 1em;\">Механизъм на действие:</li><ul><li style=\"font-size: 1em;\">Свързва се с рецепторите на <strong>растежния хормон</strong>.</li><li style=\"font-size: 1em;\">Води до тяхната <strong>димеризация</strong>, но <strong>не и до активацията им</strong> =&gt; <strong>рецепторен антагонист</strong>.</li></ul><li style=\"font-size: 1em;\"><strong>Pegvisomant</strong> е <b>пегилиран </b>(добавен полиетиленгликол), което забавя разграждането му и удължава действието му.</li><li style=\"font-size: 1em;\">Подкожно приложение веднъж дневно.</li><li style=\"font-size: 1em;\">Използва се при пациенти с <strong><font color=\"#dd0a0a\">акромегалия</font></strong>, които <strong>не реагират на терапия с octreotide</strong>.</li><li style=\"font-size: 1em;\">Стимулира <strong>индиректно</strong> освобождаването на <strong>растежен хормон</strong>, тъй като нарушава <strong>отрицателната обратна връзка</strong> между <strong>IGF-1</strong> и <strong>хипофизата</strong> =&gt; възможен риск от <strong>увеличаване на размера на тумора</strong>.</li></ul><h3 style=\"font-size: 1.1em;\"><hr></h3><h3 style=\"font-size: 1.1em;\">Гонадотропни хормони (FSH и LH)</h3><ul><li style=\"font-size: 1em;\"><strong>Фоликуло-стимулиращ (FSH)</strong> и <strong>лутеинизиращ хормон (LH)</strong> се произвеждат и освобождават от гонадотрофните клетки.</li><li style=\"font-size: 1em;\">Освобождаването им се стимулира от гонадоторопин-освобождаващия фактор (gonadotropin-releasing hormone, <b>GnRH</b>) от хипоталамуса.</li><li style=\"font-size: 1em;\"><strong>GnRH</strong> се освобождава <strong>пулсатативно</strong> – в зависимост от амплитудата и честотата на пулсовете от хипофизата се отделя FSH или LH.</li><li><b>Физиологични функции</b>:</li><ul><li style=\"font-size: 1em;\"><strong>При жени</strong>:</li><ul><li style=\"font-size: 1em;\"><strong>FSH</strong> стимулира уголемяването и узряването на <strong>яйчниковите фоликули</strong> и контролира овариалния синтез на <strong>естрогени</strong> по време на <strong>фоликуларната фаза</strong> на менструалния цикъл.</li><li style=\"font-size: 1em;\"><strong>LH</strong> предизвиква <strong>овулацията</strong> в средата на менструалния цикъл и регулира овариалната продукция на <strong>андрогени</strong> по време на <strong>фоликуларната фаза</strong> и на <strong>естрогени</strong> и <strong>прогестерон</strong> по време на <strong>лутеалната фаза</strong>.</li></ul><li style=\"font-size: 1em;\"><strong>При мъже</strong>:</li><ul><li style=\"font-size: 1em;\"><strong>FSH</strong> регулира <strong>сперматогенезата</strong>.</li><li style=\"font-size: 1em;\"><strong>LH</strong> стимулира синтеза на <strong>тестостерон</strong>.</li></ul><li style=\"font-size: 1em;\">Освобождаването на гонадотропните хормони се потиска чрез отрицателна обратна връзка от периферните полови хормони.</li></ul><li><b>Човешки хорионгонадотропен хормон (hCG)</b>:</li><ul><li style=\"font-size: 1em;\">Плацентарен гликопротеин, произвеждан по време на бременността.</li><li style=\"font-size: 1em;\">Почти идентичен на <strong>LH</strong>, активира неговите рецептори.</li></ul></ul><h3 style=\"font-size: 1.1em;\">Лекарства с активност на гонадотропни хормони</h3><h4 style=\"font-size: 1.05em;\"></h4><h4><font color=\"#000000\">Лекарства с активност на FSH -</font> <font color=\"#7e22ce\">Urofollitropin</font></h4><ul><li><font color=\"#000000\">E</font>кстрахира се от урина на жени в <strong>менопауза</strong></li><li>В менопаузата физиологичната липса на <strong>естрогени</strong> води до нарушаване на <strong>отрицателната обратна връзка</strong> между периферните полови хормони и гонадотропните хормони<b>&nbsp;</b><p style=\"\">=&gt; <b>секрецията на FSH се </b></p><p style=\"\"><b>повишава</b></p>.</li></ul><h4><font color=\"#000000\">Лекарства с активност на LH - </font><font color=\"#7e22ce\">Chorionic gonadotropin</font>:</h4><ul><li><span style=\"white-space-collapse: preserve;\">Eкстрахира се от урина на бременни жени</span></li></ul><span style=\"white-space-collapse: preserve;\"><b>Клинично приложение:</b></span><ul><li><span style=\"white-space-collapse: preserve;\"><p>Стимулиране на овариалната функция при <b>инфертилитет </b>вследствие </p><p>на ановулаторни менструални цикли и при жени, подлагащи се на <b>in </b></p><p><b>vitro фертилизация</b></p></span></li><li><span style=\"white-space-collapse: preserve;\"><p>Лечение на <b>инфертилитет </b>при мъже с олигоспермия</p></span></li></ul><ul><li style=\"font-size: 1em;\"><p><b>Приложение – подкожно инжектиране:</b></p></li><ul><li style=\"font-size: 1em;\"><p><b>При жени:</b></p></li><ul><li style=\"font-size: 1em;\"><p>Терапията започва от 2-ия ден на менструалното кървене с ежедневни </p><p>инжекции на FSH в продължение на 12 дни</p></li><li style=\"font-size: 1em;\"><p>Chorionic gonadotropin се прилага с цел индукция на овулацията, когато </p><p>яйчниковите фоликули узреят (обикновено на 14-ия ден от менструалния </p><p>цикъл)</p></li></ul><li><p style=\"font-size: 1em;\"><b>При мъже:</b></p></li><ul><li><p style=\"font-size: 1em;\">Терапията се състои от ежедневни инжекции на двата медикамента (с </p><p style=\"font-size: 1em;\">активност на FSH и LH)</p></li><li><p style=\"font-size: 1em;\">Лечението продължава обикновено 4 до 6 месеца</p></li></ul></ul><li><p style=\"font-size: 1em;\"><b>Нежелани лекарствени реакции:</b></p></li><ul><li><p style=\"font-size: 1em;\"><b>При жени:</b></p></li><ul><li><p style=\"font-size: 1em;\">Главоболие, гадене, отоци, напрежение в гърдите, промени в настроението, </p><p style=\"font-size: 1em;\">раздразнителност, алергични реакции</p></li><li><p style=\"font-size: 1em;\">Синдром на овариалната хиперстимулация – обикновено се изразява в </p><p style=\"font-size: 1em;\">безсимптомно уголемяване на яйчниците, което преминава спонтанно, но </p><p style=\"font-size: 1em;\">понякога състоянието се усложнява с асцит, чернодробна дисфункция, </p><p style=\"font-size: 1em;\">белодробен оток, електролитни нарушения, тромбоемболични инциденти</p></li><li><p style=\"font-size: 1em;\">Многоплодна бременност – увеличава риска от развитие на усложнения по </p><p style=\"font-size: 1em;\">време на бременността и раждането</p></li></ul><li><span style=\"font-size: 1em; white-space-collapse: preserve;\"><b>При мъже:</b> гинекомастия, алергични реакции</span></li></ul></ul><hr style=\"white-space-collapse: preserve;\"><h3 style=\"white-space-collapse: preserve;\">Аналози на GnRH (Релини)</h3><ul style=\"white-space-collapse: preserve;\"><li><strong>GnRH</strong> стимулира секрецията на <strong>FSH</strong> и <strong>LH</strong> само, ако се освобождава <strong>на пулсове</strong>.</li><li>Постоянната <strong>непулсатативна секреция</strong> на <strong>GnRH</strong> потиска отделянето на <strong>гонадотропни хормони</strong>.</li><li><strong>Аналози на GnRH</strong>: <i><font color=\"#7e22ce\">goserelin</font></i>, <font color=\"#7e22ce\"><i>nafarelin</i></font>, <font color=\"#7e22ce\"><i>triptorelin</i></font>.</li></ul><h4 style=\"white-space-collapse: preserve;\"><font color=\"#b53f17\">Фармакокинетика:</font></h4><ul style=\"white-space-collapse: preserve;\"><li>Аналозите на <strong>GnRH</strong> са с много <strong>по-дълго действие</strong> от ендогенния <strong>GnRH</strong>.</li><li>Прилагат се под лекарствени форми, осигуряващи различна продължителност на действие:</li><ul><li><i><font color=\"#7e22ce\"><strong>Goserelin</strong> </font></i>се имплантира в <strong>подкожната мастна тъкан</strong> – имплантите осигуряват стабилни плазмени концентрации в продължение на <strong>месеци</strong> (1, 4, 6 или 12 месеца).</li><li><i><font color=\"#7e22ce\"><strong>Nafarelin</strong> </font></i>се прилага под формата на <strong>назален спрей</strong> – подходящ е за <strong>краткосрочно лечение</strong>.</li><li><i><font color=\"#7e22ce\"><strong>Triptorelin</strong> </font></i>се инжектира <strong>ежедневно</strong> при краткосрочна терапия; съществуват форми със <strong>забавено освобождаване</strong> (<strong>депо препарати</strong>), подходящи за <strong>дългосрочна терапия</strong>.</li></ul></ul><h4 style=\"white-space-collapse: preserve;\"><font color=\"#b53f17\">Фармакодинамика:</font></h4><ul style=\"white-space-collapse: preserve;\"><li>Аналозите на <strong>GnRH</strong> не могат да имитират напълно ефектите на <strong>пулсатативното освобождаване</strong> на ендогенния <strong>GnRH</strong>, защото имат <strong>продължително действие</strong>.</li><li>Аналозите на <strong>GnRH</strong> предизвикват <strong>двуфазен отговор</strong> от страна на <strong>хипофизата</strong>:</li><ul><li>През <strong>първите 7-10 дена</strong> на терапията се наблюдава <strong><font color=\"#dd0a0a\">агонистичен ефект</font></strong>, което води до <strong><font color=\"#dd0a0a\">повишаване на нивата FSH и LH</font></strong>.</li><li>Дългото действие на аналозите на GnRH води до <font color=\"#3b82f6\"><strong style=\"\">десенситизация</strong> </font>на техните рецептори в <strong>хипофизата</strong>.</li><li>Вследствие на това <strong>хипофизата</strong> спира да отговаря на действието на ендогенния GnRH, което води до <strong><font color=\"#3b82f6\">спад в нивата на FSH и LH</font></strong>.</li></ul><li>Инхибирането на секрецията на <strong>FSH</strong> и <strong>LH</strong> води до <strong>потискане на продукцията на периферните полови хормони</strong>.</li><li>Крайният ефект на аналозите на GnRH е състояние на <strong>хипогонадотропен хипогонадизъм</strong>.</li></ul><h4 style=\"white-space-collapse: preserve;\"><font color=\"#b53f17\">Клинично приложение – за гонадна супресия при:</font></h4><ul style=\"white-space-collapse: preserve;\"><li><strong>Хормонално-чувствителни злокачествени заболявания</strong>:</li><ul><li><strong>Простатен карцином</strong> при мъжете.</li><li><strong>Карцином на гърдата</strong>, <strong>яйчниците</strong>, <strong>ендометриума</strong> при жените.</li><li>Обикновено се използват <font color=\"#7e22ce\"><i>goserelin </i></font>и <i><font color=\"#7e22ce\">triptorelin </font></i>в лекарствени форми, осигуряващи <strong>продължително действие</strong>.</li></ul><li><strong>Доброкачествени хормонално-чувствителни заболявания</strong>:</li><ul><li><strong>Ендометриоза</strong>, <strong>миома на матката</strong>.</li><li>Терапията трябва да е <strong>по-кратка от 6 месеца</strong>.</li></ul><li><strong>Преждевременен пубертет</strong>.</li><li><strong><u>При in vitro фертилизация</u></strong>:</li><ul><li>Употребата на екзогенен <strong>FSH</strong> може да доведе до <strong>преждевременен пик на ендогенния LH</strong>, което би довело до <strong>преждевременна овулация</strong> и пропадане на in vitro цикъла.</li><li>Аналозите на <strong>GnRH</strong> се включват в протокола, за да <strong>потиснат отделянето на ендогенния LH</strong> и така да предотвратят потенциална <strong>преждевременна овулация</strong>.</li><li>Приложението на аналозите на <strong>GnRH</strong> започва от средата на предходния менструален цикъл.</li><li>Използват се <i><font color=\"#7e22ce\">triptorelin </font></i>и <i><font color=\"#7e22ce\">nafarelin </font></i>в лекарствени форми, подходящи за <strong>краткосрочно лечение</strong>.</li></ul></ul><h4 style=\"white-space-collapse: preserve;\"><font color=\"#b53f17\">Нежелани лекарствени реакции:</font></h4><ul style=\"white-space-collapse: preserve;\"><li>През <strong>първите 7-10 дни</strong> от терапията <strong>симптомите на заболяването се влошават</strong> (напр. болката при пациенти със злокачествени заболявания и костни метастази) вследствие на <strong>първоначалното активиране на секрецията на периферни полови хормони</strong>.</li><li><strong>Симптоми на менопауза</strong>.</li><li><strong>Намаляване на костната минерална плътност</strong> и <font color=\"#dd0a0a\"><strong><u>остеопороза</u></strong> </font>при лечение по-дълго от <strong>6 месеца</strong>.</li></ul><h3 style=\"white-space-collapse: preserve;\"><hr></h3><h2 style=\"white-space-collapse: preserve;\">Антагонисти на GnRH (Реликси)</h2><ul style=\"white-space-collapse: preserve;\"><li><strong>Лекарства</strong>: <i style=\"\"><font color=\"#7e22ce\" style=\"\">ganirelix</font></i>, <i style=\"\"><font color=\"#7e22ce\" style=\"\">cetrorelix</font></i>.</li></ul><h4 style=\"white-space-collapse: preserve;\"><font color=\"#b53f17\">Механизъм на действие:</font></h4><ul style=\"white-space-collapse: preserve;\"><li><strong>Конкурентни антагонисти</strong> на рецепторите на <strong>GnRH</strong>.</li><li>Секрецията на <strong>FSH</strong> и <strong>LH</strong> се потиска <strong>дозо-зависимо</strong>.</li><li>Производството на <strong>периферни полови хормони</strong> се потиска <strong>без първоначално активиране</strong>.</li></ul><h4 style=\"white-space-collapse: preserve;\"><font color=\"#b53f17\">Клинично приложение – за гонадна супресия (също като релините):</font></h4><ul style=\"white-space-collapse: preserve;\"><li><strong>Хормонално-чувствителни злокачествени</strong> и <strong>доброкачествени заболявания</strong>.</li><li>В <strong>in vitro протоколите</strong> с цел предотвратяване на <strong>преждевременното отделяне на ендогенен LH</strong>.</li><li><strong>Преждевременен пубертет</strong>.</li></ul><h4 style=\"white-space-collapse: preserve;\"><font color=\"#b53f17\">Нежелани лекарствени реакции:</font></h4><ul style=\"white-space-collapse: preserve;\"><li><strong>Симптоми на дефицит на полови хормони</strong>.</li><li><font color=\"#dd0a0a\"><strong style=\"text-decoration-line: underline;\">Остеопороза</strong> </font>при продължителна терапия.</li></ul><h4 style=\"white-space-collapse: preserve;\"><font color=\"#b53f17\">Предимства в сравнение с релините:</font></h4><ul style=\"white-space-collapse: preserve;\"><li>Няма <strong>първоначално влошаване</strong> на симптомите.</li><li><strong>Бързо начало</strong> на ефекта.</li></ul><h3 style=\"white-space-collapse: preserve;\"><hr></h3><h2 style=\"white-space-collapse: preserve;\">Пролактин</h2><ul style=\"white-space-collapse: preserve;\"><li>Синтезира се от лактотрофните клетки; техният брой се увеличава по време на <strong>бременност</strong>.</li><li><strong>Отговорен е за лактацията</strong>; основният стимул за отделянето му е <strong>сученето на бебето</strong>.</li><li><strong>Секрецията</strong> му е под <strong>непрекъснат инхибиторен контрол</strong> от <strong>допамина</strong>, освобождаван от <strong>хипоталамуса</strong>, чрез действието му върху <strong>D2 рецептори</strong> в <strong>хипофизата</strong>.</li></ul><h4 style=\"white-space-collapse: preserve;\"><font color=\"#b53f17\">Ефекти:</font></h4><ul style=\"white-space-collapse: preserve;\"><li><strong>Стимулиране производството на мляко</strong>.</li><li><strong>Стимулиране на пролиферацията</strong> и <strong>диференциацията</strong> на клетките на <strong>млечната жлеза</strong>.</li><li><strong>Потискане отделянето на GnRH и гонадотропини</strong>, както и на отговора на половите жлези към действието на гонадотропините – по време на кърмене <strong>овулация обикновено липсва</strong>.</li><li><strong>Стимулиране на „родителско“ поведение</strong>.</li><li><strong>Дефицитът</strong> на пролактин е <strong>рядък</strong> и се изразява в <strong>невъзможност за кърмене</strong>.</li></ul><h4 style=\"white-space-collapse: preserve;\"><font color=\"#b53f17\">Хиперпролактинемия:</font></h4><ul style=\"white-space-collapse: preserve;\"><li>Се развива <strong>физиологично</strong> по време на <strong>бременност</strong> и <strong>кърмене</strong>.</li><li>Се наблюдава <strong>патофизиологично</strong> най-често при <strong>пролактин-продуциращи аденоми на хипофизата</strong> (<strong>пролактиноми</strong>).</li><li>Се развива като <strong>нежелана лекарствена реакция</strong> при употреба на лекарства, които <strong>блокират D2 рецепторите</strong> – <strong>антипсихотици</strong>, някои <strong>антиеметици</strong>.</li><li><strong>Последствия от хиперпролактинемията</strong>:</li><ul><li><strong>При жени</strong>: инфертилитет, олигоменорея или аменорея, галакторея.</li><li><strong>При мъже</strong>: инфертилитет, загуба на либидо, еректилна дисфункция, гинекомастия.</li></ul></ul><h3 style=\"white-space-collapse: preserve;\"><hr></h3><h3 style=\"white-space-collapse: preserve;\">Инхибитори на пролактиновата секреция</h3><ul style=\"white-space-collapse: preserve;\"><li><i style=\"\"><font color=\"#7e22ce\">Bromocriptine</font></i>.</li></ul><h4 style=\"white-space-collapse: preserve;\"><font color=\"#b53f17\">Фармакокинетика:</font></h4><ul style=\"white-space-collapse: preserve;\"><li>Орално приложение.</li><li>Чернодробен метаболизъм.</li></ul><h4 style=\"white-space-collapse: preserve;\"><font color=\"#b53f17\">Механизъм на действие:</font></h4><ul style=\"white-space-collapse: preserve;\"><li><strong>Активиране на D2 рецепторите</strong>.</li></ul><h4 style=\"white-space-collapse: preserve;\"><font color=\"#b53f17\">Клинично приложение:</font></h4><ul style=\"white-space-collapse: preserve;\"><li><strong>Пролактином</strong>.</li><li><strong>Предотвратяване</strong> или <strong>спиране на лактацията</strong>.</li><li><strong>Акромегалия</strong> (в комбинация с <strong>octreotide</strong>).</li><li><strong>Болест на Паркинсон</strong>.</li></ul><h4 style=\"white-space-collapse: preserve;\"><font color=\"#b53f17\">Нежелани лекарствени реакции:</font></h4><ul style=\"white-space-collapse: preserve;\"><li><strong>Гадене</strong> и <strong>повръщане</strong> – поради активирането на <strong>D2 рецепторите</strong> в <strong>хеморецепторната тригер зона</strong>.</li><li><strong>Централно-нервни смущения</strong>, понякога с тежка <strong>психиатрична симптоматика</strong> (халюцинации, налудни идеи, нерационално поведение) – поради активирането на <strong>D2 рецепторите</strong> в <strong>мезо-лимбичния допаминергичен път</strong>.</li><li><strong>Периферен вазоспазъм</strong>, най-често <strong>студово индуциран</strong> – поради това, че са производни на ерго алкалоиди.</li><li><b>Белодробни инфилтрати; фиброзни изменения в белия дроб и ретроперитонеума</b> – при хронично приложение във висока доза.</li></ul><h3 style=\"white-space-collapse: preserve;\"><hr></h3><h2 style=\"white-space-collapse: preserve;\">Неврохипофиза</h2><ul style=\"white-space-collapse: preserve;\"><li><strong>Хормони</strong> – <strong>окситоцин</strong> и <strong>вазопресин</strong>.</li><li><strong>Нонапептиди</strong> със сходна структура.</li><li>Произвеждат се в супраоптичното и паравентрикуларното<b> </b>ядро на <strong>хипоталамуса</strong>.</li><li>Транспортират се по хипоталамо<strong>-</strong>хипофизния път до <b>задната хипофиза</b>.</li><li>Там се <strong>съхраняват</strong> и се <strong>освобождават</strong> в циркулацията при определени стимули.</li></ul><h3 style=\"white-space-collapse: preserve;\">1. Окситоцин</h3><h4 style=\"white-space-collapse: preserve;\"><font color=\"#b53f17\">Физиологично действие:</font></h4><ul style=\"white-space-collapse: preserve;\"><li>Върху <strong>матката</strong>: <strong><font color=\"#3b82f6\">стимулиране на маточните контракции</font></strong> по време на раждане.</li><li>Върху <strong>млечната жлеза</strong>: <strong><font color=\"#3b82f6\">контракция на миоепителните клетки</font></strong>, което води до <strong>отделяне на кърмата</strong>.</li><li>В <strong>ЦНС</strong>: роля в <strong>емоционалното обвързване</strong> – „хормона на обичта“.</li><li><strong>Освобождаването</strong> на <strong>окситоцин</strong> се стимулира от <strong>дилатацията на маточната шийка</strong> по време на раждане и от <strong>сученето на бебето</strong>.</li><li>Броят на <strong>окситоциновите рецептори</strong> нараства през втората половина на бременността.</li></ul><h3 style=\"white-space-collapse: preserve;\"><font color=\"#7e22ce\">Oxytocin</font></h3><ul style=\"white-space-collapse: preserve;\"><li><b style=\"\"><font color=\"#000000\"><p style=\"\">Лекарството е идентично на ендогенния хормон.</p></font></b></li><li><font color=\"#b53f17\"><b>Фармакокинетика:</b></font></li><ul><li><strong>Пътища на приложение</strong>: Интравенозна инфузия, Мускулна инжекция, Сублингвални или букални таблети, Назален спрей.</li><li><strong>Елиминация</strong> – разграждане от <strong>окситоциназа</strong> в <strong>черния дроб</strong> и <strong>бъбреците</strong>.</li><li><strong>Кратък плазмен полуживот</strong> (5 минути) и продължителност на действие.</li></ul><li><font color=\"#b53f17\"><b>Механизъм на действие:</b></font></li><ul><li>Активиране на Gq-протеин свързан рецептор с последващо увеличаване вътреклетъчните нива на свободни Ca<sup>2+</sup> =&gt; контракция на мускулната клетка.</li></ul><li><font color=\"#b53f17\"><b>Ефекти</b>:</font></li><ul><li>В <strong>матката</strong>:</li><ul><li>В <strong>ниски дози</strong> – увеличаване на честотата и силата на <strong>регулярните координирани маточни контракции</strong> (<strong>утерокинетично действие</strong>).</li><li>Във <strong>високи дози</strong> – <strong>трайна маточна контракция</strong> (<strong>утеротонично действие</strong>).</li></ul><li>В <strong>млечната жлеза</strong>: <strong>отделяне на кърма</strong>.</li></ul><li><font color=\"#b53f17\"><b>Клинично приложение:</b></font></li><ul><li><font color=\"#3b82f6\"><strong>Индукция</strong> или <strong>стимулиране на естествено раждане</strong> </font>– бавна интравенозна инфузия.</li><li><strong>Превенция</strong> и <strong>лечение на постпартално кървене</strong> – интрамускулна инжекция.</li><li><strong>За стимулиране на лактацията</strong> – сублингвални или букални таблети.</li><li>Потенциално бъдещо приложение в терапията на аутизъм, тревожност, депресия и други невропсихиатрични заболявания – назален спрей.</li></ul><li><font color=\"#b53f17\"><b>Нежелани лекарствени реакции:</b></font></li><ul><li><strong>Добра поносимост</strong> при правилна употреба.</li><li><strong>Прекомерното стимулиране</strong> на маточните контракции може да доведе до <strong>фетален дистрес</strong>, <strong>отлепване на плацентата</strong> или <strong>маточна руптура</strong>.</li><li>Във <strong>високи дози</strong> може да активира рецепторите на <strong>вазопресин</strong> и да доведе до <strong>задръжка на вода</strong>.</li><li>При <strong>бързо интравенозно приложение</strong> – <strong>вазодилатация</strong> и <strong>хипотония</strong>.</li></ul></ul><h3 style=\"white-space-collapse: preserve;\"><font color=\"#7e22ce\">Atosiban</font></h3><ul style=\"white-space-collapse: preserve;\"><li><strong>Пептиден аналог</strong> на <strong>окситоцина</strong>.</li><li><font color=\"#b53f17\"><b>Механизъм на действие:</b></font></li><ul><li><font color=\"#dd0a0a\"><strong>Антагонист</strong> </font>на <strong>окситоциновите рецептори</strong>.</li></ul><li><font color=\"#b53f17\"><b>Ефект:</b></font></li><ul><li>Предотвратяване на <strong>окситоцин-индуцираните маточни контракции</strong> =&gt; <strong>токолитичен ефект</strong>.</li></ul><li><font color=\"#b53f17\"><b>Клинично приложение:</b></font></li><ul><li><strong><font color=\"#3b82f6\">Преждевременно раждане</font></strong>.</li></ul><li><font color=\"#b53f17\"><b>Приложение:</b></font></li><ul><li>Интравенозна инфузия за 2-48 часа.</li></ul><li><font color=\"#b53f17\"><b>Нежелани лекарствени реакции:</b></font></li><ul><li>По-добре поносим от бета2-агонистите.</li><li><strong>Гадене</strong>, <strong>повръщане</strong>.</li><li><strong>Хипотония</strong>.</li><li>Възможна <strong>атония на матката</strong> и <strong>кръвоизливи</strong>.</li></ul></ul><h3 style=\"white-space-collapse: preserve;\">2. Вазопресин (Антидиуретичен хормон, АДХ)</h3><ul style=\"white-space-collapse: preserve;\"><li><strong>Физиологична роля</strong> – регулира <strong>задръжката на вода</strong> в организма.</li><li><strong>Отделянето му се стимулира от</strong>:</li><ul><li><strong>Повишаване на плазмения осмоларитет</strong>.</li><li><strong>Намаляване обема на циркулиращата кръв</strong>.</li></ul><li><font color=\"#b53f17\"><b>Рецептори и ефекти:</b></font></li><ul><li><strong>V1 рецептори</strong>:</li><ul><li>Свързани с Gq протеин.</li><li><strong>Локализация</strong> – <strong>кръвоносни съдове</strong>.</li><li><strong>Ефект</strong> – <strong>вазоконстрикция</strong>.</li></ul><li><strong>V2 рецептори</strong>:</li><ul><li>Свързани с Gs протеин.</li><li><strong>Локализация</strong> – <strong>събирателното каналче на нефрона</strong>.</li><li><strong>Ефект</strong> – <strong>реабсорбция на вода</strong>.</li></ul></ul><li><font color=\"#b53f17\"><b>Нарушения, свързани с промени в секрецията или действието на вазопресин:</b></font></li><ul><li><strong>Безвкусен диабет (diabetes insipidus)</strong> – образува се голямо количество разредена урина вследствие на:</li><ul><li><strong>Нарушена секреция на вазопресин</strong> (<strong>централен безвкусен диабет</strong>).</li><li><strong>Нарушено действие</strong> върху <strong>V2 рецепторите</strong> в бъбреците (<strong>нефрогенен безвкусен диабет</strong>).</li></ul><li><strong>Синдром на неадекватна секреция на АДХ</strong> – <strong>водна задръжка</strong> и <strong>хипонатриемия</strong> вследствие на повишени нива на вазопресин.</li></ul></ul><h3 style=\"white-space-collapse: preserve;\">Лекарства с активност на вазопресин: <font color=\"#7e22ce\" style=\"\"><i>Terlipressin</i></font></h3><ul style=\"white-space-collapse: preserve;\"><li><strong>Пептиден аналог</strong> на <strong>вазопресина</strong>.</li><li><font color=\"#b53f17\"><b>Фармакокинетика:</b></font></li><ul><li><strong>Приложение</strong> – интравенозно инжектиране.</li><li><strong>Пролекарство</strong> – в организма се превръща в лизин-вазопресин.</li><li><strong>По-дълъг полуживот</strong> и продължителност на действие (няколко часа) от ендогенния вазопресин.</li></ul><li><font color=\"#b53f17\"><b>Механизъм на действие и ефекти:</b></font></li><ul><li>Подобни на тези на ендогенния <strong>вазопресин</strong>.</li><li>Активира основно <strong>V1 рецепторите</strong> в <strong>кръвоносните съдове</strong>.</li><li>Води до <strong>вазоконстрикция</strong> и <strong>повишаване на кръвното налягане</strong>.</li><li><strong>Минимален ефект</strong> върху бъбреците и водната задръжка.</li></ul><li><font color=\"#b53f17\"><b>Клинично приложение:</b></font></li><ul><li><strong><font color=\"#3b82f6\">Остро кървене на езофагеални варици</font></strong>.</li></ul><li><font color=\"#b53f17\"><b>Нежелани лекарствени реакции:</b></font></li><ul><li><strong>Хипертония</strong>, <strong>коронарен вазоспазъм</strong>, <strong>тъканна исхемия</strong> (поради вазоконстрикцията).</li><li><strong>Абдоминални крампи</strong>, <strong>бронхоспазъм</strong>.</li><li>Възможно, но рядко – <strong>хипонатриемия</strong>, <strong>водна интоксикация</strong>, <strong>гърчове</strong>.</li></ul></ul><h3 style=\"white-space-collapse: preserve;\">Лекарства с активност на вазопресин: <font color=\"#7e22ce\"><i>Desmopressin</i></font></h3><ul style=\"white-space-collapse: preserve;\"><li><strong>Пептиден аналог</strong> на <strong>вазопресин</strong>.</li><li><font color=\"#b53f17\"><b>Фармакокинетика:</b></font></li><ul><li><strong>Пътища на приложение</strong>: Назален спрей, Сублингвални таблети.</li><li><strong>По-дълъг полуживот</strong> и продължителност на действие от ендогенния вазопресин – приложение обикновено 2 или 3 пъти дневно.</li></ul><li><font color=\"#b53f17\"><b>Механизъм на действие и ефекти:</b></font></li><ul><li><strong>Активиране на V2 рецепторите</strong> в <strong>събирателното каналче</strong>.</li><li><strong>Имитира ефекта на вазопресин</strong> по отношение на <strong>водната задръжка</strong>.</li><li><strong>Минимално действие</strong> върху <strong>V1 рецепторите</strong>.</li><li>Отношението антидиуретичен спрямо вазопресорен ефект е 4000 пъти по-голямо от това на вазопресин.</li></ul><li><font color=\"#b53f17\"><b>Клинично приложение:</b></font></li><ul><li><strong>Централен безвкусен диабет</strong> (<strong>заместителна терапия</strong>).</li><li><strong>Enures nocturna</strong> – приема се вечер преди лягане за <strong>намаляване на производството на урина</strong> през нощта.</li></ul><li><font color=\"#b53f17\"><b>Нежелани лекарствени реакции:</b></font></li><ul><li><strong>Добра поносимост</strong>.</li><li>Главоболие, гадене, абдоминални крампи.</li><li><p>Алергични реакции</p></li><li>При <strong>предозиране</strong> – <strong>водна интоксикация</strong> с <strong>хипонатриемия</strong> и <strong>гърчове</strong>.</li></ul></ul><h3 style=\"white-space-collapse: preserve;\">Антагонисти на АДХ (Ваптани)</h3><ul style=\"\"><li style=\"white-space-collapse: preserve;\"><i><font color=\"#7e22ce\">Conivaptan</font></i>, <i><font color=\"#7e22ce\">tolvaptan</font></i> – непептидна структура.</li><li style=\"white-space-collapse: preserve;\"><font color=\"#b53f17\"><b>Фармакокинетика:</b></font></li><ul style=\"white-space-collapse: preserve;\"><li><strong>Пътища на приложение</strong>:</li><ul><li><font color=\"#7e22ce\"><i><strong>Conivaptan</strong> </i></font>– интравенозно приложение.</li><li><font color=\"#7e22ce\"><i><strong>Tolvaptan</strong> </i></font>– орално приложение.</li></ul><li><strong>Елиминация</strong>:</li><ul><li><strong>Чернодробен метаболизъм</strong> от <strong>CYP3A4</strong>.</li><li><i><font color=\"#7e22ce\"><strong>Conivaptan</strong> </font></i>е <strong>инхибитор на CYP3A4</strong>.</li></ul></ul><li style=\"white-space-collapse: preserve;\"><font color=\"#b53f17\"><b>Механизъм на действие:</b></font></li><ul><li><strong>Блокада на вазопресиновите рецептори</strong>.</li><li><i><font color=\"#7e22ce\"><strong>Conivaptan</strong> </font></i>блокира и <strong>V1</strong>, и <strong>V2 рецепторите</strong>.</li><li><i><font color=\"#7e22ce\"><strong>Tolvaptan</strong> </font></i>блокира само <strong>V2 рецепторите</strong>.</li></ul><li style=\"white-space-collapse: preserve;\"><font color=\"#b53f17\"><b>Ефекти:</b></font></li><ul style=\"white-space-collapse: preserve;\"><li><strong>Повишена екскреция на вода</strong> (<strong>аквареза</strong>).</li></ul><li><span style=\"white-space-collapse: preserve;\"><p><b><font color=\"#c34318\">Клинично приложение</font></b>:</p></span></li><ul><li><span style=\"white-space-collapse: preserve;\"><p>Хипонатриемия вследствие на синдром на неадекватна секреция на АДХ</p></span></li><li><span style=\"white-space-collapse: preserve;\"><p>Остра сърдечна недостатъчност (често има повишени нива на вазопресин)</p></span></li></ul><li><span style=\"white-space-collapse: preserve;\"><p><b><font color=\"#c34318\">Нежелани лекарствени реакции</font></b>:</p></span></li><ul><li><span style=\"white-space-collapse: preserve;\"><p>Симптоми на дехидратация – главоболие, </p><p>жажда, ксеростомия, хипотония</p></span></li><li><span style=\"white-space-collapse: preserve;\"><p><i style=\"\"><font color=\"#7e22ce\" style=\"\">Tolvaptan </font></i>– <b>хепатотоксичност </b>и чернодробна</p><p>недостатъчност</p></span></li></ul></ul><hr style=\"white-space-collapse: preserve;\"><h2 style=\"white-space-collapse: preserve;\">Лекарства с активност на полови хормони и техни антагонисти</h2><p style=\"white-space-collapse: preserve;\"><b>Доц. д-р Силвия Ганчева, д.м</b></p><h3 style=\"white-space-collapse: preserve;\">Женски полови хормони</h3><ul style=\"\"><li style=\"white-space-collapse: preserve;\">Женските полови хормони са <strong>естрогени</strong> и <strong>гестагени</strong>.</li><li style=\"white-space-collapse: preserve;\">Произвеждат се в <strong>яйчниците</strong> под стимулаторния контрол на <strong>хипофизарните гонадотропни хормони</strong>.</li><li style=\"white-space-collapse: preserve;\">Нивата на ендогенните хормони се променят в хода на <strong>менструалния цикъл</strong>:</li><ul style=\"white-space-collapse: preserve;\"><li><strong>Естрогените</strong> достигат своя пик в средата на цикъла.</li><li><strong>Прогестеронът</strong> достига своя пик в края.</li></ul><li style=\"white-space-collapse: preserve;\"><strong>Естрогените</strong> се произвеждат най-вече от нарастващия през първата половина на цикъла <strong>яйчников фоликул</strong> под контрола на <strong>фоликуло-стимулиращия хормон (FSH)</strong>.</li><li style=\"white-space-collapse: preserve;\">В средата на цикъла, <p>когато фоликулът е узрял, </p>под въздействието на <strong>лутеинизиращия хормон (LH)</strong>, настъпва <strong>овулацията</strong> и яйцеклетката попада в <strong>маточните тръби</strong>.</li><li style=\"white-space-collapse: preserve;\">След овулацията фоликулът се трансформира в <strong>жълто тяло</strong>, което произвежда <strong>естрогени</strong> и най-вече <strong>прогестерон</strong> под контрола на <strong>LH</strong>.</li><li style=\"white-space-collapse: preserve;\">Ако <strong>не настъпи бременност</strong>:</li><ul style=\"white-space-collapse: preserve;\"><li><strong>Жълтото тяло</strong> дегенерира.</li><li>Рязкото намаляване на нивата на <strong>прогестерон</strong> води до появата на <strong>менструалното кървене</strong> и цикълът започва от начало.</li></ul><li style=\"white-space-collapse: preserve;\">Ако <strong>настъпи бременност</strong>:</li><ul style=\"white-space-collapse: preserve;\"><li><strong>Жълтото тяло</strong>, а впоследствие <strong>плацентата</strong> продължават да произвеждат <strong>женски полови хормони</strong>.</li></ul></ul><span style=\"white-space-collapse: preserve;\"><img src=\"https://files.coursebook.lol/Coursebook%20Assets/2026-05-05/coursebook-assets/assets/%D0%9C%D0%B5%D0%BD%D1%81%D1%82%D1%83%D0%B0%D0%BB%D0%B5%D0%BD%D1%86%D0%B8%D0%BA%D1%8A%D0%BB%D1%84%D0%B0%D1%80%D0%BC%D0%B0%D0%BA.png\" alt=\"Менстуаленцикълфармак.png\" data-original-src=\"https://files.coursebook.lol/Coursebook%20Assets/2026-05-05/coursebook-assets/assets/%D0%9C%D0%B5%D0%BD%D1%81%D1%82%D1%83%D0%B0%D0%BB%D0%B5%D0%BD%D1%86%D0%B8%D0%BA%D1%8A%D0%BB%D1%84%D0%B0%D1%80%D0%BC%D0%B0%D0%BA.png\" style=\"max-width: 100%; height: auto;\"><br><br></span><h2>Естрогени</h2><ul style=\"white-space-collapse: preserve;\"><li><strong><font color=\"#b83d14\">Ендогенни естрогени</font></strong>: <strong>естрадиол</strong>, естрон и естриол.</li><li><strong><font color=\"#b83d14\">Синтез</font></strong>:</li><ul><li>Изходна суровина за синтез на всички стероидни хормони е <strong>холестеролът</strong>.</li><li>Непосредствен прекурсор са <strong>андрогените</strong>, като чрез ензима <strong>ароматаза,</strong> <strong>тестостерон</strong> и <strong>андростенедион</strong> се превръщат съответно в <strong>естрадиол</strong> и <strong>естрон</strong>.</li><li>Основното количество естрогени при жени във фертилна възраст се произвежда в <strong>яйчниците</strong>.</li><ul><li>В началото на цикъла нивото на естрогени е минимално и постепенно се увеличава с узряването на Граафовия фоликул.</li><li><strong>Пикът в секрецията</strong> е непосредствено преди <strong>овулацията</strong>.</li><li>Във втората половина на цикъла нивата са умерени и се поддържат от синтез в <strong>жълтото тяло</strong>.</li></ul><li><strong>Екстраовариална продукция на естрогени</strong>:</li><ul><li>В <strong>кората на надбъбрека</strong> и в <strong>мастната тъкан</strong> – и при двата пола.</li><li>В <strong>плацентата</strong> – по време на бременност.</li><li>В <strong>туморна тъкан</strong>.</li></ul></ul><li><font color=\"#b83d14\"><b>Механизъм на действие:</b></font></li><ul><li><strong>Геномни ефекти</strong> – <font color=\"#3b82f6\">бавно настъпващи</font> и с <font color=\"#3b82f6\">дълга продължителност</font>:</li><ul><li>Свързване с <strong><font color=\"#3b82f6\">вътреклетъчни рецептори</font></strong> – ERα и Erβ.</li><li>Образуване на димери от два комплекса хормон-рецептор.</li><li>Свързване на димера с определен участък от молекулата на <strong>ДНК</strong>.</li><li>Промяна на <strong><font color=\"#3b82f6\">генната транскрипция</font></strong> =&gt; промяна в <strong>протеиновия синтез</strong>.</li></ul><li><strong>Негеномни ефекти</strong> – <font color=\"#3b82f6\">бързо настъпващи</font>:</li><ul><li>Чрез повлияване на <strong><font color=\"#3b82f6\">мембранни рецептори</font></strong>.</li><li>Чрез повлияване на <strong>вътреклетъчни рецептори</strong>, но не чрез промяна на генната експресия, а чрез <strong>вътреклетъчни сигнални пътища</strong>.</li></ul></ul><li><font color=\"#b83d14\"><b>Ефекти, свързани с женската полова система:</b></font></li><ul><li>Необходими са за оформянето на женската полова система по време на ембрионалното развитие.</li><li>По време на пубертета са отговорни за оформянето на <strong>вторичните полови белези</strong>, вкл. <strong>пролиферативните промени в млечните жлези</strong>.</li><li>По време на <strong>менструалния цикъл</strong> са отговорни за промените в гениталния апарат през <b>първата половина на цикъла</b>.</li><ul><li>Стимулират <strong>пролиферативни промени в ендометриума</strong> – увеличаване на дебелината и васкуларизацията му.</li><li>Променят състава на цервикалния секрет, така че да е гостоприемен за сперматозоида.</li></ul></ul><li><b><font color=\"#b83d14\">Ефекти, които не са свързани с половата система:</font></b></li><ul><li><strong>В костната тъкан</strong>:</li><ul><li>По време на пубертета <b>стимулират растежа на дългите кости</b> и <strong>затварянето на епифизарните плочки</strong>.</li><li><b>Инхибират </b><strong>остеокластите</strong> и поддържат нормалния баланс между процесите на костна резорбция и костно формиране (затова по време на <strong>менопаузата</strong> се увеличава рискът от <strong>остеопороза</strong>).</li></ul><li><strong>Подобряват липидния профил</strong> (затова жените във фертилна възраст развиват по-рядко атеросклероза и свързаните с нея заболявания).</li><li><b>Стимулират синтеза</b> на много протеини в <strong>черния дроб</strong>, вкл. на <strong>коагулационните фактори</strong>.</li><li>Водят до <strong>задръжка на натрий и вода</strong> – минералкортикоиден ефект.</li><li>Имат <strong>поведенчески ефекти в ЦНС</strong> – оформят т.нар. „женски тип“ поведение; намаляването на нивата на естрогените в периода на <strong>менопаузата</strong> и след раждане е свързано с появата на емоционални нарушения, нарушения на съня и депресия.</li><li>Осъществяват отрицателна обратна връзка с хипоталамуса и хипофизната жлеза и <b>потискат отделянето на </b><strong>гонадотропин-рилийзинг фактор</strong> и <strong>FSH</strong>.</li></ul></ul><h3 style=\"white-space-collapse: preserve;\"><hr></h3><h2>Лекарства с естрогенна активност</h2><ul style=\"white-space-collapse: preserve;\"><li><strong><font color=\"#b83d14\">Представители</font></strong>:</li><ul><li>Природни – <strong><i><font color=\"#7e22ce\">estradiol</font></i></strong>, <strong><font color=\"#7e22ce\"><i>estriol</i></font></strong>.</li><li>Полусинтетичен – <strong><font color=\"#7e22ce\"><i>ethinylestradiol</i></font></strong>.</li></ul><li><b><font color=\"#b83d14\">Фармакокинетика – висока липоразтворимост (стероидни хормони):</font></b></li><ul><li><strong><font color=\"#b83d14\">Резорбция и пътища на приложение</font></strong>:</li><ul><li>Добра резорбция в ГИТ при перорално приложение.</li><li><i><font color=\"#7e22ce\"><strong>Estradiol</strong> </font></i>подлежи на <strong>предсистемен метаболизъм</strong> =&gt; <strong>ниска орална бионаличност</strong>.</li><li><i><font color=\"#7e22ce\"><strong>Estradiol</strong> </font></i>може да се прилага <font color=\"#3b82f6\"><strong>трансдермално</strong> </font>под формата на <strong>TTS</strong> (избягва се <strong>first-pass ефектът</strong>).</li><li><i><font color=\"#7e22ce\"><strong>Estradiol</strong> </font></i>и <i><font color=\"#7e22ce\"><strong>estriol</strong> </font></i>имат форми за <strong>локално вагинално приложение</strong>.</li><li><i><font color=\"#7e22ce\"><strong>Ethinylestradiol</strong> </font></i>не подлежи на предсистемен метаболизъм и има <strong>добра бионаличност</strong> – прилага се <strong>орално</strong>.</li></ul><li><strong><font color=\"#b83d14\">Елиминация</font></strong>:</li><ul><li><strong>Чернодробен метаболизъм</strong> чрез глюкурониране и сулфатиране.</li><li><strong>Ентерохепатален кръговрат</strong>, удължаващ продължителността на действие.</li></ul></ul><li><b><font color=\"#b83d14\">Механизъм на действие и ефекти:</font></b></li><ul><li><strong>Идентични</strong><b> на тези на ендогенните </b><strong>естрогени</strong>.</li><li>При перорална употреба ефектът върху <strong>черния дроб</strong> (стимулиране синтеза на <strong>фактори на кръвосъсирване</strong>) е <strong>по-силно проявен</strong>.</li></ul><li><b><font color=\"#b83d14\">Клинична употреба:</font></b></li><ul><li><strong>При момичета с хипогонадизъм</strong>:</li><ul><li><strong>Заместителна терапия</strong>.</li><li>Терапията започва през пубертета, за да се развият <strong>вторичните полови белези</strong>.</li></ul><li><strong>При жени в менопауза</strong>:</li><ul><li><strong>Хормонална заместителна терапия</strong> за повлияване на <strong>симптомите на менопауза</strong> и за предпазване от <strong>остеопороза</strong>, обикновено в комбинация с гестагени.</li><li>Препаратите за <strong>локално приложение</strong> се предпочитат при наличие само на <strong>локални вагинални симптоми</strong>.</li></ul><li><strong>При жени във фертилна възраст</strong> – <strong>комбинирани орални контрацептиви</strong>:</li><ul><li>Използват се <strong>комбинации</strong> от <strong>ethynilestradiol</strong> и <strong>гестаген</strong>.</li><li>Освен с цел <strong>контрацепция</strong> се използват за <strong>регулиране на месечния цикъл</strong> при нередовна, болезнена и/или обилна менструация.</li></ul></ul><li><b><font color=\"#b83d14\">Нежелани ефекти:</font></b></li><ul><li><strong>Естрогените</strong> стимулират <strong>пролиферативни промени</strong> в <strong>млечната жлеза</strong> и <strong>ендометриума</strong> =&gt; <strong>увеличава се рискът от рак на гърдата и ендометриума</strong>.</li><ul><li><strong>Гестагените</strong> <strong>премахват</strong> този опасен ефект в <strong>ендометриума</strong>, затова естрогените почти винаги се <strong>комбинират с гестагени</strong>.</li></ul><li><strong>Естрогените</strong> увеличават синтеза на <strong>фактори на кръвосъсирването</strong> =&gt; увеличават риска от образуване на<strong> венозни тромбози</strong>.</li><li><strong>Други</strong>:</li><ul><li>Напрежение в гърдите, главоболие.</li><li>Гадене, повръщане, промени в апетита.</li><li>Задръжка на вода и отоци.</li><li>При деца – преждевременно спиране на растежа.</li><li>При мъже – феминизация.</li></ul></ul><li><strong><font color=\"#b83d14\">Лекарствени взаимодействия</font></strong>:</li><ul><li>При употреба с <strong>ензимини индуктори</strong> (напр. <font color=\"#7e22ce\" style=\"\"><i style=\"\">phenobarbital</i></font>, <font color=\"#7e22ce\" style=\"\"><i style=\"\"><u><b>rifampicin</b></u></i></font>) метаболизмът им се ускорява =&gt; ефектът <strong>намалява</strong>.</li><li>При употреба с <strong>широкоспектърни антибиотици</strong> може да се развие <strong>дисбактериоза</strong> и да се наруши <strong>ентерохепаталният кръговрат</strong> =&gt; <b>ефектът </b><strong>намалява</strong>.</li></ul></ul><h3 style=\"white-space-collapse: preserve;\">Селективни естроген рецепторни модулатори (SERMs)</h3><ul style=\"white-space-collapse: preserve;\"><li><strong>Селективните естроген рецепторни модулатори</strong> <u>действат като </u><strong style=\"text-decoration-line: underline;\">агонисти</strong><u> на </u><strong style=\"text-decoration-line: underline;\">естрогенните рецептори</strong><u> в някои тъкани и като </u><strong style=\"text-decoration-line: underline;\">антагонисти</strong><u> в други</u>.</li><li><strong><font color=\"#7e22ce\"><i>Tamoxifen</i></font></strong>:</li><ul><li><strong><font color=\"#b83d14\">Действие</font></strong>: <strong>антагонист</strong><b> в</b> <strong>млечната жлеза</strong>, агонист в другите тъкани, вкл. костите.</li><li><strong><font color=\"#b83d14\">Клинична употреба</font></strong>: естроген-чувствителни<strong> тумори на млечната жлеза</strong>.</li><li><strong><font color=\"#b83d14\">Бонус</font></strong>: Агонистичният ефект в <strong>костите</strong> предпазва от <strong>остеопороза</strong>.</li><li><strong><font color=\"#b83d14\">Нежелани ефекти</font></strong>: повишен риск от <strong>венозни тромбози</strong> и <strong>тромбоемболизъм</strong> и <strong>рак на ендометриума</strong>.</li></ul><li><strong><font color=\"#7e22ce\"><i>Raloxifene</i></font></strong>:</li><ul><li><strong><font color=\"#b83d14\">Действие</font></strong>: антагонист в млечната жлеза и ендометриума, <strong>агонист</strong><b> в </b><strong>костите</strong> и другите тъкани.</li><li><strong><font color=\"#b83d14\">Клинична употреба</font></strong>: <strong>постменопаузална остеопороза</strong>.</li><li><font color=\"#b83d14\"><b>Бонус</b></font>: <strong>Намалява риска</strong> от <strong>рак на гърдата</strong> и <strong>ендометриума</strong>.</li><li><strong><font color=\"#b83d14\">Нежелани ефекти</font></strong>: повишен риск от <strong>венозни тромбози</strong> и <strong>тромбоемболизъм</strong>.</li></ul><li><strong><font color=\"#7e22ce\"><i>Clomifene</i></font></strong>:</li><ul><li><strong><font color=\"#b83d14\">Действие</font></strong>: <strong>антагонист</strong><b> в</b> <strong>хипофизата</strong> (нарушава отрицателната обратна връзка и <b>стимулира отделянето на гонадотропни хормони</b>) и агонист в другите тъкани.</li><li><strong><font color=\"#b83d14\">Клинична употреба</font></strong>: <strong>стимулиране на овулацията</strong> при лечение на <strong>инфертилитет</strong>.</li><li><strong><font color=\"#b83d14\">Нежелани ефекти</font></strong>: <strong>синдром на яйчникова хиперстимулация</strong> (нисък риск); повишава вероятността за развитие на<strong> многоплодна бременност</strong>.</li></ul></ul><h3 style=\"white-space-collapse: preserve;\"><p>Естрогенни антагонисти, разграждащи естрогенните рецептори</p></h3><ul style=\"white-space-collapse: preserve;\"><li><strong><p style=\"\"><font color=\"#bc3f15\">Предсатвители:</font><font color=\"#cd4518\"> </font></p><i style=\"color: rgb(126, 34, 206);\">Fulvestrant</i></strong>:</li><li><strong><font color=\"#b83d14\">Механизъм на действие</font></strong>: <strong>пълен рецепторен антагонист</strong>; свързва се с рецепторите, блокира ги и стимулира тяхното <strong>разграждане</strong>.</li><li><strong><font color=\"#b83d14\">Клинично приложение</font></strong>: <strong>рак на гърдата</strong>; при <strong>неефективност на <i><font color=\"#7e22ce\">tamoxifen</font></i></strong>.</li><li><strong><font color=\"#b83d14\">НЛР</font></strong>: <strong>симптоми на менопауза</strong>; риск от <strong>остеопороза</strong>.</li></ul><span style=\"white-space-collapse: preserve;\"><br></span><strong style=\"white-space-collapse: preserve;\"></strong><h3>Естрогенни антагонисти, ароматозни инхибитори:</h3><ul style=\"white-space-collapse: preserve;\"><li><strong><font color=\"#b83d14\">Предсатвители: </font><p style=\"\"><font color=\"#7e22ce\"><i>Anastrozole</i></font><font color=\"#b83d14\">, </font></p><p style=\"\"><i style=\"\"><font color=\"#7e22ce\">Letrozole</font></i><font color=\"#b83d14\">, </font></p><p style=\"\"><i style=\"\"><font color=\"#7e22ce\">Exemestane </font></i></p></strong></li><li><strong><font color=\"#b83d14\">Механизъм на действие</font></strong>: <strong>блокиране на синтеза на естрогени</strong>.</li><ul><li><strong><font color=\"#7e22ce\"><i>Anastrozole</i></font></strong> и <strong><font color=\"#7e22ce\"><i>letrozole</i></font></strong>: нестероидни селективни обратими инхибитори на ароматазата.</li><li><strong><font color=\"#7e22ce\"><i>Еxemestane</i></font></strong>: стероиден необратим инхибитор на ароматазата.</li></ul><li><strong><font color=\"#b83d14\">Клинично приложение</font></strong>:</li><ul><li><strong>Рак на млечната жлеза</strong> при жени в <strong>менопауза</strong> или <strong>овариектомирани</strong>.</li><li><strong>Цел</strong> – да се потисне <strong>екстраовариалната естрогенна продукция</strong> основно в <strong>туморната тъкан</strong>.</li></ul><li><strong><font color=\"#b83d14\">НЛР</font></strong>: <strong>симптоми на менопауза</strong>; риск от <strong>остеопороза</strong>.</li></ul><h3 style=\"white-space-collapse: preserve;\"><hr></h3><h3 style=\"white-space-collapse: preserve;\">Женски полови хормони: Гестагени</h3><ul style=\"white-space-collapse: preserve;\"><li><strong>Ендогенен гестаген</strong>: <strong>Прогестерон</strong>.</li><li><strong><font color=\"#b83d14\">Синтез и секреция</font></strong>:</li><ul><li><strong>Овариална</strong>:</li><ul><li>През пролиферативната фаза концентрацията е минимална.</li><li>Отделя се от <strong>жълтото тяло</strong> през <b>втората половина</b> от цикъла (лутеална фаза).</li><li>При липса на бременност <b>нивото му пада рязко в края на цикъла</b> заради дегенерацията на жълтото тяло, което води до менструалното кървене.</li></ul><li><strong>Екстраовариална</strong>:</li><ul><li>В <strong>плацентата</strong> – по време на бременност.</li><li>В <strong>кората на надбъбрека</strong> и <strong>тестисите</strong> (минимални количества).</li></ul></ul><li><strong><font color=\"#b83d14\">Механизъм на действие</font></strong>:</li><ul><li><strong>Активиране на вътреклетъчни рецептори</strong> =&gt; <strong>геномни ефекти</strong> – бавни и продължителни.</li><li><strong>Негеномни ефекти</strong> – бързи, чрез <strong>мембранни рецептори</strong>.</li></ul></ul><ul style=\"white-space-collapse: preserve;\"><li><b><font color=\"#b83d14\">Ефекти, свързани с половата система:</font></b></li><ul><li>По време на <strong>менструалния цикъл</strong> е отговорен за промените в <strong>гениталния апарат</strong> през втората половина на цикъла.</li><ul><li>Стимулира <strong>секреторните промени в ендометриума</strong> и го подготвя за евентуална имплантация на оплодена яйцеклетка.</li><li>Прави цервикалния секрет негостоприемен за сперматозоида.</li><li>Потиска маточните контракции (протектор на бременността).</li></ul></ul><li><b><font color=\"#b83d14\">Ефекти, които не са свързани с половата система:</font></b></li><ul><li>Повишава телесната температура с около 0.5 °C.</li><li>Намалява инсулиновата чувствителност, повишава LDL.</li><li>Ефекти върху ЦНС – емоционални промени, повишаване на апетита.</li><li>Потиска имунитета.</li><li>Отрицателна обратна връзка с хипоталамуса и хипофизната жлеза –<b> потиска отделянето на гонадотропин-рилийзинг фактор и LH.</b></li></ul></ul><h3 style=\"white-space-collapse: preserve;\">Лекарства с гестагенна активност</h3><ul style=\"white-space-collapse: preserve;\"><li><strong><font color=\"#b83d14\">Представители</font></strong>:</li><ul><li><strong>Природен</strong> – <strong><font color=\"#7e22ce\"><i>progesterone</i></font></strong>.</li><li><strong>Синтетични</strong>:</li><ul><li>Производни на прогестерона – <strong><i><font color=\"#7e22ce\">medroxyprogesterone</font></i></strong>, <strong><i><font color=\"#7e22ce\">dydrogesterone</font></i></strong>.</li><li>Производни на 19-нортестостерон – <strong><i><font color=\"#7e22ce\">norethisterone</font></i></strong>, <strong><i><font color=\"#7e22ce\">levonorgestrel</font></i></strong>, <strong><i><font color=\"#7e22ce\">lynestrenol</font></i></strong>, <strong><i><font color=\"#7e22ce\">dienogest</font></i></strong>, <strong><i><font color=\"#7e22ce\">gestodene</font></i></strong>.</li><li>Производни на алдостерон – <strong><i><font color=\"#7e22ce\">drospirenone</font></i></strong>.</li></ul></ul><li><b><font color=\"#b83d14\">Фармакокинетика – висока липоразтворимост (стероидни хормони):</font></b></li><ul><li><b><font color=\"#b83d14\">Резорбция и пътища на приложение:</font></b></li><ul><li>Добра резорбция в ГИТ при перорално приложение.</li><li><font color=\"#7e22ce\"><i><strong>Progesteronе</strong> </i></font>подлежи на <strong>предсистемен метаболизъм</strong> =&gt; <strong>ниска бионаличност</strong> при орално приложение; възможност за <strong>локално вагинално приложение</strong>.</li><li><font color=\"#7e22ce\"><strong>Синтетичните</strong> </font>не подлежат на предсистемен метаболизъм и има <strong>добра бионаличност</strong> при орално приложение.</li><li><font color=\"#7e22ce\"><i><strong>Levonorgestrel</strong> </i></font>се прилага и <strong>локално</strong> включен във <strong>вътрематочна спирала</strong>.</li></ul></ul><li><b style=\"\"><font color=\"#b83d14\">Елиминация</font><font color=\"#000000\"> – </font></b><font color=\"#000000\" style=\"font-weight: bold;\">чернодробен метаболизъм.</font></li><li><b><font color=\"#b34019\">Механизъм на действие и ефекти</font>:</b></li><ul><li>Като на ендогенния <strong>прогестерон</strong>.</li><li><strong>Синтетичните</strong> притежават и известна <strong>андрогенна активност</strong> – без по-новите производни на 19-нортестостерон (<i><font color=\"#7e22ce\">dienogest</font></i>, <i><font color=\"#7e22ce\">gestodene</font></i>) и <i><font color=\"#7e22ce\">drospirenone</font></i>.</li></ul><li><b><font color=\"#ac3f1b\">Клинична употреба</font></b>:</li><ul><li>По време на <strong>бременност</strong> – <i><font color=\"#7e22ce\"><strong>progesterone</strong> </font></i>като <strong>протектор на бременността</strong> при жени с анамнеза за <strong>спонтанни аборти</strong>.</li><li>При жени в <strong>менопауза</strong> – <strong><i><font color=\"#7e22ce\">синтетични гестагени</font></i></strong> в <strong>комбинация с <i><font color=\"#7e22ce\">естрогени</font></i></strong><i><font color=\"#7e22ce\"> </font></i>за <strong>хормонална заместителна терапия</strong>.</li><li>При жени във <strong>фертилна възраст</strong> – използват се <i><font color=\"#7e22ce\"><strong>синтетичните</strong> </font></i>с цел <strong>контрацепция</strong>:</li><ul><li>В <strong>комбинация с естрогени</strong> (комбинирани орални контрацептиви).</li><li><strong>Самостоятелно</strong>:</li><ul><li>Перорално за <strong>продължително приложение</strong> (рядко).</li><li><u>Перорално за <strong>спешна контрацепция</strong> след непротектиран полов акт - <strong><i><font color=\"#7e22ce\">levonorgestrel</font></i></strong>.</u></li><li><strong>Локално</strong> – включени във вътрематочна спирала.</li></ul></ul></ul><li><b><font color=\"#b83d14\">Нежелани ефекти:</font></b></li><ul><li><strong>Промени в ЦНС</strong> – симптоми на пременструален синдром, промени в апетита, либидото, настроението.</li><li><strong>Нарушаване на менструалния цикъл</strong> – пробивно кървене.</li><li><strong>Гастроинтестинални оплаквания</strong>.</li><li><strong>Андрогенни нежелани ефекти</strong> – при синтетичните; </li><ul><li>Акне, хирзутизъм, задръжка на вода.</li><li><i><font color=\"#7e22ce\">Dienogest </font></i>и <i><font color=\"#7e22ce\">drospirenone </font></i>имат антиандрогенни ефекти и могат да се използват за благоприятно повлияване на акне и хирзутизъм.</li></ul></ul></ul><h3 style=\"white-space-collapse: preserve;\">Антипрогестини</h3><ul style=\"white-space-collapse: preserve;\"><li><strong><font color=\"#7e22ce\"><i>Mifepristone</i></font></strong>:</li><ul><li><strong><font color=\"#b83d14\">Механизъм на действие</font></strong>: </li><ul><li><strong>Антагонист</strong> на <strong>прогестероновите</strong> и <strong>глюкокортикоидните рецептори.</strong></li><li>Има <strong>лутеолитичен ефект</strong> – жълтото тяло дегенерира преждевременно =&gt; рязък спад в нивата на хормони =&gt; отлепване на ендометриума и начало на менструално кървене.</li></ul><li><strong><font color=\"#b83d14\">Клинично приложение</font></strong>:</li><ul><li><strong><u>Фармакологичен аборт</u></strong>: в ранните етапи на бременността, в <strong><u>комбинация с misoprostol</u></strong> (аналог на PGE1).</li><li><strong>Посткоитална контрацепция</strong> – до <b>120 часа</b> след непротектиран сексуален контакт.</li><li>При лечение на синдром на Cushing заради ефекта върху глюкокортикоидните рецептори.</li></ul><li><strong><font color=\"#b83d14\">НЛР</font></strong>: гастроинтестинални оплаквания; маточно кървене, понякога тежко; нарушаване на менструалния цикъл.</li></ul><li><strong><font color=\"#7e22ce\"><i>Ulipristal acetate</i></font></strong>:</li><ul><li><strong><font color=\"#b83d14\">Механизъм на действие</font></strong>: </li><ul><li><strong>Парциален агонист</strong> на <strong>прогестероновите рецептори</strong> (селективен прогестеронов рецепторен модулатор) =&gt; <strong>предотвратява овулацията</strong>, ако още не е настъпила; </li><li>Прави <b>ендометриума неподходящ за имплантация</b>.</li></ul><li><strong><font color=\"#b83d14\">Клинично приложение</font></strong>:</li><ul><li><strong>Посткоитална контрацепция</strong> – до <strong>120 часа</strong> след непротектиран сексуален контакт.</li><li>Маточни фиброиди.</li></ul><li><strong><font color=\"#b83d14\">НЛР</font></strong>: гастроинтестинални оплаквания, нарушаване на менструалния цикъл, хепатотоксичност при продължителна употреба (в терапията на маточни фиброиди).</li></ul></ul><h3 style=\"white-space-collapse: preserve;\"><hr></h3><h3 style=\"white-space-collapse: preserve;\">Видове хормонални контрацептиви</h3><ul style=\"\"><li><strong style=\"white-space-collapse: preserve;\"><font color=\"#7e22ce\" style=\"\">Комбинирани орални контрацептиви</font></strong><span style=\"white-space-collapse: preserve;\"> – комбинации от минимални дози </span><strong style=\"white-space-collapse: preserve;\">ethynilestradiol</strong><span style=\"white-space-collapse: preserve;\"> и </span><strong style=\"white-space-collapse: preserve;\">синтетичен гестаген</strong><span style=\"white-space-collapse: preserve;\"> с минимални андрогенни или антиандрогенни ефекти:</span></li><ul style=\"\"><li><strong style=\"white-space-collapse: preserve;\">Монофазни</strong><span style=\"white-space-collapse: preserve;\"> – всички таблетки съдържат </span><strong style=\"white-space-collapse: preserve;\">една и съща доза естроген и гестаген</strong><span style=\"white-space-collapse: preserve;\">; приемат се 21 дена, след което не се приемат 7 дена (или се приемат празни таблетки).</span></li><li><strong style=\"white-space-collapse: preserve;\">Трифазни</strong><span style=\"white-space-collapse: preserve;\"> – таблетките са разделени на 3 вида според дозата на </span><strong style=\"white-space-collapse: preserve;\">естрогена</strong><span style=\"white-space-collapse: preserve;\"> и </span><strong style=\"white-space-collapse: preserve;\">гестагена</strong><span style=\"white-space-collapse: preserve;\"> с цел имитация на физиологичните промени в хормоналните нива; + 7 празни таблетки.</span></li><li><b style=\"white-space-collapse: preserve;\"><font color=\"#b83d14\">Механизъм на действие:</font></b></li><ul style=\"\"><li><span style=\"white-space-collapse: preserve;\">Използва се </span><strong style=\"white-space-collapse: preserve;\">отрицателната обратна връзка</strong><span style=\"white-space-collapse: preserve;\"> между </span><span style=\"white-space-collapse: preserve;\">половите</span><span style=\"white-space-collapse: preserve;\"> и </span><span style=\"white-space-collapse: preserve;\">гонадотропните хормони</span><span style=\"white-space-collapse: preserve;\">.</span></li><li><strong style=\"white-space-collapse: preserve;\">Потиска се отделянето на FSH и LH</strong><span style=\"white-space-collapse: preserve;\">, което </span><strong style=\"white-space-collapse: preserve;\">предотвратява узряването на яйчниковия фоликул</strong><span style=\"white-space-collapse: preserve;\"> и </span><strong style=\"white-space-collapse: preserve;\">овулацията</strong><span style=\"white-space-collapse: preserve;\"> =&gt; </span><strong style=\"white-space-collapse: preserve;\">бременност не е възможна</strong><span style=\"white-space-collapse: preserve;\">.</span></li></ul><li><b style=\"white-space-collapse: preserve;\"><font color=\"#b83d14\">Допълнителни ползи:</font></b></li><ul style=\"\"><li><strong style=\"white-space-collapse: preserve;\">Менструалното кървене</strong><span style=\"white-space-collapse: preserve;\"> става </span><strong style=\"white-space-collapse: preserve;\">предвидимо</strong><span style=\"white-space-collapse: preserve;\">, </span><strong style=\"white-space-collapse: preserve;\">намалява кървенето</strong><span style=\"white-space-collapse: preserve;\"> и </span><strong style=\"white-space-collapse: preserve;\">болката</strong><span style=\"white-space-collapse: preserve;\">.</span></li><li><strong style=\"white-space-collapse: preserve;\">Намалява се рискът</strong><span style=\"white-space-collapse: preserve;\"> от </span><strong style=\"white-space-collapse: preserve;\">овариален</strong><span style=\"white-space-collapse: preserve;\"> и </span><strong style=\"white-space-collapse: preserve;\">ендометриален карцином</strong><span style=\"white-space-collapse: preserve;\">.</span></li></ul><li><span style=\"white-space-collapse: preserve;\"><b><font color=\"#b6421b\">Нежелани ефекти:</font></b></span></li><ul style=\"\"><li><font color=\"#dd0a0a\"><strong style=\"white-space-collapse: preserve;\">Увеличен риск</strong><span style=\"white-space-collapse: preserve;\"> от </span><strong style=\"white-space-collapse: preserve;\">венозни тромбози</strong></font><span style=\"white-space-collapse: preserve;\"> – по-висок риск при жени над 40-годишна възраст, </span><span style=\"white-space-collapse: preserve;\">тютюнопушене</span><span style=\"white-space-collapse: preserve;\">, </span><span style=\"white-space-collapse: preserve;\">затлъстяване</span><span style=\"white-space-collapse: preserve;\">, </span><span style=\"white-space-collapse: preserve;\">хипертония</span><span style=\"white-space-collapse: preserve;\">.</span></li><li><strong style=\"white-space-collapse: preserve;\">Увреждане на черния дроб</strong><span style=\"white-space-collapse: preserve;\"> – </span><span style=\"white-space-collapse: preserve;\">холестаза</span><span style=\"white-space-collapse: preserve;\">, </span><span style=\"white-space-collapse: preserve;\">холестатичен хепатит</span><span style=\"white-space-collapse: preserve;\"> (естрогени стимулират синтеза на жлъчни киселини).</span></li><li><strong style=\"white-space-collapse: preserve;\">Други</strong><span style=\"white-space-collapse: preserve;\"> – </span><span style=\"white-space-collapse: preserve;\">напрежение в гърдите</span><span style=\"white-space-collapse: preserve;\">, </span><span style=\"white-space-collapse: preserve;\">главоболие</span><span style=\"white-space-collapse: preserve;\">, </span><span style=\"white-space-collapse: preserve;\">андрогенни нежелани ефекти</span><span style=\"white-space-collapse: preserve;\"> (повишаване на апетита, акне, хирзутизъм – проблем при по-старите препарати).</span></li></ul><li><b style=\"white-space-collapse: preserve;\"><font color=\"#b83d14\">Лекарствени взаимодействия:</font></b></li><ul style=\"\"><li><span style=\"white-space-collapse: preserve;\">При едновременна употреба на </span><strong style=\"white-space-collapse: preserve;\">ензимни индуктори</strong><span style=\"white-space-collapse: preserve;\"> (<i><font color=\"#7e22ce\">rifampicin</font></i>) ефектът им </span><span style=\"white-space-collapse: preserve;\">намалява</span><span style=\"white-space-collapse: preserve;\"> – </span><strong style=\"white-space-collapse: preserve;\">риск от забременяване</strong><span style=\"white-space-collapse: preserve;\">.</span></li><li><span style=\"white-space-collapse: preserve;\">При употреба на </span><strong style=\"white-space-collapse: preserve;\">широкоспектърни антибиотици</strong><span style=\"white-space-collapse: preserve;\"> може да се развие </span><strong style=\"white-space-collapse: preserve;\">дисбактериоза</strong><span style=\"white-space-collapse: preserve;\">, което </span><span style=\"white-space-collapse: preserve;\"><b>нарушава ентерохепаталния кръговрат</b></span><span style=\"white-space-collapse: preserve;\"> – </span><strong style=\"white-space-collapse: preserve;\">риск от забременяване</strong><span style=\"white-space-collapse: preserve;\">.</span></li></ul><li><span style=\"white-space-collapse: preserve;\"><p><font color=\"#7e22ce\"><b>Синтетични гестагени</b></font> <b>самостоятелно </b>като редовна терапия или спешна контрацепция.</p></span></li><ul><li><span style=\"white-space-collapse: preserve;\"><p>Разчита се на <strong>предотвратяване на овулацията</strong> и на <strong>локални промени</strong> в <strong>гениталния апарат</strong>, които правят средата <strong>неблагоприятна</strong> за оплождане и евентуално имплантиране на оплодената яйцеклетка.</p></span></li></ul></ul></ul><h3 style=\"white-space-collapse: preserve;\">Хормонална заместителна терапия (ХЗТ)</h3><ul style=\"white-space-collapse: preserve;\"><li><b><font color=\"#b83d14\">Цел на терапията:</font></b></li><ul><li>Повлияване на <strong>симптомите на менопауза</strong> – вазомоторни симптоми, вагинални оплаквания (дискомфорт, сухота), емоционални нарушения, депресия, безсъние.</li><li>Предотвратяване на бързата загуба на костна тъкан – <b>предотвратяване развитието на </b><strong>остеопороза</strong>.</li></ul><li><b><font color=\"#b83d14\">Форми на терапия:</font></b></li><ul><li><strong>Системна терапия с <font color=\"#7e22ce\">естроген </font>+ <font color=\"#7e22ce\">гестаген</font></strong>:</li><ul><li><b>Ежедневен орален прием</b> – в началото терапията може да бъде <strong>циклична</strong> (21 дена + 7 дена празни таблетки) =&gt; циклично кървене, наподобява менструалния цикъл; при непрекъснато приложение – липса на кървене.</li><li><font color=\"#7e22ce\"><strong>Естрогенът</strong> </font>постига целите на терапията – подобрява симптомите и предотвратява <strong>остеопорозата</strong>.</li><li><font color=\"#7e22ce\"><strong style=\"\">Гестагенът</strong> </font>цели да премахне <strong>пролиферативния ефект</strong> на естрогена в <strong>ендометриума</strong> =&gt; предотвратява развитието на <strong>рак на ендометриума</strong>.</li></ul><li><strong>Системна терапия само с <font color=\"#7e22ce\">естроген</font></strong><font color=\"#7e22ce\"> </font>– при <strong>хистеректомирани жени </strong>(<font color=\"#65a30d\">нямат матка, че да има рак на матката</font>); <i><font color=\"#7e22ce\">estradiol </font></i>под формата на <strong>TTS</strong>.</li><li><strong>Локално приложение</strong> – при наличие само на <strong>локални вагинални оплаквания</strong>; <i style=\"\"><font color=\"#7e22ce\" style=\"\">естрогени</font></i> под форми за <strong>вагинално приложение</strong>.</li><li><i><font color=\"#7e22ce\"><b>Raloxifene </b></font></i>– ако единствената причина за терапия е <strong>рискът от остеопороза</strong>.</li></ul><li><b><font color=\"#b83d14\">Рискове:</font></b></li><ul><li><font color=\"#dd0a0a\"><strong>Повишен риск</strong> от <strong>рак на млечна жлеза</strong></font>.</li><li><strong>Повишен риск</strong> от <strong>рак на ендометриум</strong> – <strong>не</strong> и при <strong>комбиниране с гестаген</strong>.</li><li><font color=\"#dd0a0a\"><strong>Повишен риск</strong> от <strong>тромбози</strong></font>.</li><li><strong>Препоръка</strong> – системната терапия да се използва в <strong>минимални ефективни дози</strong> за <strong>възможно най-кратък период от време</strong>.</li></ul><li><font color=\"#7e22ce\"><i><b>Tibolone</b></i></font></li><ul><li><strong><font color=\"#b83d14\">Механизъм на действие</font></strong>: <b>синтетичен стероиден про-хормон</b>, който в организма се метаболизира до <strong>три активни метаболита</strong> с <strong>естрогенна</strong>, <strong>прогестогенна</strong> и <strong>андрогенна активност</strong>.</li><li><font color=\"#b83d14\"><strong>Ефекти</strong>:</font></li><ul><li><strong>Подобрява симптомите на менопауза</strong> – заради <strong>естрогенната активност</strong>.</li><li><strong>Предотвратява риска от остеопороза</strong> – заради <strong>естрогенната</strong> и <strong>андрогенната активност</strong>.</li><li><strong>Подобрява либидото</strong> – заради <strong>андрогенната активност</strong>.</li></ul><li><font color=\"#c14015\"><strong style=\"\">В сравнение с класическата системна терапия</strong>:</font></li><ul><li><strong>По-малък риск</strong> от <strong>рак на млечна жлеза</strong>.</li><li>По-малък риск от рак на ендометриума (в сравнение с естроген самостоятелно).</li><li><strong><font color=\"#dd0a0a\">Еднакво повишен риск</font></strong><font color=\"#dd0a0a\"> от </font><strong><font color=\"#dd0a0a\">тромбози</font></strong>.</li></ul></ul></ul><h3 style=\"white-space-collapse: preserve;\"><hr></h3><h3 style=\"white-space-collapse: preserve;\">Мъжки полови хормони</h3><ul style=\"white-space-collapse: preserve;\"><li>Основният ендогенен андроген е <strong>тестостeронът</strong>.</li><li><b><font color=\"#b83d14\">Синтез и секреция:</font></b></li><ul><li>Изходна суровина - <strong>холестерол</strong>.</li><li>Произвежда се в <strong>тестисите</strong> под въздействието на <strong>лутеинизиращия хормон</strong>.</li><li>Малки количества се произвеждат в яйчниците и кората на надбъбречната жлеза.</li></ul><li><b><font color=\"#c14015\">Механизъм на действие</font>:</b></li><ul><li>В повечето клетки се превръща вътреклетъчно в дихитротестостерон от ензима 5α-редуктаза.</li><li>Активиране на <strong>вътреклетъчни рецептори</strong> – <strong>геномни ефекти</strong>.</li></ul><li><b><font color=\"#b83d14\">Ефекти, свързани с половата система:</font></b></li><ul><li>Оформяне на <strong>мъжкия генитален тракт</strong> по време на ембрионалното развитие.</li><li>Развитие на <strong>половите белези</strong> по време на пубертета.</li></ul><li><b><font color=\"#b83d14\">Ефекти, несвързани с половата система:</font></b></li><ul><li><strong>Анаболен ефект</strong><b> в </b><strong>скелетните мускули</strong> – стимулира синтеза на протеини и увеличава мускулната сила и издръжливост.</li><li><b>В костната тъкан стимулира костното формиране;</b> по време на пубертета стимулира растежа на <strong>дългите кости</strong> и <strong>затварянето на епифизарните плочки</strong>.</li><li><strong>Влошава липидния профил</strong>.</li><li><b>Води до </b><strong>задръжка на натрий и вода</strong>.</li><li>Повишава образуването на себум – <strong>акне</strong>.</li><li><strong>Стимулира производството на еритроцити</strong>.</li><li>Има <strong>поведенчески ефекти в ЦНС</strong> – отговорен за т.нар. „мъжки тип“ поведение, повишава либидото, повишава агресивността.</li><li><strong>Отрицателна обратна връзка</strong> с хипоталамуса и хипофизната жлеза – потиска отделянето на <strong>гонадотропин-рилийзинг фактор</strong> и <strong>гонадотропни хормони</strong>.</li></ul></ul><h3 style=\"white-space-collapse: preserve;\">Лекарства с активност на мъжки полови хормони</h3><ul style=\"white-space-collapse: preserve;\"><li><strong><font color=\"#7e22ce\"><i>Testosterone</i></font></strong>:</li><ul><li>Идентичен на ендогенния хормон.</li><li><font color=\"#b83d14\"><strong>Фармакокинетика</strong> </font>– <strong>предсистемен метаболизъм</strong> при орално приложение =&gt; <strong>ниска орална бионаличност</strong>; прилага се <strong>инжекционно</strong> или локално под формата на гел.</li><li><font color=\"#b83d14\"><strong>Приложение</strong> </font>– за <strong>заместителна терапия</strong> при <strong><font color=\"#3b82f6\">хипогонадизъм</font></strong>.</li></ul><li><strong>Анаболни стероиди</strong> - <i><font color=\"#7e22ce\"><b>Nandrolone</b></font></i>.</li><ul><li>Производни на <strong>андрогените</strong>, които имат <strong>засилен анаболен ефект</strong>.</li><li><strong>Не са разрешени за употреба</strong> и <strong>нямат официално клинично приложение</strong>.</li><li>Използват се за <strong>злоупотреба</strong> с цел увеличаване на мускулната маса и физическата сила и съответно подобряване на представянето в състезания (<strong>допинг</strong>).</li><li><strong><font color=\"#b83d14\">Нежелани ефекти и рискове</font></strong>:</li><ul><li><strong>Хипертрофия на сърцето</strong> и развитие на <strong>сърдечна недостатъчност</strong>.</li><li><strong>Артериална хипертония</strong> и развитие на <strong>атеросклероза</strong>, риск от остър миокарден инфаркт.</li><li>Акне.</li><li><strong>Атрофия на тестисите</strong>, <strong>инфертилитет</strong> – заради <strong>отрицателната обратна връзка</strong> с <strong>хипоталамуса</strong> и <strong>хипофизата</strong>.</li><li><strong>Промени в поведението</strong> (<strong>агресивно поведение</strong>), възможно развитие на <strong>зависимост</strong>.</li><li><strong>Увреждане на черния дроб</strong>, риск от <strong>рак на черния дроб</strong>.</li></ul></ul></ul><h3 style=\"white-space-collapse: preserve;\">Антиандрогени</h3><ul style=\"\"><li style=\"white-space-collapse: preserve;\"><strong><font color=\"#7e22ce\"><i>Cyproterone</i></font></strong>:</li><ul style=\"white-space-collapse: preserve;\"><li><strong><font color=\"#b83d14\">Механизъм на действие</font></strong>: <font color=\"#dd0a0a\"><strong>антагонист</strong> </font>на <strong>андрогенните рецептори</strong>, <strong>прогестагенна активност</strong> (потиска отделянето на гонадотропните хипофизарни хормони, което <strong>засилва антиандрогенния ефект</strong>).</li><li><strong><font color=\"#b83d14\">Клинична употреба</font></strong>: <strong>хирзутизъм</strong> при жени, <strong>хиперсексуалност</strong> при мъже.</li><li><strong><font color=\"#b83d14\">Нежелани ефекти</font></strong>: хепатотоксичност, менструални смущения при жени, сексуални смущения (намалено либидо, еректилна дисфункция) и гинекомастия при мъже.</li></ul><li style=\"white-space-collapse: preserve;\"><strong><font color=\"#7e22ce\"><i>Flutamide</i></font></strong>:</li><ul style=\"white-space-collapse: preserve;\"><li><strong><font color=\"#b83d14\">Механизъм на действие</font></strong>: <strong>конкурентен <font color=\"#dd0a0a\">антагонист</font></strong><font color=\"#dd0a0a\"> </font>на <strong>андрогенните рецептори</strong>.</li><li><strong><font color=\"#b83d14\">Клинична употреба</font></strong>: тестостерон-чувствителни тумори, напр. <strong><font color=\"#3b82f6\">карцином на простатата</font></strong>.</li><li><strong><font color=\"#b83d14\">Нежелани ефекти</font></strong>: сексуални смущения, гинекомастия, риск от остеопороза.</li></ul><li style=\"white-space-collapse: preserve;\"><strong><font color=\"#7e22ce\"><i>Finasteride</i></font></strong>:</li><ul style=\"white-space-collapse: preserve;\"><li><strong><font color=\"#b83d14\">Механизъм на действие</font></strong>:<font color=\"#dd0a0a\"> <strong>инхибитор на 5α-редуктазата</strong></font> =&gt; <font color=\"#3b82f6\">предотвратяват превръщането на <strong>тестостерон</strong> в <strong>дихидростестостерон</strong></font>.</li><li><strong><font color=\"#b83d14\">Клинична употреба</font></strong>: <strong>доброкачествена простатна хиперплазия</strong>, <strong>оплешивяване (алопеция)</strong>.</li><li><strong><font color=\"#b83d14\">Нежелани ефекти</font></strong>: сексуални смущения.</li></ul><li style=\"\"><span style=\"white-space-collapse: preserve;\"><b>Инхибитори на тестостероновата синтеза</b>: <i><font color=\"#7e22ce\">гонадорелени</font></i>, <i><font color=\"#7e22ce\">реликси</font></i>, <i><font color=\"#7e22ce\">ketoconazole</font></i></span></li></ul><br><br>\r\n<h1 style=\"font-size: 1.5em;\">Кортикостероиди</h1><ul><li style=\"font-size: 1em;\"><strong>Надбъбрекът</strong> секретира смес от <strong>глюкокортикостероиди (ГКС)</strong>; главният хормон при хората е хидрокортизон (<strong>кортизол</strong>).</li><li style=\"font-size: 1em;\"><strong>Минералкортикоидите (МКС)</strong> регулират <strong>водния</strong> и <strong>електролитен баланс</strong>; главният ендогенен хормон е <strong>алдостерон</strong>.</li><li style=\"font-size: 1em;\">При дефицит на кортикостероиди се развива <strong>Адисонова болест</strong>.</li><li style=\"font-size: 1em;\">При свръхпродукция на кортикостероиди се развива <strong>синдром на Кушинг</strong>.</li></ul><h3 style=\"font-size: 1.1em;\">Глюкокортикостероиди (ГКС)</h3><h4 style=\"font-size: 1.05em;\">Синтез и освобождаване&nbsp;</h4><ul><li style=\"font-size: 1em;\"><strong>ГКС</strong> се синтезират под влиянието на циркулиращия <strong>АКТХ</strong> (от предния дял на <strong>хипофизата</strong>).</li><li style=\"font-size: 1em;\">Има <strong>циркаден ритъм</strong> в секрецията:</li><ul><li style=\"font-size: 1em;\">Кръвната концентрация е най-висока рано сутрин.</li><li style=\"font-size: 1em;\">Намалява през деня и достига най-ниско ниво през нощта.</li></ul><li style=\"font-size: 1em;\">Секрецията на <strong>АКТХ</strong> (също с пулсов характер) се регулира от <strong>КРФ</strong> от <strong>хипоталамуса</strong>.</li><li style=\"font-size: 1em;\">Отделянето на <strong>АКТХ</strong> и <strong>КРФ</strong> се <strong>инхибира</strong> от повишените концентрации на <strong>ГКС</strong> в кръвта (<strong>отрицателна обратна връзка</strong>).</li><li style=\"font-size: 1em;\">Така се формира <strong>ос хипоталамус-хипофиза-надбъбреци</strong>.</li></ul><h3 style=\"font-size: 1.1em;\">Сравнителна таблица на КС</h3><table><thead><tr><th style=\"font-size: 1em;\">Група/лекарства</th><th style=\"text-align: center; font-size: 1em;\">ГКС активност</th><th style=\"text-align: center; font-size: 1em;\">МКС активност</th><th style=\"text-align: center; font-size: 1em;\">Еквивалентни дози</th></tr></thead><tbody><tr><td rowspan=\"2\" style=\"font-size: 1em;\">Кратко действащи (8-12 h)<br><i><font color=\"#7e22ce\">Cortisol</font></i></td><td rowspan=\"2\" style=\"font-size: 1em;\"><br><div style=\"text-align: center;\">1</div></td><td rowspan=\"2\" style=\"font-size: 1em;\"><div style=\"text-align: center;\"><br></div><div style=\"text-align: center;\">1</div></td><td rowspan=\"2\" style=\"font-size: 1em;\"><div style=\"text-align: center;\"><br></div><div style=\"text-align: center;\">20 mg</div></td></tr><tr></tr><tr><td rowspan=\"4\" style=\"font-size: 1em;\">Със средна продължителност (18-36 h)<br><i><font color=\"#7e22ce\">Prednisone<br>Prednisolone<br>Methylprednisolone</font></i></td><td rowspan=\"4\" style=\"font-size: 1em;\"><br><div style=\"text-align: center;\">4</div><div style=\"text-align: center;\">4</div><div style=\"text-align: center;\">5</div></td><td rowspan=\"4\" style=\"font-size: 1em;\"><div style=\"text-align: center;\"><br></div><div style=\"text-align: center;\">0.5</div><div style=\"text-align: center;\">0.5</div><div style=\"text-align: center;\">0.3</div></td><td rowspan=\"4\" style=\"font-size: 1em;\"><div style=\"text-align: center;\"><br></div><div style=\"text-align: center;\">5 mg</div><div style=\"text-align: center;\">5 mg</div><div style=\"text-align: center;\">4 mg</div></td></tr><tr></tr><tr></tr><tr></tr><tr><td rowspan=\"3\" style=\"font-size: 1em;\">Дълго действащи (36-54 h)<br><i><font color=\"#7e22ce\">Dexamethasone<br>Betamethasone</font></i></td><td rowspan=\"3\" style=\"font-size: 1em;\"><br><div style=\"text-align: center;\">25</div><div style=\"text-align: center;\">30</div></td><td rowspan=\"3\" style=\"font-size: 1em;\"><div style=\"text-align: center;\"><br></div><div style=\"text-align: center;\">0</div><div style=\"text-align: center;\">0</div></td><td rowspan=\"3\" style=\"font-size: 1em;\"><div style=\"text-align: center;\"><br></div><div style=\"text-align: center;\">0.8 mg</div><div style=\"text-align: center;\">0.8 mg</div></td></tr><tr></tr><tr></tr><tr><td style=\"font-size: 1em;\">МКС: <i><font color=\"#7e22ce\">Fludrocortisone</font></i></td><td style=\"text-align: center; font-size: 1em;\">5-40</td><td style=\"text-align: center; font-size: 1em;\">125</td><td style=\"text-align: center; font-size: 1em;\">2 mg</td></tr><tr><td style=\"font-size: 1em;\"><i><font color=\"#7e22ce\">Aldosterone</font></i></td><td style=\"text-align: center; font-size: 1em;\">-</td><td style=\"text-align: center; font-size: 1em;\">500</td><td style=\"text-align: center; font-size: 1em;\">Ендогенен</td></tr></tbody></table><h3 style=\"font-size: 1.1em;\">КС - класификация</h3><ol><li style=\"font-size: 1em;\"><strong>Лекарства с активност на глюкокортикостероиди</strong>:</li><ul><li style=\"font-size: 1em;\"><strong>а. за системно приложение</strong>:</li><ul><li style=\"font-size: 1em;\">С <strong>натрий-задържащ ефект</strong>:</li><ul><li style=\"font-size: 1em;\"><strong><i><font color=\"#7e22ce\">Prednisone</font></i></strong></li><li style=\"font-size: 1em;\"><strong><i><font color=\"#7e22ce\">Prednisolone</font></i></strong></li><li style=\"font-size: 1em;\"><strong><i><font color=\"#7e22ce\">Methylprednisolone</font></i></strong></li></ul><li style=\"font-size: 1em;\">Без <strong>натрий-задържащ ефект</strong>:</li><ul><li style=\"font-size: 1em;\"><strong><i><font color=\"#7e22ce\">Betamethasone</font></i></strong></li><li style=\"font-size: 1em;\"><strong><i><font color=\"#7e22ce\">Dexamethasone</font></i></strong></li></ul></ul><li style=\"font-size: 1em;\"><strong>б. за локално приложение</strong>:</li><ul><li style=\"font-size: 1em;\">В <strong>дерматологията</strong>:</li><ul><li style=\"font-size: 1em;\"><strong><i><font color=\"#7e22ce\">Betamethasone</font></i></strong></li><li style=\"font-size: 1em;\"><strong><i><font color=\"#7e22ce\">Fluocinolone</font></i></strong></li><li style=\"font-size: 1em;\"><strong><i><font color=\"#7e22ce\">Clobetasol</font></i></strong></li></ul><li style=\"font-size: 1em;\">В <b>колопрактологията:</b></li><ul><li style=\"font-size: 1em;\"><b><p style=\"font-size: 1em;\"><i><font color=\"#7e22ce\">Budesonide</font></i></p></b></li></ul><li style=\"font-size: 1em;\">В <strong>офталмологията</strong>:</li><ul><li style=\"font-size: 1em;\"><strong><i><font color=\"#7e22ce\">Dexamethasone</font></i></strong></li></ul><li style=\"font-size: 1em;\">В <strong>ринологията</strong>:</li><ul><li style=\"font-size: 1em;\"><strong><i><font color=\"#7e22ce\">Mometasone</font></i></strong></li></ul><li style=\"font-size: 1em;\">В <strong>пулмологията</strong>:</li><ul><li style=\"font-size: 1em;\"><strong><i><font color=\"#7e22ce\">Beclometasone</font></i></strong></li><li style=\"font-size: 1em;\"><strong><i><font color=\"#7e22ce\">Fluticasone</font></i></strong></li><li style=\"font-size: 1em;\"><strong><i><font color=\"#7e22ce\">Budesonide</font></i></strong></li></ul></ul></ul><li style=\"font-size: 1em;\"><strong>Лекарства с активност на минералкортикостероиди</strong>:</li><ul><li style=\"font-size: 1em;\"><strong><i><font color=\"#7e22ce\">Fludrocortisone</font></i></strong></li></ul></ol><h3 style=\"font-size: 1.1em;\">Основни метаболитни ефекти</h3><ul><li style=\"font-size: 1em;\"><strong>Въглехидрати</strong>: <font color=\"#3b82f6\"><strong>хипергликемия</strong> </font>поради:</li><ul><li style=\"font-size: 1em;\">Намалено поемане и използване на <strong>глюкозата</strong>.</li><li style=\"font-size: 1em;\">Повишена <strong>глюконеогенеза</strong>.</li></ul><li style=\"font-size: 1em;\"><strong>Белтъци</strong>: <strong><font color=\"#3b82f6\">повишен катаболизъм</font></strong>, <strong><font color=\"#3b82f6\">понижен анаболизъм</font></strong>.</li><li style=\"font-size: 1em;\"><strong>Липиди</strong>: <strong><font color=\"#3b82f6\">преразпределение на мазнините</font></strong> както при <strong>синдром на Кушинг</strong>.</li><li style=\"font-size: 1em;\"><strong>Отрицателен калциев баланс</strong> – <strong><font color=\"#3b82f6\">остеопороза</font></strong>:</li><ul><li style=\"font-size: 1em;\"><font color=\"#3b82f6\"><p style=\"font-size: 1em;\">↓</p> <strong>Ca2+ абсорбция</strong> в <b>ГИТ</b></font>.</li><li style=\"font-size: 1em;\"><font color=\"#3b82f6\"><p style=\"font-size: 1em;\">↑</p> <strong>Ca2+ екскреция</strong> чрез <strong>бъбреците</strong>.</font></li></ul><li style=\"font-size: 1em;\"><strong>Минералкортикоидно действие</strong>:</li><ul><li style=\"font-size: 1em;\"><font color=\"#3b82f6\"><strong>Na+ ретенция</strong> и <strong>K+ загуба</strong></font>.</li></ul></ul><h3 style=\"font-size: 1.1em;\">Отрицателна обратна връзка</h3><ul><li style=\"font-size: 1em;\">В <strong>предната хипофиза</strong> и <strong>хипоталамуса</strong>:</li><ul><li style=\"font-size: 1em;\"><strong>Екзогенните ГКС</strong> потискат секрецията на <strong>КРФ</strong> и <strong>АКТХ</strong>.</li><li style=\"font-size: 1em;\">Това води до <strong>потискане на секрецията на ендогенните ГКС</strong>.</li><li style=\"font-size: 1em;\">Възниква <strong>атрофия на надбъбречната кора</strong>.</li></ul></ul><h3 style=\"font-size: 1.1em;\">Противовъзпалителен и имуносупресивен ефект</h3><ul><li style=\"font-size: 1em;\"><strong>ГКС</strong> инхибират както <strong>ранните</strong>, така и <strong>късните прояви на възпалението</strong>:</li><ul><li style=\"font-size: 1em;\">Началното зачервяване, болка, температура и оток.</li><li style=\"font-size: 1em;\">Късните фази на заздравяване на раните и пролиферативните реакции, които се наблюдават при хронично възпаление.</li></ul><li style=\"font-size: 1em;\"><strong>ГКС</strong> потискат <strong>инициацията</strong> и <strong>генерирането на имунен отговор</strong>.</li></ul><h3 style=\"font-size: 1.1em;\">Действия върху възпалителни и други клетки</h3><ul><li style=\"font-size: 1em;\"><strong>Неутрофили и други възпалителни клетки</strong>:</li><ul><li style=\"font-size: 1em;\">Намалено излизане на неутрофили от кръвоносните съдове и намалена активация на неутрофили, макрофаги и мастоцити вследствие намаляване на транскрипцията на гените на <strong>клетъчни адхезионни фактори</strong> и <strong>цитокини</strong>.</li><ul><li style=\"font-size: 1em;\">Обяснение: <strong>неутрофилите</strong> се прикрепват слабо за ендотела чрез селектини (E-selectin, P-selectin), които се експресират по повърхността на ендотелните клетки под влияние на цитокини (напр. TNF-α, IL-1).</li></ul></ul><li style=\"font-size: 1em;\"><strong>T клетки</strong>:</li><ul><li style=\"font-size: 1em;\">Намалено активиране на <strong>Т-хелперни (Th) клетки</strong>.</li></ul><li style=\"font-size: 1em;\"><strong>Фибробласти</strong>:</li><ul><li style=\"font-size: 1em;\">Намаляване на функцията на <strong>фибробластите</strong>, по-малко производство на колаген и гликозаминогликани и по този начин се <strong>забавя заздравяването на раните</strong>.</li></ul><li style=\"font-size: 1em;\"><strong>Остеобласти и остеокласти</strong>:</li><ul><li style=\"font-size: 1em;\">Намалена активност на <strong>остеобласти</strong> и увеличено активиране на <strong>остеокластите</strong> и следователно тенденция за развитие на <strong>остеопороза</strong>.</li></ul></ul><h3 style=\"font-size: 1.1em;\">Действие върху медиатори на възпалителни и имунни отговори</h3><ul><li style=\"font-size: 1em;\"><strong>Простаноиди</strong>:</li><ul><li style=\"font-size: 1em;\"><p><i>Oбщ термин за група биологично активни вещества, получени от арахидонова киселина чрез циклооксигеназния (COX) път</i>.</p></li><li style=\"font-size: 1em;\">Намалено производството на <strong>простаноиди</strong> поради намалена експресия на <strong>СОХ-2</strong>.</li></ul><li style=\"font-size: 1em;\"><strong>Цитокини</strong>:</li><ul><li style=\"font-size: 1em;\">Намалено производството на <strong>IL-1</strong>, <strong>IL-2</strong>, <strong>IL-3</strong>, <strong>IL-4</strong>, <strong>IL-5</strong>, <strong>IL-6</strong>, <strong>IL-8</strong>, <strong>TNF-α</strong> и т.н., вследствие на инхибиране на генната транскрипция.</li></ul><li style=\"font-size: 1em;\"><strong>Хистамин</strong>:</li><ul><li style=\"font-size: 1em;\">Намалено освобождаването от <strong>базофили</strong> и <strong>мастоцити</strong>.</li></ul><li style=\"font-size: 1em;\"><strong>IgG</strong>:</li><ul><li style=\"font-size: 1em;\"><strong>Понижено образуване</strong>.</li></ul><li style=\"font-size: 1em;\"><strong>Анексин-1 (липокортин)</strong> (инхибитор на <strong>фосфолипаза A2</strong>) и <strong>IL-10</strong>:</li><ul><li style=\"font-size: 1em;\"><strong>Повишена синтеза</strong>.</li></ul></ul><p><img src=\"https://files.coursebook.lol/Coursebook%20Assets/2026-05-05/coursebook-assets/assets/%D0%93%D0%9A%D0%A1%D0%A4%D0%B0%D1%80%D0%BC%D0%B0%D0%BA.png\" alt=\"ГКСФармак.png\" data-original-src=\"https://files.coursebook.lol/Coursebook%20Assets/2026-05-05/coursebook-assets/assets/%D0%93%D0%9A%D0%A1%D0%A4%D0%B0%D1%80%D0%BC%D0%B0%D0%BA.png\" style=\"max-width: 100%; height: auto;\"><br></p><h3 style=\"font-size: 1.1em;\">Механизъм на действие</h3><ul><li style=\"font-size: 1em;\"><strong>Глюкокортикостероидите</strong> се свързват с <strong><font color=\"#3b82f6\">вътреклетъчни рецептори</font></strong>, които след това се димеризират, мигрират към ядрото и взаимодействат с ДНК, за да <strong>променят генната транскрипция.</strong></li><li style=\"font-size: 1em;\"><strong>Противовъзпалителни и имуносупресивни действия</strong>:</li><ul><li style=\"font-size: 1em;\"><strong>Инхибиране на транскрипцията</strong> на гените за <strong>индуцируема СОХ-2</strong>, <strong>цитокини</strong> и <strong>интерлевкини</strong>, <strong>клетъчни адхезионни молекули</strong>.</li><li style=\"font-size: 1em;\"><strong>Увеличена синтеза и освобождаване</strong> на <strong>анексин-1</strong>.</li></ul></ul><h3 style=\"font-size: 1.1em;\">Нежелани ефекти</h3><ul><li style=\"font-size: 1em;\"><strong>Ефекти върху имунната система и зарастването</strong>:</li><ul><li style=\"font-size: 1em;\"><font color=\"#3b82f6\"><strong>Потискане на отговора</strong> </font>към <font color=\"#3b82f6\"><strong>инфекция</strong> </font>или <strong><font color=\"#3b82f6\">нараняване</font></strong>.</li></ul><li style=\"font-size: 1em;\"><strong>Метаболитни и ендокринни ефекти</strong>:</li><ul><li style=\"font-size: 1em;\"><strong><font color=\"#3b82f6\">Остеопороза</font></strong>.</li><li style=\"font-size: 1em;\"><strong><font color=\"#3b82f6\">Хипергликемия</font></strong>.</li><li style=\"font-size: 1em;\"><strong>Задържане на течности</strong>, <strong><font color=\"#3b82f6\">хипертония</font></strong>.</li><li style=\"font-size: 1em;\"><strong><font color=\"#3b82f6\">Загуба на мускулна маса</font></strong> и <strong><font color=\"#3b82f6\">мускулна слабост</font></strong>.</li><li style=\"font-size: 1em;\">При деца <strong><font color=\"#3b82f6\">забавяне на растежа</font></strong>, ако лечението продължава повече от 6 месеца.</li></ul><li style=\"font-size: 1em;\"><strong>Ефекти върху ЦНС</strong>:</li><ul><li style=\"font-size: 1em;\">Еуфория, депресия и психоза.</li></ul><li style=\"font-size: 1em;\"><strong>Дерматологични и физически промени (<font color=\"#3b82f6\">Синдром на Кушинг</font>)</strong>:</li><ul><li style=\"font-size: 1em;\">Натрупване на <strong>масти</strong> (<strong>лице</strong>, отзад на <strong>шията</strong>).</li><li style=\"font-size: 1em;\"><strong>Хирзутизъм</strong>.</li><li style=\"font-size: 1em;\"><strong>Червени стрии</strong>.</li><li style=\"font-size: 1em;\">Лесно <strong>насиняване</strong>, <strong>петехии</strong>.</li></ul><li style=\"font-size: 1em;\"><strong>Гастроинтестинални ефекти</strong>:</li><ul><li style=\"font-size: 1em;\">Улцерогенен ефект.&nbsp;</li></ul><li><strong style=\"font-size: 1em;\">Очни ефекти</strong><span style=\"font-size: 1em;\">:</span></li><ul><li style=\"font-size: 1em;\"><strong>Глаукома</strong> (в генетично предразположени лица).</li><li style=\"font-size: 1em;\">Повишена честота на <strong>катаракта</strong>.</li></ul><li style=\"font-size: 1em;\"><strong><font color=\"#3b82f6\">Остра надбъбречна недостатъчност</font></strong>:</li><ul><li style=\"font-size: 1em;\">Възниква при <strong>внезапно спиране на лекарствата</strong> след продължителна терапия.</li></ul></ul><h3 style=\"font-size: 1.1em;\">Клинична употреба на ГКС</h3><ul><li style=\"font-size: 1em;\"><strong>Заместителна терапия</strong>:</li><ul><li style=\"font-size: 1em;\">При пациенти с <strong>надбъбречна недостатъчност</strong> (<strong><font color=\"#dd0a0a\">болест на Адисон</font></strong>).</li></ul><li style=\"font-size: 1em;\"><strong>Противовъзпалителна и имуносупресивна терапия</strong>:</li><ul><li style=\"font-size: 1em;\">При <strong>бронхиална астма</strong>.</li><li style=\"font-size: 1em;\"><strong>Локално</strong> при различни възпалителни и алергични заболявания на кожата, очите, ушите или носа (например екзема, алергичен конюнктивит и ринит).</li><li style=\"font-size: 1em;\">При различни заболявания с <strong>автоимунна и възпалителна патогенеза</strong>:</li><ul><li style=\"font-size: 1em;\"><strong>Ревматоиден артрит</strong> и други заболявания на <strong>съединителната тъкан</strong>.</li><li style=\"font-size: 1em;\"><strong>Възпалителни заболявания на червата</strong>.</li><li style=\"font-size: 1em;\">Някои форми на <strong>хемолитична анемия</strong>.</li><li style=\"font-size: 1em;\"><strong>Идиопатична тромбоцитопенична пурпура</strong>.</li></ul><li style=\"font-size: 1em;\">За <strong>предотвратяване на реакцията на отхвърляне</strong> след органна или костно-мозъчна трансплантация.</li></ul><li style=\"font-size: 1em;\"><strong>При неопластични заболявания</strong>:</li><ul><li style=\"font-size: 1em;\">В комбинация с <strong>цитотоксични лекарства</strong> при лечението на някои злокачествени заболявания:</li><ul><li style=\"font-size: 1em;\">Болест на Ходжкин.</li><li style=\"font-size: 1em;\">Остра лимфоцитна левкемия.</li></ul><li style=\"font-size: 1em;\">За намаляване на оток на мозъка при пациенти с метастазирал или първичен тумор на мозъка (<i><font color=\"#7e22ce\">dexamethasone</font></i>).</li></ul><li style=\"font-size: 1em;\"><strong>Спешни, животозастрашаващи състояния</strong>:</li><ul><li style=\"font-size: 1em;\">Ангионевротичен оток.</li><li style=\"font-size: 1em;\">Анафилактичен шок.</li><li style=\"font-size: 1em;\">Status asthmaticus.</li><li style=\"font-size: 1em;\">Токсичен белодробен оток (<i><font color=\"#7e22ce\">methylprednisolone</font></i>).</li><li style=\"font-size: 1em;\">Мозъчен оток (<i><font color=\"#7e22ce\">dexamethasone</font></i>).</li></ul></ul><h3 style=\"font-size: 1.1em;\">Общи принципи при терапия с ГКС</h3><ul><li style=\"font-size: 1em;\"><strong>Приложение</strong>:</li><ul><li style=\"font-size: 1em;\"><strong>ГКС</strong> могат да бъдат прилагани орално, системно или вътреставно, чрез аерозол в дихателните пътища, като капки в очите или носа, или като кремове или унгвенти върху кожата.</li><li style=\"font-size: 1em;\"><strong>Локалното приложение</strong> намалява вероятността от <strong>системни нежелани ефекти</strong>.</li><li style=\"font-size: 1em;\">При продължителна употреба на системни глюкокортикоиди, алтерниращата терапия (лечението през ден) може да намали потискането на оста хипоталамус-хипофиза-надбъбреци и други нежелани ефекти.</li></ul><li style=\"font-size: 1em;\"><strong>Преустановяване на лечението</strong>:</li><ul><li style=\"font-size: 1em;\"><strong>Бавно и постепенно понижаване на дозата</strong>.</li><li style=\"font-size: 1em;\">Възстановяване на пълната функция на <strong>надбъбречните жлези</strong> обикновено отнема около 2 месеца, въпреки че това може да отнеме 18 месеца и повече.</li></ul></ul><h3 style=\"font-size: 1.1em;\"><hr></h3><h3 style=\"font-size: 1.1em;\">Минералкортикостероиди (МКС)</h3><ul><li style=\"font-size: 1em;\">Главният <strong>МКС</strong> е <strong>алдостерон</strong>.</li><li style=\"font-size: 1em;\">Неговото основно действие е да <strong>увеличи Na<sup>+</sup> реабсорбция</strong> в <strong>дисталните тубули в бъбреците</strong> с едновременно повишение на <strong>екскрецията на K<sup>+</sup> и H<sup>+</sup></strong>.</li><li style=\"font-size: 1em;\">В <strong>сърцето</strong> – повишава <strong>интерстициалната фиброза</strong>.</li><li style=\"font-size: 1em;\"><strong>Прекомерната секреция на МКС</strong> (<strong><font color=\"#dd0a0a\">Синдром на Conn</font></strong>):</li><ul><li style=\"font-size: 1em;\"><strong>Задръжка на Na<sup>+</sup> и вода</strong>, повишаване на <strong>екстрацелуларния обем</strong>, понякога <strong>хипокалиемия</strong>, <strong>алкалоза</strong> и <strong>хипертония</strong>.</li></ul><li style=\"font-size: 1em;\"><strong>Понижена секреция на МКС</strong> (<strong><font color=\"#dd0a0a\">Адисонова болест</font></strong>):</li><ul><li style=\"font-size: 1em;\"><strong>Загуба на Na<sup>+</sup></strong> и значително <strong>понижаване на екстрацелуларния обем</strong>, съпроводено с понижена екскреция на <strong>K<sup>+</sup></strong>, водещо до <strong>хиперкалиемия</strong>.</li></ul></ul><h4 style=\"font-size: 1.05em;\">Регулация на алдостероновата секреция</h4><ul><li style=\"font-size: 1em;\"><strong>Електролитен състав на плазмата</strong>:</li><ul><li style=\"font-size: 1em;\">Ниска плазмена концентрация на <strong>Na<sup>+</sup></strong> или висока <strong>K<sup>+</sup></strong> концентрация <strong>директно стимулира секрецията на алдостерон</strong>.</li></ul><li style=\"font-size: 1em;\">Намаляването на <strong>Na<sup>+</sup></strong> в организма активира също <strong>РААС</strong>; <strong>Ангиотензин II</strong> повишава синтезата и секрецията на <strong>алдостерон</strong>.</li></ul><h4 style=\"font-size: 1.05em;\">Механизъм на действие</h4><ul><li style=\"font-size: 1em;\"><strong>Алдостеронът</strong> действа чрез:</li><ul><li style=\"font-size: 1em;\"><b>Специфични </b><font color=\"#3b82f6\" style=\"font-weight: bold;\">вътреклетъчни рецептори</font> – транскрипция и транслация на специфични протеини:</li><ul><li style=\"font-size: 1em;\"><p>↑</p> броя на <strong>Na<sup>+</sup>-канали</strong> в <strong>апикалните мембрани</strong> на клетките.</li><li style=\"font-size: 1em;\">Последващо <p>↑</p> на броя на <strong>Na<sup>+</sup>-K<sup>+</sup>-АТФ-аза</strong> молекули в базолатералната мембрана, водещо до повишаване на <strong>K<sup>+ </sup>екскреция</strong>.</li></ul><li style=\"font-size: 1em;\"><strong>Бързи не-геномни ефекти</strong>:</li><ul><li style=\"font-size: 1em;\"><strong>Na<sup>+</sup> инфлукс</strong> чрез действие върху <strong>Na<sup>+</sup>-H<sup>+</sup> обменител</strong> в <strong>апикалната мембрана</strong>.</li></ul></ul><li style=\"font-size: 1em;\"><strong>МК рецептор</strong> е ограничен в определени тъкани:</li><ul><li style=\"font-size: 1em;\"><strong>Бъбреци</strong>.</li><li style=\"font-size: 1em;\"><strong>Транспортен епител</strong> в <strong>колона</strong> и <strong>пикочния мехур</strong>.</li></ul></ul><h3 style=\"font-size: 1.1em;\">Клинична употреба на МКС и антагонисти</h3><ul><li style=\"font-size: 1em;\"><strong><i><font color=\"#7e22ce\">Fludrocortisone</font></i></strong> – <strong>МКС</strong>:</li><ul><li style=\"font-size: 1em;\"><strong>Заместителна терапия</strong> при <strong><font color=\"#dd0a0a\">Адисонова болест</font></strong> заедно с <strong>ГКС</strong>.</li></ul><li style=\"font-size: 1em;\"><strong>Антагонисти на алдостерона</strong> – <strong><i><font color=\"#7e22ce\">Spironolactone</font></i></strong>, <b style=\"font-style: italic; color: rgb(126, 34, 206);\">Eplerenone&nbsp;</b><p style=\"\"><font color=\"#000000\" style=\"\">(</font><font color=\"#65a30d\">има ги в упражнение 16</font><font color=\"#000000\" style=\"\">)</font></p>:&nbsp;</li><ul><li style=\"font-size: 1em;\">Първичен и вторичен хипералдостеронизъм.</li><li style=\"font-size: 1em;\">Заедно с K-губещи диуретици при хипертония.</li><li style=\"font-size: 1em;\">Сърдечна недостатъчност.</li></ul></ul><hr><hr><h1>Лекарства, повлияващи костно-минералната хомеостаза</h1><h3>Костно ремоделиране</h3><ul><li>Този процес включва:</li><ul><li>Два основни типа клетки: <strong>остеобласти</strong> и <strong>остеокласти</strong>.</li><li>Различни <strong>цитокини</strong>.</li><li>Костни минерали – особено <strong>калций</strong> и <strong>фосфат</strong>.</li><li>Действията на редица <strong>хормони</strong>:</li><ul><li><strong>Паратиреоиден хормон</strong> (<strong>ПТХ</strong>)</li><li>Семейството на <strong>витамин D</strong></li><li><strong>Естрогени</strong></li><li><strong>Растежен хормон</strong></li><li><strong>Стероиди</strong></li></ul></ul></ul><h4>Действия на клетки и цитокини</h4><ul><li><strong>Остеобластът</strong> експресира повърхностен лиганд – <strong>RANK лиганд (RANKL)</strong>:</li><ul><li>Експресията се стимулира от <strong>калцитриол</strong>, <strong>паратиреоиден хормон (ПТХ)</strong>, <strong>цитокини</strong> и <strong>глюкокортикоиди</strong>.</li></ul><li><strong>RANKL</strong> взаимодейства с рецептор върху <strong>остеокластите</strong>, наречен <strong>RANK</strong>. Резултатът е:</li><ul><li><strong>Диференциация</strong> и <strong>активиране</strong> на прекурсорите на <strong>остеокластите</strong> да образуват <strong>зрели остеокласти</strong>.</li><li>Сливане на остеокластите в гигантски многоядрени кост-резорбиращи клетки.</li></ul><li><strong>Бифосфонатите</strong> инхибират <strong>костната резорбция</strong> от <strong>остеокластите</strong>.</li><li><strong>Анти-RANKL антитела</strong> (напр. <strong><i><font color=\"#7e22ce\">denosumab</font></i></strong>) свързват <strong>RANKL</strong> и предотвратяват взаимодействието <strong>RANK – RANKL</strong>.</li></ul><h3>Хормони, участващи в костния метаболизъм</h3><ul><li><font color=\"#ac3c16\"><b>Паратиреоиден хормон (ПТХ)</b></font></li><ul><li><strong><font color=\"#3b82f6\">Мобилизира Ca<sup>2+</sup> от костите</font></strong>.</li><li>Улеснява <font color=\"#3b82f6\"><strong>реабсорбцията на Ca<sup>2+</sup></strong> в <strong>бъбреците</strong></font>.</li><li><strong>Стимулира синтеза на <i><font color=\"#7e22ce\">калцитриол</font></i></strong>, който от своя страна:</li><ul><li>Увеличава <font color=\"#3b82f6\"><strong>Ca<sup>2+</sup> резорбция</strong> от <strong>червата</strong>.</font></li><li>Действа <strong><font color=\"#3b82f6\">синергично с ПТХ</font></strong> в мобилизирането на <strong>костния Ca<sup>2+</sup></strong>.</li></ul><li>Улеснява <strong><font color=\"#3b82f6\">екскрецията на фосфат</font></strong>.</li><li><strong>Краен ефект</strong> – <strong>повишаване на концентрацията на Са<sup>2+</sup> в плазмата</strong> и <strong>понижаване на фосфата</strong>.</li><li>Но като се дава терапевтично при <strong>ниска доза интермитентно</strong>&nbsp;<strong>ПТХ</strong> и <strong>фрагменти от ПТХ</strong> <strong>парадоксално стимулират дейността на остеобластите</strong> и <strong>подобряват формирането на костите</strong>.</li></ul><li><font color=\"#ac3c16\"><b>Калцитонин</b></font></li><ul><li>Пептиден хормон от специализирани С клетки във <strong>фоликулите на щитовидната жлеза</strong>.</li><li><strong>Действие</strong>:</li><ul><li>Върху <strong>костите</strong>: <strong><font color=\"#3b82f6\">Потиска остеокластите</font></strong>.</li><li>В <strong>бъбреците</strong>: <strong><font color=\"#3b82f6\">Намалява реабсорбцията на Ca<sup>2+</sup> и фосфат</font></strong>.</li></ul><li><strong>Общ ефект</strong>: <strong>Намаляване на плазмената концентрация на Са<sup>2+</sup></strong>.</li></ul><li><b><font color=\"#ac3c16\">Vitamin D (calciferol)</font></b></li><ul><li><strong>2 източника на витамин D</strong>:</li><ul><li>Диетичен ergocalciferol (D2).</li><li><strong><i><font color=\"#7e22ce\">Cholecalciferol</font></i> (D3)</strong> – образуван в <strong>кожата</strong> под действието на <strong>UV светлина</strong>.</li></ul><li><strong>Превръщания на <i><font color=\"#7e22ce\">cholecalciferol</font></i></strong>:</li><ul><li>В <strong>черния дроб</strong> – до <strong>calcifediol</strong> (25-hydroxy-vitamin D3).</li><li>Впоследствие в <strong>бъбреците</strong> до <i><font color=\"#7e22ce\"><strong>calcitriol</strong> </font></i>(1,25-dihydroxy-vitamin D3) – <strong>активната форма</strong>.</li></ul><li><i><font color=\"#7e22ce\"><strong style=\"\">Calcitriol</strong> </font></i>ефекти:</li><ul><li><strong><font color=\"#3b82f6\">Стимулира резорбцията на Ca<sup>2+</sup> и фосфати в червата</font></strong>.</li><li><strong><font color=\"#3b82f6\">Мобилизира Ca<sup>2+</sup> от костите</font></strong>.</li><li><strong><font color=\"#3b82f6\">Увеличава Ca<sup>2+</sup> реабсорбция в бъбречните тубули</font></strong>.</li><li><strong>Но</strong>:</li><ul><li>Ефектът върху <strong>костите</strong> е сложен и не се ограничава до мобилизиране <strong>Ca<sup>2+</sup></strong>.</li><li>Прилагането на <strong>витамин D</strong> <strong>възстановява формирането на костите</strong>.</li><li>Едно обяснение може да се състои в това, че той стимулира синтеза на <strong>остеокалцин</strong> – <strong>Са<sup>2+</sup>-свързващия протеин</strong> на <strong>костния матрикс</strong>.</li></ul></ul></ul><li><b><font color=\"#ac3c16\">Естрогени</font></b></li><ul><li><strong><font color=\"#3b82f6\">Инхибират остеокластите</font></strong>.</li><li><b><font color=\"#3b82f6\">Противодействат на ПТХ</font></b>.</li><li><font color=\"#3b82f6\">Увеличават на <strong>пролиферацията</strong> и <strong>инхибират апоптозата на остеобластите</strong></font>.</li><li><strong>Отнемане на естрогените</strong>, както се случва в периода на <strong>менопауза</strong>, може да доведе до <strong><font color=\"#3b82f6\">остеопороза</font></strong>.</li></ul><li><b><font color=\"#ac3c16\">Глюкокортикостероиди (ГКС)</font></b></li><ul><li><strong>Физиологични концентрации</strong> са необходими за <strong>диференциация на остеобластите</strong>.</li><li><strong>Прекалено високи фармакологични концентрации</strong>:</li><ul><li><strong><font color=\"#3b82f6\">Инхибират остеобластна</font> диференциация и дейност</strong>.</li><li><strong><font color=\"#3b82f6\">Стимулират остеокластите</font></strong>.</li></ul><li><strong>Резултат</strong>: <strong><font color=\"#3b82f6\">Остеопороза</font></strong>.</li></ul></ul><h3><hr></h3><h3>Болести на костите</h3><ul><li><strong>Остеопороза</strong>: Намаляване на костната маса.</li><li><strong>Остеомалация, рахит</strong>: Дефект в костната минерализация поради дефицит на vitamin D.</li><li><strong>Болест на Paget</strong>: Нарушаване на процеса на костната резорбция и ремоделиране.</li></ul><h3>Лекарства при костни заболявания</h3><ol><li><strong>Бифосфонати</strong>:</li><ul><li>I поколение:&nbsp;</li><ul><li><strong><font color=\"#7e22ce\"><i>Clodronic acid</i></font></strong>.</li></ul><li>II поколение:&nbsp;</li><ul><li><strong><i><font color=\"#7e22ce\">Alendronic acid</font></i></strong></li><li><strong><i><font color=\"#7e22ce\">Ibandronic acid</font></i></strong></li><li><strong><i><font color=\"#7e22ce\">Zoledronic acid</font></i></strong></li></ul></ul><li><strong>ХЗТ</strong> (<i><font color=\"#7e22ce\"><b>Femoston</b></font></i>)<strong> и SERM&nbsp;</strong>(<strong><i><font color=\"#7e22ce\">Raloxifene</font></i></strong>) - само при жени в менопауза</li><li><strong>Аналози на паратхормона</strong>:</li><ul><li><strong><i><font color=\"#7e22ce\">Teriparatide</font></i></strong></li></ul><li><strong>Моноклонални антитела срещу RANKL</strong>:&nbsp;</li><ul><li><strong><i><font color=\"#7e22ce\">Denosumab</font></i></strong></li></ul><li><strong>Калцитонин</strong>:&nbsp;</li><ul><li><strong><i><font color=\"#7e22ce\">Calcitonin</font></i></strong></li></ul><li><strong>Vit. D и аналози</strong>:&nbsp;</li><ul><li><strong><i><font color=\"#7e22ce\">Calcitriol</font></i></strong></li><li><strong><i><font color=\"#7e22ce\">Cholecalciferol</font></i></strong></li><li><strong><i><font color=\"#7e22ce\">Calcipotriol</font></i></strong></li></ul><li><strong>Калцимиметици</strong>:&nbsp;</li><ul><li><strong><i><font color=\"#7e22ce\">Cinacalcet</font></i></strong></li></ul></ol><h3>Бифосфонати</h3><ul><li><strong><font color=\"#b53f17\">Фармакокинетика</font></strong>:</li><ul><li>По-малко от 10% се резорбират, резорбцията се намалява от храна.</li><li><strong>Натрупват се в костите</strong> (~50%).</li><li>Остават там в продължение на <strong>месеци или години</strong>, докато костта се <strong>резорбира</strong>.</li><li>Останалата част се излъчва в <strong>урината</strong>.</li></ul><li><strong><font color=\"#b53f17\">Фармакодинамика</font></strong>:</li><ul><li>Те образуват <strong>здрави комплекси с калция</strong> в <strong>костния матрикс</strong>.</li><li>При <strong>резорбцията на костта</strong> от <strong>остеокластите</strong> те са изложени на високи лекарствени концентрации.</li><li>Предизвикват <strong>апоптоза на остеокластите</strong>.</li><li><strong>Намаляват хиперкалциемията</strong> при злокачествени заболявания.</li></ul></ul><img src=\"https://files.coursebook.lol/Coursebook%20Assets/2026-05-05/coursebook-assets/assets/%D0%91%D0%B8%D1%84%D0%BE%D1%81%D1%84%D0%BE%D0%BD%D0%B0%D1%82%D0%B8%D0%A4%D0%B0%D1%80%D0%BC%D0%B0%D0%BA.png\" alt=\"БифосфонатиФармак.png\" data-original-src=\"https://files.coursebook.lol/Coursebook%20Assets/2026-05-05/coursebook-assets/assets/%D0%91%D0%B8%D1%84%D0%BE%D1%81%D1%84%D0%BE%D0%BD%D0%B0%D1%82%D0%B8%D0%A4%D0%B0%D1%80%D0%BC%D0%B0%D0%BA.png\" style=\"max-width: 100%; height: auto;\"><br><ul><li><font color=\"#b53f17\"><strong>Нежелани лекарствени реакции</strong>:</font></li><ul><li><strong>СЧ нарушения</strong>, <strong>язва</strong>.</li><li><strong>Езофагит</strong> (<strong><i><font color=\"#7e22ce\">alendronate</font></i></strong>).</li><li><strong>Костна болка</strong>.</li><li>При i.v. приложение – <strong>остеонекроза на челюстта</strong> (<strong><i><font color=\"#7e22ce\">zoledronate</font></i></strong>).</li></ul><li><strong><font color=\"#b53f17\">Клинично приложение</font></strong>:</li><ul><li><strong>Остеопороза</strong>:</li><ul><li><i><font color=\"#7e22ce\"><strong>Alendronate</strong> </font></i>– p.o., ежедневно или веднъж седмично в допълнение към <strong>калций</strong> и <strong>vitamin D</strong>.</li><li><i><font color=\"#7e22ce\"><strong>Zoledronate</strong> </font></i>– веднъж годишно чрез i.v. инфузия.</li></ul><li><strong>Злокачествени заболявания</strong>, засягащи <strong>костите</strong> (например метастатичен рак на гърдата, множествен миелом).</li><li><strong>Болест на Paget</strong> – интермитентно приложение.</li></ul></ul><h4>Естрогени и SERM: <i><font color=\"#7e22ce\">Raloxifene</font></i></h4><ul><li><font color=\"#b53f17\"><strong>Механизъм на действие</strong> – <strong>SERM</strong></font>:</li><ul><li>Агонистична активност на костите: <strong>стимулиране на остеобластите</strong> и <strong>инхибиране на остеокластите</strong>.</li><li>Агонистично действие върху сърдечно-съдовата система.</li><li>Антагонистичната активност на гръдната тъкан и матката.</li></ul><li><strong><font color=\"#b53f17\">Клинична употреба</font></strong>:</li><ul><li><strong>Алтернатива на бифосфонатите</strong> за <strong>профилактика на остеопороза</strong> при жени в <strong>менопауза</strong>, които не могат да понасят бифосфонати.</li></ul><li><strong><font color=\"#b53f17\">Нежелани лекарствени реакции</font></strong>:</li><ul><li><strong>Горещи вълни</strong>, <strong>крампи на краката</strong> и <strong>периферни отоци</strong>.</li><li>По-рядко срещани са <strong>тромбофлебит</strong> и <strong>тромбоемболизъм</strong>.</li></ul></ul><h3>Аналози на паратхормон: <i><font color=\"#7e22ce\">Teriparatide</font></i></h3><ul><ul><li><font color=\"#000000\" style=\"\">Представлява</font><i style=\"color: rgb(126, 34, 206);\">&nbsp;</i>пептидният фрагмент&nbsp;на <strong>рекомбинантен ПТХ.</strong></li><li>Прилага се в <b>малки дози </b>подкожно веднъж дневно.</li><li><strong><u>Парадоксално</u> стимулира остеобластната активност</strong> и <strong>повишава образуването на костна тъкан</strong>.</li><li>Използва се за лечение на някои пациенти с <strong>остеопороза</strong>.</li><li>Понася се добре.</li></ul></ul><h3>Моноклонални антитела срещу RANKL: <i><font color=\"#7e22ce\">Denosumab</font></i></h3><ul><li><strong><font color=\"#b53f17\">Механизъм на действие</font></strong>:</li><ul><li>Моноклонално антитяло (IgG<sub>2</sub>), което се прицелва и се <strong>свързва с висок афинитет и специфичност с RANKL</strong>.</li></ul><li><strong><font color=\"#b53f17\">Клинична употреба</font></strong>:</li><ul><li>Лечение на <strong>остеопороза</strong> при <strong>високо рискови пациенти</strong>.</li></ul><li><strong><font color=\"#b53f17\">Приложение</font></strong>:</li><ul><li><strong>Подкожно веднъж на 6 месеца</strong> заедно с <strong>калций</strong> и <strong>vitamin D</strong>.</li></ul><li><strong><font color=\"#b53f17\">НЛР</font></strong>:</li><ul><li><strong>Инфекции</strong> (на дихателните и пикочните пътища).</li><li>Рядко – <strong><font color=\"#dd0a0a\">остеонекроза на челюстта</font></strong>.</li></ul></ul><h4>Vitamin D</h4><ul><li><strong><font color=\"#7e22ce\"><i>Calcitriol</i></font></strong> (1,25-дихидрокси D3), <i><font color=\"#7e22ce\"><strong>Cholecalciferol</strong> </font></i>(D3).</li><li><strong><font color=\"#b53f17\">Клинично приложение</font></strong>:</li><ul><li><strong>Рахит</strong> – лечение и профилактика.</li><li><strong>Остеомалация</strong> и <strong>ренална остеодистрофия</strong> (<strong><i><font color=\"#7e22ce\">Calcitriol</font></i></strong>).</li><li><strong>Остеопороза</strong> (заедно с калциеви препарати).</li><li><strong>Хипопаратиреоидизъм</strong>.</li></ul><li><strong><i><font color=\"#7e22ce\">Calcipotriol</font></i></strong>:</li><ul><li>Унгвент.</li><li><strong>Псориазис:</strong></li><ul><li><p>Хронично автоимунно, възпалително кожно заболяване, което може да засяга и костите.</p></li><li>Инхибира клетъчната пролиферация; има ефект върху имунологичните маркери<p>, за които </p><p>се смята, че играят роля в етиологията на</p><p>заболяването</p>.</li></ul></ul></ul><h4><font color=\"#7e22ce\"><i>Calcitonin</i></font></h4><ul><li>Синтетичен полипептид&nbsp;– идентичен с калцитонин на <strong>сьомга</strong>.</li><li><strong><font color=\"#b53f17\">Приложение</font></strong>: Подкожно или интрамускулно инжектиране.</li><li><strong><font color=\"#b53f17\">НЛР</font></strong>: Повишена честота на <strong>рак</strong>.</li><li><strong><font color=\"#b53f17\">Клинична употреба</font></strong>:</li><ul><li><strong>Calcitonin</strong> вече <strong>не се използва за лечение на остеопороза</strong>!</li><li>Използва се <strong>краткотрайно</strong> при:</li><ul><li><strong>Болест на Paget</strong>.</li><li><strong>Хиперкалциемия</strong> (например свързана със злокачествено заболяване).</li></ul></ul></ul><h4><i><font color=\"#7e22ce\">Cinacalcet</font></i></h4><ul><li><strong><font color=\"#a63a17\">Механизъм</font>:</strong></li><ul><li><strong>Калцимиметик</strong> – наподобява действието на <strong>Ca.</strong></li><li>В <strong>паращитовидните жлези</strong> имитира <strong>стимулиращия ефект на Ca<sup>2+</sup></strong> върху <strong>калций-чувствителния рецептор</strong> и така <strong>инхибира секрецията на ПТХ</strong>.</li><li>Понижаването на <strong>ПТХ</strong> понижава кръвните нива на <strong>Ca</strong>.</li></ul><li><strong><font color=\"#b53f17\">Клинична употреба</font></strong>:</li><ul><li><strong>Вторичен хиперпаратиреоидизъм</strong> при пациенти с<b> бъбречна недостатъчност</b>.</li><li><strong>Понижава хиперкалциемията</strong> при пациенти с <strong>рак на паращитовидните жлези</strong> или при <strong>първичен хиперпаратиреоидизъм</strong>, които не могат да бъдат оперирани.</li></ul></ul><br>\r\n<h1 style=\"font-size: 1.5em; color: rgb(124, 45, 18);\"></h1><h1 style=\"color: rgb(124, 45, 18);\"><span style=\"font-size: 1.5em;\">Антидиабетични лекарства</span></h1><h3 style=\"color: rgb(124, 45, 18);\">Контрол на кръвната глюкоза</h3><ul><li><strong>Инсулин</strong>:</li><ul><li>Понижава <strong>кръвната глюкоза</strong>.</li><li>Повишената <strong>кръвна глюкоза</strong> стимулира <strong>инсулиновата секреция</strong>.</li></ul><li><strong>„Контра-инсуларни“ хормони</strong>:</li><ul><li>Глюкагон</li><li>Адреналин</li><li>Глюкокортикоиди</li><li>Растежен хормон</li></ul></ul><h3 style=\"color: rgb(124, 45, 18);\">Захарен диабет</h3><ul><li>Характеризира се с <strong>намалена</strong> или <strong>липсваща секреция на инсулин</strong>.</li><li>Често е съчетан с <strong>инсулинова резистентност</strong> (намалена чувствителност към действието му), която е пряко свързана със <strong>затлъстяване</strong>.</li><li><strong>Диабет тип 1</strong>:</li><ul><li>Преди известен като: Инсулино-зависим диабет, Ювенилен диабет.</li><li><strong>Патогенеза</strong>: <strong>автоимунен процес</strong>.</li></ul><li><strong>Диабет тип 2</strong>:</li><ul><li>Преди известен като: Не-инсулино-зависим диабет, Старчески диабет.</li><li><strong>Патогенеза</strong>: <strong>инсулинова резистентност</strong> (предшества изявата на болестта) и <strong>понижена инсулинова секреция</strong>.</li></ul></ul><h3 style=\"color: rgb(124, 45, 18);\">Панкреасни клетки (Islet of Langerhans)</h3><ul><li><strong>Alpha cell</strong>: Секретира <strong>глюкагон</strong>.</li><li><strong>Beta cell</strong>: Секретира <strong>инсулин</strong> и <strong>amylin</strong>.</li><li><strong>Delta cell</strong>: Секретира <strong>соматостатин</strong>.</li><li><strong>F cell</strong>: Секретира панкреатичен полипептид.</li></ul><h3 style=\"color: rgb(124, 45, 18);\"><hr></h3><h3 style=\"color: rgb(124, 45, 18);\">Инсулин</h3><h4 style=\"color: rgb(124, 45, 18);\">Структура и Секреция</h4><ul><li><strong>Структура</strong>: Състои се от 2 пептидни вериги (от 21 и 30 а.к.), свързани с дисулфидни връзки.</li><li><strong>Освобождаване</strong>:</li><ul><li>Има постоянно <strong>базално освобождаване</strong> на инсулин и също <strong>стимулиран отговор</strong> към повишението на <strong>кръвната глюкоза</strong>.</li></ul><li><strong>Секреция на инсулин</strong>:</li><ul><li><strong>Глюкозата</strong> навлиза в <strong>В клетките</strong> чрез мембранен транспортер <strong>Glut-2</strong>.</li><li><strong>Метаболизмът на глюкозата</strong> повишава <strong>вътреклетъчните нива на АТФ</strong>.</li><li>АТФ блокира&nbsp;<b>K<sub style=\"\">АТФ</sub> канали</b> и предизвиква мембранна деполяризация.</li><li>Деполяризацията води до отваряне на <strong>волтаж-зависими Са канали</strong>, водещо до <strong>инфлукс на Ca<sup>2+</sup></strong>.</li><li>Повишаването на <strong>цитоплазмения <p>Ca<sup>2+</sup></p></strong> стимулира <strong>инсулиновата секреция</strong>.</li><li><strong>Сулфонилурейните лекарства</strong> блокират/затварят и деполяризират&nbsp;<p>K<sub>АТФ </sub>канали</p><strong></strong>.</li></ul></ul><h4 style=\"color: rgb(124, 45, 18);\">Действия на инсулина</h4><ul><li>Той е <strong>анаболен хормон</strong> и <strong>понижава кръвната глюкоза</strong>.</li><li><strong>В черния дроб</strong>:</li><ul><li>Инхибира <strong>гликогенолизата</strong>.</li><li>Стимулира <strong>синтезата на гликоген</strong>.&nbsp;</li><li>Краен ефект: повишава <strong>чернодробните запаси на гликоген</strong>.</li><li>Инхибира <strong>глюконеогенезата</strong>.</li><li>Увеличава използването на <strong>глюкозата</strong> (<strong>гликолизата</strong>).</li><li>Понижава <strong>катаболизма на протеините</strong> и инхибира <strong>окислението на а.к.</strong></li><li>Повишава синтезата на <strong>мастни киселини и триглицериди</strong> и инхибира <strong>липолизата</strong>.</li></ul><li><strong>В мастната тъкан</strong>:</li><ul><li>Повишава поемането на <strong>глюкоза</strong> чрез <strong>Glut-4</strong>.</li><li>Улеснява глюкозния метаболизъм до <strong>глицерол</strong>, който се естерифицира с мастни киселини до <strong>триглицериди</strong>.</li><li>Инхибира <strong>липолизата</strong>.</li></ul><li><strong>В мускулите</strong>:</li><ul><li>Повишава улеснения транспорт на <strong>глюкоза</strong> чрез&nbsp;<strong>Glut-4</strong>.</li><li>Стимулира <strong>синтезата на гликоген</strong> и <strong>гликолизата</strong>.</li><li>Стимулира поемането на <strong>а.к.</strong> в мускулите и повишава <strong>протеиновата синтеза</strong>.</li></ul></ul><h4 style=\"color: rgb(124, 45, 18);\">Механизъм на действие</h4><ul><li><strong>Инсулинов рецептор</strong>:</li><ul><li>Голям <strong>трансмембранен гликопротеин</strong>, принадлежащ към суперфамилията на <strong><font color=\"#3b82f6\">тирозин киназа-свързаните рецептори</font></strong>.</li><li>Състои се от две α и две β субединици.</li><li>Настъпва рецепторно автофосфорилиране в резултат на димеризация<p>, при </p><p>което един рецептор </p><p>фосфорилира другия</p></li><li>Протеини,<i style=\"font-weight: bold;\"> субстрати на инсулиновия рецептор (IRS)</i><i> </i>претърпяват бързо фосфорилиране.</li><li>Фосфорилираните <strong>IRS</strong> взаимодействат с SH2 домен на фосфатидилинозитол 3-киназа и я активират.</li></ul><li><strong>Резултат</strong>: Настъпва придвижване на транспортерите <strong>Glut-4</strong> от апарата на Голджи към плазмената мембрана на мускулните и мастните клетки, което улеснява навлизането на <strong>глюкоза</strong>.</li><li>По-продължителните действия на инсулина са свързани с <strong>ефекти върху ДНК и РНК</strong>.</li></ul><h3 style=\"color: rgb(124, 45, 18);\">Инкретини</h3><ul><li><strong>Glucose-dependent insulinotropic polypeptide (GIP)</strong>:&nbsp;</li><ul><li>Секретиран от <strong>ентероендокринните клетки</strong> в дуоденума и проксималния йейюнум.</li></ul><li><strong>Glucagon-like peptide-1 (GLP-1)</strong>:&nbsp;</li><ul><li>Секретиран от <strong>ентероендокринните клетки</strong>, които са по-широко застъпени в червата, вкл. илеума и колона.</li></ul><li><strong>Действия на тези хормони</strong>:</li><ul><li>Стимулират <strong>инсулиновата секреция</strong> след прием на храна.</li><li>Инхибират <strong>секрецията на глюкагон</strong>.</li><li>Забавят <strong>изпразването на стомаха</strong>.</li></ul><li><strong>Dipeptidyl peptidase-4 (DPP-4)</strong>:&nbsp;</li><ul><li>Бързо преустановява действията на <strong>GIP</strong> и <strong>GLP-1</strong>.</li></ul></ul><img src=\"https://files.coursebook.lol/Coursebook%20Assets/2026-05-05/coursebook-assets/assets/GIP%2CGLP-1%2CDPP-4.png\" alt=\"GIP,GLP-1,DPP-4.png\" data-original-src=\"https://files.coursebook.lol/Coursebook%20Assets/2026-05-05/coursebook-assets/assets/GIP%2CGLP-1%2CDPP-4.png\" style=\"max-width: 100%; height: auto;\"><br><h3 style=\"color: rgb(124, 45, 18);\">Инсулинови препарати</h3><ul><li><strong>Произход</strong>: Сега се използва <strong>човешки инсулин</strong> <b>(рекомбинантна ДНК технология)</b>.</li><li><strong>Пътища на приложение</strong>&nbsp;-&nbsp;<strong>Парентерални:</strong></li><ul><li>Oбикновено <strong>s.c.</strong></li><li><strong>I.v.</strong> или инцидентно <strong>i.m.</strong> при спешност.</li></ul><li><strong>Фармакокинетика</strong>:</li><ul><li>Плазмен полуживот – около 10 min.</li><li>Метаболизъм в <strong>черния дроб</strong> и <strong>бъбреците</strong>; <strong>10%</strong> - екскретиран в <strong>урината</strong>.</li><li><strong>Бъбречната недостатъчност</strong> намалява инсулиновите нужди (<font color=\"#65a30d\">бъбреците&nbsp;ппц разграждат инсулина и участват в глюконеогенеза</font>)</li></ul></ul><h4 style=\"color: rgb(124, 45, 18);\">Класификация</h4><ol><li><strong>Инсулини и аналози с бързо начало и кратка продължителност на действието</strong>:</li><ul><li><b>Човешки инсулини</b>:&nbsp;</li><ul><li><b><font color=\"#7e22ce\" style=\"\"><i>Regular insulin</i></font> </b>(<strong><font color=\"#7e22ce\"><i>Insulin Actrapid)</i></font></strong></li><li><i><font color=\"#7e22ce\"><p><b>Insulin Actrapid penfill</b></p><b>&nbsp;</b></font></i></li><li><strong><i><font color=\"#7e22ce\">Humulin R</font></i></strong></li></ul><li><b>Аналози</b>:&nbsp;</li><ul><li><i style=\"color: rgb(126, 34, 206); font-weight: bold;\">Insulin lispro&nbsp;</i><p style=\"\"><font color=\"#000000\">(действа по-бързо и по-кратко от инсулина).</font></p></li><li><strong><i><font color=\"#7e22ce\">Insulin aspart</font></i></strong>&nbsp;</li></ul></ul><li><strong>Инсулини с интермедиерно действие</strong>:</li><ul><li><b>Монопрепарати</b>:&nbsp;</li><ul><li><strong><i><font color=\"#7e22ce\">Humulin N</font></i></strong></li><li><strong><i><font color=\"#7e22ce\">Insulatard</font></i></strong></li></ul><li><b>Инсулинови смеси</b> (Insulin + Isophane insulin):&nbsp;</li><ul><li><i><font color=\"#7e22ce\"><strong>Insulin Mixtard</strong></font></i></li><li><i><font color=\"#7e22ce\"><strong>Humulin M</strong></font></i><font color=\"#7e22ce\"><b><i>1 (M2, M3, M4)</i></b></font></li></ul><li><b>Смеси от аналози</b>:</li><ul><li><b><i><font color=\"#7e22ce\">&nbsp;<p>Insulin lispro + Insulin lispro protamine = Humalog Mix</p></font></i></b></li></ul></ul><li><strong>Инсулинови аналози с продължително действие</strong>:</li><ul><li><i style=\"\"><font color=\"#7e22ce\" style=\"\"><b>Insulin glargine penfill&nbsp;</b></font></i>(осигурява <strong>базалното инсулиново ниво</strong>).</li><li><p><i><b style=\"color: rgb(126, 34, 206);\">Insulin detemir penfill </b><font color=\"#000000\">(не се произвежда повече)</font></i></p></li></ul></ol><h4 style=\"color: rgb(124, 45, 18);\">Клинична употреба на инсулините</h4><ul><li><strong>Поддържаща терапия при диабет тип 1</strong>:</li><ul><li>Препарат с <strong>интермедиерно действие</strong> <p>(напр.<i><font color=\"#000000\"> </font><font color=\"#7e22ce\">insulatard</font></i>) </p>2 пъти дневно</li><li><strong>Дълго действащ аналог</strong> <p>(напр. <i><font color=\"#7e22ce\">glargine</font></i>) </p>1 път дневно в комбинация с <strong>бързо действащ инсулинов аналог</strong> <p>(напр. <i><font color=\"#7e22ce\">Insulin lispro</font></i>) </p>преди хранене.</li></ul><li><strong><i><font color=\"#7e22ce\">Insulin Actrapid</font></i> </strong>(i.v.) при <strong>хипергликемична кома</strong> (<strong>диабетна кетоацидоза</strong>).</li><li>При <strong>диабет тип 2</strong> в комбинация с <strong>перорални лекарства</strong>.</li><li><strong>Краткосрочно лечение</strong> при пациенти с <strong>диабет тип 2</strong> по време на <strong>интеркурентни събития</strong> (операции, инфекции, миокарден инфаркт).</li><li>По време на <strong>бременност</strong> за <strong>гестационен диабет</strong>, ако не се повлиява от диета.</li><li><strong>Спешна терапия на хиперкалиемия</strong>: инсулинът се дава с глюкоза, за понижаване на <strong>екстрацелуларния K<sup>+</sup>&nbsp;</strong><p>чрез преразпределение в </p><p>клетките.</p></li></ul><h4 style=\"color: rgb(124, 45, 18);\">Нежелани реакции към инсулин</h4><ul><li><strong>Хипогликемия</strong>: Лечение на тежка хипогликемия – <strong>i.v глюкоза</strong> и <strong>i.m. глюкагон</strong>.</li><li><strong>Алергия</strong> към човешкия инсулин – рядка, но може да настъпи; <strong>локални</strong> и <strong>системни реакции</strong>.</li><li><strong>Инсулинова резистентност</strong> в резултат на <strong>антиинсулинови антитела</strong> – рядка.</li><li><strong>Липодистрофия</strong> на инжекционното място.</li></ul><h3 style=\"color: rgb(124, 45, 18);\">Лекарства при диабет тип 2</h3><h3 style=\"color: rgb(124, 45, 18);\"><strong style=\"font-size: 17.6px;\"><font color=\"#000000\">1.&nbsp;</font></strong><strong style=\"color: rgb(31, 41, 55); font-size: 16px;\">Инсулинови очувствители:</strong></h3><ol><ul><li><strong>a) Бигваниди</strong>:&nbsp;</li><ul><li><strong><i><font color=\"#7e22ce\">Metformin</font></i></strong></li></ul><li><p><b>б) Тиазолидиндиони</b>: </p></li><ul><li><p><i><font color=\"#7e22ce\"><b>Pioglitazone</b></font></i></p></li></ul></ul></ol><strong>2. Инсулинови секреготи:</strong><br><ul><ul><li><strong>Сулфонилурейни лекарства</strong>:&nbsp;</li></ul></ul><ol><ul><ul><li><strong><i><font color=\"#7e22ce\">Glibenclamide</font></i></strong></li><li><strong><i><font color=\"#7e22ce\">Gliclazide</font></i></strong></li><li><strong><i><font color=\"#7e22ce\">Glipizide</font></i></strong></li><li><strong><i><font color=\"#7e22ce\">Glimepiride</font></i></strong></li></ul></ul><ul><li><strong>Меглитиниди</strong>:&nbsp;</li><ul><li><strong><i><font color=\"#7e22ce\">Repaglinide</font></i></strong></li><li><i><font color=\"#7e22ce\"><strong>Nateglinide</strong></font></i></li></ul></ul></ol><strong>3. Алфа-глюкозидазни инхибитори</strong>:&nbsp;<br><ol><ul><li><strong><i><font color=\"#7e22ce\">Acarbose</font></i></strong>.</li></ul></ol><strong>4.&nbsp;</strong><span style=\"white-space-collapse: preserve; font-weight: 600;\">Лекарства на базата на инкретини</span><ul><li><strong>а) Инктеринови миметици (GLP-1 рецепторни агонисти)</strong>:&nbsp;</li></ul><ol><ul><li><strong><i><font color=\"#7e22ce\">Exenatide</font></i></strong></li><li><strong><i><font color=\"#7e22ce\">Lixisenatide</font></i></strong></li><li><strong><i><font color=\"#7e22ce\">Liraglutide</font></i></strong></li><li><strong><i><font color=\"#7e22ce\">Dulaglutide</font></i></strong></li></ul></ol><ul><li><b style=\"\"><i style=\"\"><p style=\"\"><font color=\"#000000\">б) Инхибитори на дипептидил пептидаза-4 (DPP-4 инхибитори): </font></p></i></b></li><ul><li><b style=\"color: rgb(126, 34, 206);\"><i><p>Sitagliptin</p></i></b></li><li><b style=\"color: rgb(126, 34, 206);\"><i><p>Vildagliptin</p></i></b></li><li><b style=\"color: rgb(126, 34, 206);\"><i><p>Linagliptin</p></i></b></li><li><b style=\"color: rgb(126, 34, 206);\"><i><p>Saxagliptin</p></i></b></li></ul></ul><strong>5.&nbsp;</strong><span style=\"white-space-collapse: preserve; font-weight: 600;\">Глюкуретици: инхибитори на натриево-глюкозен котранспортер 2 (sodium-glucose</span><strong><p>cotransporter 2, SGLT2):</p></strong><ul><ul><li><strong><i><font color=\"#7e22ce\">Dapagliflozin</font></i></strong></li><li><strong><i><font color=\"#7e22ce\">Empagliflozin</font></i></strong></li><li><strong><i><font color=\"#7e22ce\">Canagliflozin</font></i></strong></li></ul></ul><h3 style=\"color: rgb(124, 45, 18);\"><hr></h3><h3 style=\"color: rgb(124, 45, 18);\">Бигваниди</h3><ul><li><strong><font color=\"#b13d16\">Представител: </font><i style=\"\"><font color=\"#7e22ce\">Metformin</font></i></strong></li><li><strong><font color=\"#b13d16\">Ефекти</font></strong>:</li><ul><li><strong>Понижава <p>глюконеогенезата</p> в черния дроб</strong>.</li><li><strong><font color=\"#3b82f6\">Повишава поемането и използването на глюкоза в скелетната мускулатура</font></strong> (т.е. понижава <strong>инсулиновата резистентност</strong>).</li><li><strong>Понижава абсорбцията на въглехидрати</strong>.</li><li><strong>Понижава LDL и VLDL</strong>.</li></ul><li><strong><font color=\"#b13d16\">Нежелани ефекти</font></strong>:</li><ul><li><strong>СЧ нарушения</strong> (безапетитие, гадене, диария).</li><li><strong>Лактацидоза</strong> – рядък, но потенциално фатален ефект. Не бива да се дава на пациенти със:</li></ul><ul><ul><li><strong>Понижена тъканна оксигенация</strong> (<b>дихателна</b> и <b>сърдечна недостатъчност</b>)<p>(<font color=\"#65a30d\">Понижена тъканна оксигензация -&gt; анаеробна гликоза -&gt; ↑ производство на лактат</font>)</p></li><li><strong>Намалена елиминация на лекарството</strong> (<strong>бъбречна</strong> или <strong>чернодробна недостатъчност</strong>).(<font color=\"#65a30d\">намалена елиминация -&gt;&nbsp;</font><p><font color=\"#65a30d\">↑ производство на лактат &amp; в черния дроб лактата се превръща обратно в клюкоза</font>)</p></li></ul></ul><li><strong><font color=\"#b13d16\">Важно</font></strong>: <strong>Не предизвиква хипогликемия!</strong></li><li><strong><font color=\"#b13d16\">Клинична употреба</font></strong>: <strong>Диабет тип 2</strong>, особено при пациенти със <strong>затлъстяване</strong>.</li></ul><h3 style=\"color: rgb(124, 45, 18);\">Сулфонилурейни лекарства</h3><ul><li><strong><font color=\"#b13d16\">Представители</font></strong>: <strong><i><font color=\"#7e22ce\">Glibenclamide</font></i></strong>, <strong><i><font color=\"#7e22ce\">Gliclazide</font></i></strong>, <strong><i><font color=\"#7e22ce\">Glipizide</font></i></strong>, <strong><i><font color=\"#7e22ce\">Glimepiride</font></i></strong>.</li><li><strong><font color=\"#b13d16\">Механизъм на действие</font></strong>:</li><ul><li><p>Рецептори за сулфонилурейната </p><p>молекула</p> върху <strong><p>K<sub>ATФ</sub></p> канали</strong>.</li><li><strong>Блокиране</strong> на активацията на <strong><p>K<sub>ATФ</sub></p> канал</strong>.</li><li><strong>Деполяризация</strong> -&gt; Навлизане на <strong>Ca2+</strong> -&gt; <strong><u><font color=\"#3b82f6\">Секреция на инсулин</font></u></strong>.</li></ul><li><strong><font color=\"#b13d16\">Фармакокинетика</font></strong>:</li><ul><li>Орална абсорбция, високо свързване с <strong>плазмени протеини</strong>.</li><li><strong>Ренална екскреция</strong> на лекарствата и техните активни метаболити.</li><li>Преминаване през плацентарната бариера.</li></ul><li><strong><font color=\"#b13d16\">Нежелани лекарствени реакции</font></strong>:</li><ul><li><strong>Хипогликемия</strong>, особено при пациенти с <strong>бъбречна недостатъчност</strong>.</li><li><strong>Наддаване на тегло</strong> – стимулират апетита.</li><li><strong>СЧ нарушения</strong></li><li><strong>Кожни алергични реакции</strong>.</li><li><strong>Костно-мозъчна токсичност</strong> – рядка, но може да бъде тежка.</li></ul><li><strong><font color=\"#b13d16\">Клинична употреба</font></strong>: <strong>Диабет тип 2</strong>.</li><li><strong><font color=\"#b13d16\">Лекарствени взаимодействия</font></strong>:</li><ul><li><strong>Лекарства, повишаващи ефекта</strong>:&nbsp;</li><ul><li>НСПВЛ</li><li>Кумаринови антикоагуланти</li><li><b>Алкохол </b>(↑ секреция на инсулин)</li><li>Някои антибактериални лекарства (сулфонамиди и хлорамфеникол)</li><li>Някои<b> </b>имидазолови противогъбичкови лекарства.</li></ul><li><strong>Лекарства, които понижават ефекта</strong>:&nbsp;</li><ul><li>Тиазидни диуретици</li><li>Кортикостероиди.</li></ul></ul></ul><h3 style=\"color: rgb(124, 45, 18);\">Меглитиниди</h3><ul><li><strong><font color=\"#b13d16\">Представители</font></strong>: <font color=\"#7e22ce\"><i><strong>Repaglinide</strong> </i></font>и <strong><i><font color=\"#7e22ce\">Nateglinide</font></i></strong>.</li><li><strong><font color=\"#b13d16\">Характеристики</font></strong>:</li><ul><li>По-малка активност от <i style=\"\"><font color=\"#7e22ce\" style=\"\">СУП</font></i>.</li><li><strong>Бързо</strong> и <strong>кратко действие</strong>.</li><li><strong>Нисък риск от хипогликемия</strong>.</li><li>По-малко <strong>наддаване на тегло</strong> в сравнение със<i><font color=\"#7e22ce\"> СУП</font></i>.</li></ul><li><strong><font color=\"#b13d16\">Приложение</font></strong>: Малко преди хранене, понижават <strong>постпрандиалната хипергликемия</strong> при <strong>диабет тип 2</strong>.</li></ul><h3 style=\"color: rgb(124, 45, 18);\">Тиазолидиндиони</h3><ul><li><strong><font color=\"#b13d16\">Представители: </font><i style=\"\"><font color=\"#7e22ce\">Pioglitazone</font></i></strong></li><li><strong><font color=\"#b13d16\">Ефекти</font></strong>:</li><ul><li><strong>Понижава постъпването на глюкоза от черния дроб</strong> в кръвта.</li><li><strong><font color=\"#3b82f6\">Повишава поемането на глюкоза в мускулите</font></strong> чрез повишаване на ефекта на <strong>ендогенния инсулин</strong>.</li><li><strong>Понижава триглицеридите</strong>.</li></ul><li><strong><font color=\"#b13d16\">Механизъм на действие</font></strong>:</li><ul><li>Свързва се с нуклеарен рецептор, наречен пероксизом пролифератор активиран рецептор-γ (<strong><font color=\"#dd0a0a\"><u>PPARγ</u></font></strong>), който е в комплекс с ретиноид X рецептор (RXR).</li><li>Предизвиква свързването на комплекса <strong><p>PPARγ</p>-RXR с ДНК</strong>, улеснявайки транскрипцията на гени, важни за инсулиновото действие (напр. <strong>Glut-4</strong>).</li><li><p style=\"\">PPARγ</p> предизвиква диференциация на адипоцитите, повишава липогенезата и улеснява поемането на мастни киселини и глюкоза.</li></ul><li><strong><font color=\"#b13d16\">Фармакокинетика</font></strong>: Бърза и почти пълна абсорбция, метаболизъм в <strong>черния дроб</strong>.</li><li><strong><font color=\"#b13d16\">Нежелани лекарствени реакции</font></strong>:</li><ul><li><strong>Наддаване на тегло</strong> и <strong>задръжка на течности</strong>: <strong>Противопоказан при Сърдечна Недостатъчност (СН)</strong>.</li><li>Повишен риск от <strong>фрактури</strong> при хронично приложение.</li></ul><li><strong><font color=\"#b13d16\">Клинична употреба</font></strong>: В комбинация с <i><font color=\"#7e22ce\"><strong>metformin</strong> </font></i>или <strong><i><font color=\"#7e22ce\">СУП</font></i></strong>.</li></ul><h3 style=\"color: rgb(124, 45, 18);\">Алфа-глюкозидазни инхибитори</h3><ul><li><strong><font color=\"#b13d16\">Представители: </font><font color=\"#7e22ce\"><i>Acarbose</i></font></strong></li><li><strong><font color=\"#b13d16\">Механизъм на действие</font></strong>: Инхибира алфа-глюкозидазата в червата.</li><li><strong><font color=\"#b13d16\">Ефект</font></strong>: <strong>Забавя абсорбцията на въглехидрати</strong>, понижава <strong>постпрандиалните нива на глюкоза</strong>.</li><li><strong><font color=\"#b13d16\">Нежелани лекарствени реакции</font></strong>: <strong>Метеоризъм</strong>, <strong>диария</strong>, <strong><font color=\"#dd0a0a\">коремна болка</font></strong> и <strong><font color=\"#dd0a0a\">подуване на корема</font></strong>.</li><li><strong><font color=\"#b13d16\">Клинична употреба</font></strong>: <strong>Диабет тип 2</strong>, особено при пациенти със <strong>затлъстяване</strong>.</li></ul><h3 style=\"color: rgb(124, 45, 18);\">Инкретини и техните миметици</h3><ul><li><strong><font color=\"#b13d16\">Фармакокинетика на GLP-1</font></strong>:&nbsp;</li><ul><li>Нативният пептид <strong>не може да се използва терапевтично</strong> поради <strong>бързото му разграждане</strong> от <strong>DPP-4</strong>.&nbsp;</li><li>Разработени са стабилни аналози или производни на GLP-1<p>, които не са обект на ензимно </p><p>разграждане от DPP-4.</p></li></ul><li><strong><font color=\"#b13d16\">Ефекти на GLP-1</font></strong>:</li><ul><li>Стимулира <strong>освобождаването на инсулин</strong>, като ефектът <strong>зависи от глюкозата</strong>:</li><ul><li><p>Освобождаването на инсулин е по-изразено </p><p>при повишени нива на глюкозата и по-слабо </p><p>при нормални нива на глюкозата -&gt; </p><p><b>нисък риск от хипогликемия.</b></p></li></ul><li>Потиска <strong>секрецията на глюкагон</strong>.</li><li><strong>Забавя изпразването на стомаха</strong>.</li><li><strong>Инхибира храненето</strong> (пациентите са по-малко гладни).</li><li>Има <strong>сърдечно-съдови ползи</strong> (кръвно налягане, съдов ендотел, атеросклероза, миокардна исхемия, сърдечна недостатъчност).</li></ul><li><b><font color=\"#7e22ce\">GLP-1 рецепторни агонисти (Аналози/производни на GLP-1)</font><font color=\"#000000\">:</font></b></li><ul><li><strong><i><font color=\"#7e22ce\">Exenatide</font></i></strong>:&nbsp;</li><ul><li>Синтетичен вариант на exendin-4<p>, пептид в слюнката на голям</p><p>отровен гущер, който убива плячката си </p><p>като я прави хипогликемична. </p></li><li>Приложение s.c. 2 пъти дневно или веднъж седмично.</li></ul><li><strong><font color=\"#7e22ce\"><i>Lixisenatide</i></font></strong>:&nbsp;</li><ul><li>Синтетичен аналог на exendin-4.&nbsp;</li><li>Дозиране веднъж дневно, s.c.</li></ul><li><strong><i><font color=\"#7e22ce\">Liraglutide</font></i></strong>:&nbsp;</li><ul><li>Разтворим аналог на GLP-1.&nbsp;</li><li>Дозиране веднъж дневно, s.c.</li></ul><li><strong><i><font color=\"#7e22ce\">Dulaglutide</font></i></strong>:&nbsp;</li><ul><li><p>Състои се от две GLP-1 аналогови молекули, ковалентно</p><p>свързани с Fc фрагмент на човешки IgG4</p></li><li>Дозиране веднъж седмично, s.c.</li></ul><li><strong><font color=\"#b13d16\">Нежелани ефекти</font></strong>:&nbsp;</li><ul><li>Най-често – <strong>гадене</strong>, <strong>повръщане</strong> и <strong>диария</strong>.&nbsp;</li><li><strong>Панкреатит</strong> (рядък, но понякога тежък).</li></ul><li><strong><font color=\"#b13d16\">Клинична употреба</font></strong>:</li><ul><li><strong>Диабет тип 2</strong> в комбинация с перорални лекарства.</li><li>Полза при пациенти с <strong>атеросклеротично сърдечно съдово заболяване</strong> (<strong><i><font color=\"#7e22ce\">liraglutide</font></i>, <i><font color=\"#7e22ce\">dulaglutide</font></i></strong>).</li><li>Одобрени за <strong>отслабване</strong> при пациенти без диабет (<strong><i><font color=\"#7e22ce\">liraglutide</font></i></strong>).</li></ul></ul></ul><h3 style=\"color: rgb(124, 45, 18);\">Инхибитори на дипептидил пептидаза-4 (DPP-4 инхибитори)</h3><ul><li><strong><font color=\"#b13d16\">Представители</font></strong>: <strong><i><font color=\"#7e22ce\">Sitagliptin</font></i></strong>, <strong><i><font color=\"#7e22ce\">Vildagliptin</font></i></strong>, <strong><i><font color=\"#7e22ce\">Linagliptin</font></i></strong>, <strong><i><font color=\"#7e22ce\">Saxagliptin</font></i></strong>.</li><li><strong><font color=\"#b13d16\">Механизъм на действие</font></strong>: <strong>Инхибират DPP-4</strong> и така <strong>повишават ефекта на ендогенните инкретини</strong> (<strong>GLP-1</strong> и <strong>GIP</strong>).</li><li><strong><font color=\"#b13d16\">Характеристики</font></strong>: <strong>Не водят до наддаване на тегло</strong>. Добре се абсорбират <strong>перорално</strong>.</li><li><strong><font color=\"#b13d16\">Клинична употреба</font></strong>: <strong>Диабет тип 2</strong> в добавка към други лекарства.</li></ul><h3 style=\"color: rgb(124, 45, 18);\">Инхибитори на натриево-глюкозен котранспортер 2 (SGLT2i, глюкуретици)</h3><ul><li><strong><font color=\"#b13d16\">Представители</font></strong>: <strong><i><font color=\"#7e22ce\">Dapagliflozin</font></i></strong>, <strong><i><font color=\"#7e22ce\">Empagliflozin</font></i></strong>, <strong><i><font color=\"#7e22ce\">Canagliflozin</font></i></strong>.</li><li><strong><font color=\"#b13d16\">Механизъм на действие</font></strong>:</li><ul><li><strong>Инхибиция на SGLT2 в бъбреците</strong>.</li><li><strong>Понижение на глюкозната реабсорбция</strong>.</li><li><strong>Екскреция на глюкозата в урината</strong>.</li><li><strong>Понижаване на глюкозата в кръвта</strong>.</li><li>Действието им <strong>не зависи от инсулиновата секреция и действие</strong>.</li></ul><li><strong><font color=\"#b13d16\">Клинична употреба</font></strong>:&nbsp;</li><ul><li>При пациенти с <strong>диабет тип 2</strong>.</li><ul><li><p>Допълнителна полза при пациенти със </p><p>сърдечна недостатъчност и хронично </p><p>бъбречно заболяване</p></li></ul><li><p>При лечение на сърдечна недостатъчност, </p><p>независимо от диабетния статус – загубата </p><p>на тегло, по-ниското кръвно налягане и </p><p>диурезата могат да играят роля</p></li></ul><li><span style=\"white-space-collapse: preserve;\"><p><b><font color=\"#c14015\">Нежелани реакции</font></b>:</p></span></li><ul><li><span style=\"white-space-collapse: preserve;\"><p>Генитални инфекции и уроинфекции – 9-</p><p>8% от пациентите.</p></span></li></ul></ul><span style=\"white-space-collapse: preserve;\"><hr><hr><h1 style=\"color: rgb(124, 45, 18);\">Тиреоактивни лекарства</h1><h3 style=\"color: rgb(124, 45, 18);\">Хормони на щитовидната жлеза</h3><ul><li><strong>Тироксин</strong> (<strong>T4</strong>)</li><li><strong>Трийодтиронин</strong> (<strong>T3</strong>)</li><li><strong>Калцитонин</strong></li></ul><h3 style=\"color: rgb(124, 45, 18);\">Синтез на T3 и T4</h3><ul><li>T3 и T4 се синтезират чрез йодиране на тирозиновите остатъци върху тиреоглобулина в лумена на фоликулите на щитовидната жлеза.</li><ul><li>Функционалната единица на щитовидната жлеза е фоликулът, състоящ се от:</li><ul><li>Един слой епителни клетки.</li><li>Кухина, пълна с колоид, съдържащ тиреоглобулин.</li></ul></ul><li>Синтезът и секрецията на хормони се регулира от TSH и се повлиява от плазмената концентрация на йод.</li><li><font color=\"#3a5a40\"><b>Етапи на синтеза</b></font></li><ul><li>Поемане на йодид от плазмата във фоликулните клетки.</li><li>Окисление на йодида (чрез тиреопероксидаза).</li><li>Йодиране на тирозиновите остатъци в молекулата на тиреоглобулина до MIT (монойодтирозин) и DIT (дийодтирозин) в колоида на фоликулите.</li><li>Кондензация на MIT и DIT до Т3 и Т4 и протеолиза.</li><li>Секреция на щитовидни хормони.</li></ul></ul><h3 style=\"color: rgb(124, 45, 18);\">Действия на щитовидните хормони</h3><ol><li><strong>Повлияване на метаболизма</strong>:</li><ul><li><strong>Общо повишаване на метаболизма</strong> на <strong>въглехидрати</strong>, <strong>мазнини</strong> и <strong>белтъци</strong>.</li><li><strong>Т3</strong> е почти <strong>5 пъти по-активен от Т4</strong>.</li></ul><li><strong>Повлияване на растежа и развитието - критичен ефект върху растежа</strong>:</li><ul><li>Частично чрез <strong>директно действие</strong> върху клетките.</li><li>Индиректно чрез повлияване на продукцията на <strong>растежен хормон</strong> и <strong>потенциране</strong> на неговите ефекти върху тъканите.</li><li><p>↑ метаболизма на остеобластите и остеокластите.</p></li></ul></ol><h4 style=\"color: rgb(124, 45, 18);\">Механизъм на действие</h4><ul><li>Геномни действия – специфичен нуклеарен рецептор, <b>TR</b> (Thyroid hormone Receptor).</li><li><b>T4</b> е <b>преобладаващият </b>хормон в циркулацията.</li><li><b>T4</b> може да се разглежда като <b>прохормон</b>, тъй като при влизане в клетката се превръща в <b>T3</b>.</li><li>T3 се свързва с висок афинитет към TR.</li><li>Настъпва активиране на транскрипцията, което има за резултат генериране на mRNA и синтез на протеини.</li></ul><h3 style=\"color: rgb(124, 45, 18);\">Абнормости в тироидната функция</h3><ul><li><strong>Хипертиреоидизъм</strong> (<strong><font color=\"#dd0a0a\">Базедова болест</font></strong>, <strong><font color=\"#dd0a0a\">тиреотоксикоза</font></strong>):</li><ul><li>Дифузна токсична гуша.</li><li>Токсична нодозна гуша.</li></ul><li><strong>Хипотиреоидизъм</strong>:</li><ul><li><font color=\"#dd0a0a\"><strong>Микседем</strong> </font>(при възрастни).</li><li><font color=\"#dd0a0a\"><strong>Кретенизъм</strong> </font>(при деца).</li></ul><li><strong>Проста нетоксична гуша</strong>:</li><ul><li>Причинена от <strong>хранителен недостиг на йод</strong>, обикновено с <strong>нормална функция</strong> на щитовидната жлеза.</li></ul></ul><h3 style=\"color: rgb(124, 45, 18);\">Лекарства с тиреотропна активност</h3><ol><li><strong>Лекарства с активност на щитовидни хормони</strong>:</li><ul><li><strong><i><font color=\"#7e22ce\">Levothyroxine</font></i></strong></li></ul><li><strong>Лекарства с тиреостатична активност</strong>:</li><ul><li><strong><i><font color=\"#7e22ce\">Thiamazole</font></i></strong></li><li><strong><i><font color=\"#7e22ce\">Propylthiouracil</font></i></strong></li></ul><li><strong>Йодни препарати</strong>:</li><ul><li><strong><i><font color=\"#7e22ce\">Potassium iodide</font></i></strong></li></ul></ol><hr><h3 style=\"color: rgb(124, 45, 18);\">Лекарства с активност на щитовидни хормони</h3><h4 style=\"color: rgb(124, 45, 18);\"><i><font color=\"#7e22ce\">Levothyroxine</font></i></h4><ul><li><strong><font color=\"#c54216\">Приложение</font></strong>: перорално.</li><li><strong><font color=\"#c54216\">Клинична употреба</font></strong>: <strong>Стандартна заместителна терапия</strong> при <strong>хипотиреоидизъм</strong>.</li><li><strong><font color=\"#c54216\">Нежелани лекарствени реакции</font></strong>:</li><ul><li>При <strong>предозиране</strong> (<strong>симптоми на хипертиреоидизъм</strong>):</li><ul><li><strong>Сърдечна исхемия</strong>, <strong>аритмии</strong>, <strong>сърдечна недостатъчност</strong>. \r\n(<font color=\"#65a30d\">поради тахикардия, </font><p><font color=\"#65a30d\">↑ сила на съкращение → ↑ </font></p><p><font color=\"#65a30d\">O<sub>2</sub> потребности</font>)</p></li></ul><li>При <strong>по-леко предозиране</strong>:</li><ul><li><strong>Увеличена костна резорбция</strong>, водеща до <strong>остеопороза</strong>.</li></ul></ul></ul><hr><h3 style=\"color: rgb(124, 45, 18);\">Тиреостатици</h3><h4 style=\"color: rgb(124, 45, 18);\"><i><font color=\"#7e22ce\">Thiamazole, Propylthiouracil</font></i></h4><ul><li><strong><font color=\"#c54216\">Механизъм на действие</font></strong>:</li><ul><li><strong>Потискат йодирането</strong> на тирозиновите остатъци в молекулата на тиреоглобулина.</li><li><strong>Инхибират окислението на йодида</strong> от <strong>тиреопероксидазата</strong>.</li><li><strong><i><font color=\"#7e22ce\">Propylthiouracil</font></i></strong> допълнително <strong>понижава превръщането на T4 до T3</strong> в периферните тъкани.</li></ul><li><strong><font color=\"#c54216\"><p><strong>Клиничен отговор</strong>: </p></font></strong></li><ul><li>След няколко седмици (щитовидната жлеза може да има големи депа на хормони)</li><li><i><font color=\"#7e22ce\">Propylthiouracil </font></i>се счита, че действа малко по-бързо поради намаляването на дейодирането на T<sub>4</sub> до T<sub>3</sub></li></ul><li><strong><font color=\"#c54216\">Нежелани лекарствени реакции</font></strong>:</li><ul><li><strong>Гадене</strong>.</li><li><strong>Обриви</strong> (чести – до 25%).</li><li><strong>Сериозни хематологични</strong> (около 1%): <strong>гранулоцитопения</strong> и <strong>агранулоцитоза</strong>.</li></ul><li><strong><font color=\"#c54216\">Индикации</font></strong>:</li><ul><li><strong>Базедова болест</strong> (дифузна токсична гуша) – дълго лечение (най-малко 1 година).</li><li><b>Тиреотоксикоза </b>(щитовидна буря) – <i><font color=\"#7e22ce\"><strong>propylthiouracil</strong> </font></i>се предпочита. Използват се също бета блокери (напр. <i><font color=\"#7e22ce\">propranolol</font></i>).</li></ul></ul><hr><h3 style=\"color: rgb(124, 45, 18);\">Йодиди</h3><h4 style=\"color: rgb(124, 45, 18);\"><i><font color=\"#7e22ce\">Potassium iodide</font></i></h4><ul><li><strong><font color=\"#c54216\">Механизъм на действие</font></strong> – не е напълно ясен:</li><ul><li>Може да инхибира йодирането на тиреоглобулин, вероятно чрез намаляване на образуването на H<sub>2</sub><span style=\"font-size: 16px;\">O</span><sub>2</sub>, който е необходим за този процес.</li></ul><li><strong><font color=\"#c54216\">Ефекти</font></strong>:</li><ul><li><strong>Временно инхибиране на освобождаването на хормони</strong> на щитовидната жлеза (<strong>10-14 дни</strong>).</li><li><strong>Намаляване на кръвоснабдяването</strong> на жлезата.</li></ul><li><strong><font color=\"#c54216\">Клинична употреба</font></strong>:</li><ul><li><strong>Предоперативно</strong> – преди хирургическа резекция на жлезата.</li><li>Като част от лечението на <strong>тиреотоксикоза</strong>.</li></ul><li><strong><font color=\"#c54216\">Нежелани лекарствени реакции</font></strong> (йодид в сълзите и слюнката):</li><ul><li>Сълзотечение, конюнктивит.</li><li>Болка в слюнчените жлези.</li></ul></ul><br></span><br>\r\n<script src=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/katex.min.js\"></script>\r\n<script src=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/contrib/auto-render.min.js\"></script>\r\n<script>\r\nrenderMathInElement(document.body, {\r\n  delimiters: [\r\n    {left: '$$', right: '$$', display: true},\r\n    {left: '$', right: '$', display: false}\r\n  ]\r\n});\r\n</script>\r\n<script src=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/katex.min.js\"></script>\r\n<script src=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/contrib/auto-render.min.js\"></script>\r\n<script>\r\nrenderMathInElement(document.body, {\r\n  delimiters: [\r\n    {left: '$$', right: '$$', display: true},\r\n    {left: '$', right: '$', display: false}\r\n  ]\r\n});\r\n</script>\r\n<script src=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/katex.min.js\"></script>\r\n<script src=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/contrib/auto-render.min.js\"></script>\r\n<script>\r\nrenderMathInElement(document.body, {\r\n  delimiters: [\r\n    {left: '$$', right: '$$', display: true},\r\n    {left: '$', right: '$', display: false}\r\n  ]\r\n});\r\n</script>\r\n</body>\r\n</html>";
